const book: BibleBook = {
  id: '2samuel',
  name: '2 Samuel',
  englishName: '2 Samuel',
  testament: 'old',
  chapters: {
    1: [
      { v: 1, en: 'After the death of Saul, when David had returned from the slaughter of the Amalekites, and David had stayed two days in Ziklag;', pt: 'Depois da morte de Saul, tendo Davi voltado da derrota dos amalequitas e estando há dois dias em Ziclague,' },
      { v: 2, en: 'on the third day, behold, a man came out of the camp from Saul, with his clothes torn, and earth on his head. When he came to David, he fell to the earth, and showed respect.', pt: 'ao terceiro dia veio um homem do arraial de Saul, com as vestes rasgadas e a cabeça coberta de terra; e, chegando ele a Davi, prostrou-se em terra e lhe fez reverência.' },
      { v: 3, en: 'David said to him, “Where do you come from?” He said to him, “I have escaped out of the camp of Israel.”', pt: 'Perguntou-lhe Davi: Donde vens? Ele lhe respondeu: Escapei do arraial de Israel.' },
      { v: 4, en: 'David said to him, “How did it go? Please tell me.” He answered, “The people have fled from the battle, and many of the people also have fallen and are dead. Saul and Jonathan his son are dead also.”', pt: 'Davi ainda lhe indagou: Como foi lá isso? Dize-mo. Ao que ele lhe respondeu: O povo fugiu da batalha, e muitos do povo caíram, e morreram; também Saul e Jônatas, seu filho, foram mortos.' },
      { v: 5, en: 'David said to the young man who told him, “How do you know that Saul and Jonathan his son are dead?”', pt: 'Perguntou Davi ao mancebo que lhe trazia as novas: Como sabes que Saul e Jônatas, seu filho, são mortos?' },
      { v: 6, en: 'The young man who told him said, “As I happened by chance on Mount Gilboa, behold, Saul was leaning on his spear; and behold, the chariots and the horsemen followed close behind him.', pt: 'Então disse o mancebo que lhe dava a notícia: Achava-me por acaso no monte Gilbea, e eis que Saul se encostava sobre a sua lança; os carros e os cavaleiros apertavam com ele.' },
      { v: 7, en: 'When he looked behind him, he saw me, and called to me. I answered, ‘Here I am.’', pt: 'Nisso, olhando ele para trás, viu-me e me chamou; e eu disse: Eis-me aqui.' },
      { v: 8, en: 'He said to me, ‘Who are you?’ I answered him, ‘I am an Amalekite.’', pt: 'Ao que ele me perguntou: Quem és tu? E eu lhe respondi: Sou amalequita.' },
      { v: 9, en: 'He said to me, ‘Please stand beside me, and kill me; for anguish has taken hold of me, because my life lingers in me.’', pt: 'Então ele me disse: Chega-te a mim, e mata-me, porque uma vertigem se apoderou de mim, e toda a minha vida está ainda em mim.' },
      { v: 10, en: 'So I stood beside him and killed him, because I was sure that he could not live after that he had fallen. I took the crown that was on his head and the bracelet that was on his arm, and have brought them here to my lord.”', pt: 'Cheguei-me, pois, a ele, e o matei, porque bem sabia eu que ele não viveria depois de ter caído; e tomei a coroa que ele tinha na cabeça, e o bracelete que trazia no braço, e os trouxe aqui a meu senhor.' },
      { v: 11, en: 'Then David took hold on his clothes, and tore them; and all the men who were with him did likewise.', pt: 'Então pegou Davi nas suas vestes e as rasgou; e assim fizeram também todos os homens que estavam com ele;' },
      { v: 12, en: 'They mourned, wept, and fasted until evening, for Saul, and for Jonathan his son, and for the people of Yahweh, and for the house of Israel; because they had fallen by the sword.', pt: 'e prantearam, e choraram, e jejuaram até a tarde por Saul, e por Jônatas, seu filho, e pelo povo do Senhor, e pela casa de Israel, porque tinham caída à espada.' },
      { v: 13, en: 'David said to the young man who told him, “Where are you from?” He answered, “I am the son of a foreigner, an Amalekite.”', pt: 'Perguntou então Davi ao mancebo que lhe trouxera a nova: Donde és tu? Respondeu ele: Sou filho de um peregrino amalequita.' },
      { v: 14, en: 'David said to him, “Why were you not afraid to stretch out your hand to destroy Yahweh’s anointed?”', pt: 'Davi ainda lhe perguntou: Como não temeste estender a mão para matares o ungido do Senhor?' },
      { v: 15, en: 'David called one of the young men, and said, “Go near, and cut him down!” He struck him so that he died.', pt: 'Então Davi, chamando um dos mancebos, disse-lhe: chega-te, e lança-te sobre ele. E o mancebo o feriu, de sorte que morreu.' },
      { v: 16, en: 'David said to him, “Your blood be on your head; for your mouth has testified against you, saying, ‘I have slain Yahweh’s anointed.’”', pt: 'Pois Davi lhe dissera: O teu sangue seja sobre a tua cabeça, porque a tua própria boca testificou contra ti, dizendo: Eu matei o ungido do Senhor.' },
      { v: 17, en: 'David lamented with this lamentation over Saul and over Jonathan his son', pt: 'Lamentou Davi a Saul e a Jônatas, seu filho, com esta lamentação,' },
      { v: 18, en: '(and he commanded them to teach the children of Judah the song of the bow; behold, it is written in the book of Jashar):', pt: 'mandando que fosse ensinada aos filhos de Judá; eis que está escrita no livro de Jasar:' },
      { v: 19, en: '“Your glory, Israel, was slain on your high places! How the mighty have fallen!', pt: 'Tua glória, ó Israel, foi morta sobre os teus altos! Como caíram os valorosos!' },
      { v: 20, en: 'Don’t tell it in Gath. Don’t publish it in the streets of Ashkelon, lest the daughters of the Philistines rejoice, lest the daughters of the uncircumcised triumph.', pt: 'Não o noticieis em Gate, nem o publiqueis nas ruas de Asquelom; para que não se alegrem as filhas dos filisteus, para que não exultem as filhas dos incircuncisos.' },
      { v: 21, en: 'You mountains of Gilboa, let there be no dew or rain on you, and no fields of offerings; For there the shield of the mighty was defiled and cast away, The shield of Saul was not anointed with oil.', pt: 'Vós, montes de Gilboa, nem orvalho, nem chuva caia sobre, vós, ó campos de morte; pois ali desprezivelmente foi arrojado o escudo dos valorosos, o escudo de Saul, ungido com óleo.' },
      { v: 22, en: 'From the blood of the slain, from the fat of the mighty, Jonathan’s bow didn’t turn back. Saul’s sword didn’t return empty.', pt: 'Do sangue dos feridos, da gordura dos valorosos, nunca recuou o arco de Jônatas, nem voltou vazia a espada de Saul.' },
      { v: 23, en: 'Saul and Jonathan were lovely and pleasant in their lives. In their death, they were not divided. They were swifter than eagles. They were stronger than lions.', pt: 'Saul e Jônatas, tão queridos e amáveis na sua vida, também na sua morte não se separaram; eram mais ligeiros do que as águias, mais fortes do que os leões.' },
      { v: 24, en: 'You daughters of Israel, weep over Saul, who clothed you delicately in scarlet, who put ornaments of gold on your clothing.', pt: 'Vós, filhas de Israel, chorai por Saul, que vos vestia deliciosamente de escarlata, que vos punha sobre os vestidos adornos de ouro.' },
      { v: 25, en: 'How the mighty have fallen in the middle of the battle! Jonathan was slain on your high places.', pt: 'Como caíram os valorosos no meio da peleja!' },
      { v: 26, en: 'I am distressed for you, my brother Jonathan. You have been very pleasant to me. Your love to me was wonderful, passing the love of women.', pt: 'Angustiado estou por ti, meu irmão Jônatas; muito querido me eras! Maravilhoso me era o teu amor, ultrapassando o amor de mulheres.' },
      { v: 27, en: 'How the mighty have fallen, and the weapons of war have perished!”', pt: 'Como caíram os valorosos, e pereceram as armas de guerra!' },
    ],
    2: [
      { v: 1, en: 'After this, David inquired of Yahweh, saying, “Shall I go up into any of the cities of Judah?” Yahweh said to him, “Go up.” David said, “Where shall I go up?” He said, “To Hebron.”', pt: 'Sucedeu depois disto que Davi consultou ao Senhor, dizendo: Subirei a alguma das cidades de Judá? Respondeu-lhe o Senhor: Sobe. Ainda perguntou Davi: Para onde subirei? Respondeu o Senhor: Para Hebrom.' },
      { v: 2, en: 'So David went up there with his two wives, Ahinoam the Jezreelitess, and Abigail the wife of Nabal the Carmelite.', pt: 'Subiu, pois, Davi para lá, e também as suas duas mulheres, Ainoã, a jizreelita, e Abigail, que fora mulher de Nabal, e carmelita.' },
      { v: 3, en: 'David brought up his men who were with him, every man with his household. They lived in the cities of Hebron.', pt: 'Davi fez subir também os homens que estavam com ele, cada um com sua família; e habitaram nas cidades de Hebrom.' },
      { v: 4, en: 'The men of Judah came, and there they anointed David king over the house of Judah. They told David, “The men of Jabesh Gilead were those who buried Saul.”', pt: 'Então vieram os homens de Judá, e ali ungiram Davi rei sobre a casa de Judá. Depois informaram a Davi, dizendo: Foram os homens de Jabes-Gileade que sepultaram a Saul.' },
      { v: 5, en: 'David sent messengers to the men of Jabesh Gilead, and said to them, “Blessed are you by Yahweh, that you have shown this kindness to your lord, even to Saul, and have buried him.', pt: 'Pelo que Davi enviou mensageiros aos homens de Jabes-Gileade, a dizer-lhes: Benditos do Senhor sejais vós, que fizestes tal benevolência, sepultando a Saul, vosso senhor!' },
      { v: 6, en: 'Now may Yahweh show loving kindness and truth to you. I also will reward you for this kindness, because you have done this thing.', pt: 'Agora, pois, o Senhor use convosco de benevolência e fidelidade; e eu também vos retribuirei esse bem que fizestes.' },
      { v: 7, en: 'Now therefore let your hands be strong, and be valiant; for Saul your lord is dead, and also the house of Judah have anointed me king over them.”', pt: 'Esforcem-se, pois, agora as vossas mãos, e sede homens valorosos; porque Saul, vosso senhor, é morto, e a casa de Judá me ungiu por seu rei.' },
      { v: 8, en: 'Now Abner the son of Ner, captain of Saul’s army, had taken Ishbosheth the son of Saul, and brought him over to Mahanaim;', pt: 'Ora, Abner, filho de Ner, chefe do exército de Saul, tomou a Isbosete, filho de Saul, e o fez passar a Maanaim,' },
      { v: 9, en: 'and he made him king over Gilead, and over the Ashurites, and over Jezreel, and over Ephraim, and over Benjamin, and over all Israel.', pt: 'e o constituiu rei sobre Gileade, sobre os asuritas, sobre Jizreel, sobre Efraim, sobre Benjamim e sobre todo o Israel.' },
      { v: 10, en: 'Ishbosheth, Saul’s son, was forty years old when he began to reign over Israel, and he reigned two years. But the house of Judah followed David.', pt: 'Quarenta anos tinha Isbosete, filho de Saul, quando começou a reinar sobre Israel, e reinou dois anos, A casa de Judá, porém, seguia a Davi.' },
      { v: 11, en: 'The time that David was king in Hebron over the house of Judah was seven years and six months.', pt: 'E foi o tempo que Davi reinou em Hebrom, sobre a casa de Judá, sete anos e seis meses.' },
      { v: 12, en: 'Abner the son of Ner, and the servants of Ishbosheth the son of Saul, went out from Mahanaim to Gibeon.', pt: 'Depois Abner, filho de Ner, com os servos de Isbosete, filho de Saul, saiu de Maanaim para Gibeão.' },
      { v: 13, en: 'Joab the son of Zeruiah and David’s servants went out, and met them by the pool of Gibeon; and they sat down, the one on the one side of the pool, and the other on the other side of the pool.', pt: 'Saíram também Joabe, filho de Zeruia, e os servos de Davi, e se encontraram com eles perto do tanque de Gibeão; e pararam uns de um lado do tanque, e os outros do outro lado.' },
      { v: 14, en: 'Abner said to Joab, “Please let the young men arise and play before us!” Joab said, “Let them arise!”', pt: 'Então disse Abner a Joabe: Levantem-se os mancebos, e se batam diante de nós. Respondeu Joabe: Levantem-se.' },
      { v: 15, en: 'Then they arose and went over by number: twelve for Benjamin and for Ishbosheth the son of Saul, and twelve of David’s servants.', pt: 'Levantaram-se, pois, e passaram, em número de doze por Benjamim e por Isbosete, filho de Saul, e doze dos servos de Davi.' },
      { v: 16, en: 'They each caught his opponent by the head, and thrust his sword in his fellow’s side; so they fell down together: therefore that place in Gibeon was called Helkath Hazzurim.', pt: 'E cada um lançou mão da cabeça de seu contendor, e meteu-lhe a espada pela ilharga; assim caíram juntos; pelo que se chamou àquele lugar, que está junto a Gibeão, Helcate-Hazurim.' },
      { v: 17, en: 'The battle was very severe that day; and Abner was beaten, and the men of Israel, before David’s servants.', pt: 'Seguiu-se naquele dia uma crua peleja; e Abner e os homens de Israel foram derrotados diante dos servos de Davi.' },
      { v: 18, en: 'The three sons of Zeruiah were there, Joab, and Abishai, and Asahel: and Asahel was as light of foot as a wild gazelle.', pt: 'Ora, estavam ali os três filhos de Zeruia: Joabe, Abisai, e Asael; e Asael era ligeiro de pés, como as gazelas do campo.' },
      { v: 19, en: 'Asahel pursued Abner; and in going he didn’t turn to the right hand or to the left from following Abner.', pt: 'Perseguiu, pois, Asael a Abner, seguindo-o sem se desviar nem para a direita nem para a esquerda.' },
      { v: 20, en: 'Then Abner looked behind him, and said, “Is that you, Asahel?” He answered, “It is.”', pt: 'Nisso Abner, olhando para trás, perguntou: És tu Asael? Respondeu ele: Sou eu.' },
      { v: 21, en: 'Abner said to him, “Turn away to your right hand or to your left, and grab one of the young men, and take his armor.” But Asahel would not turn away from following him.', pt: 'Ao que lhe disse Abner: Desvia-te para a direita, ou para a esquerda, e lança mão de um dos mancebos, e toma os seus despojos. Asael, porém , não quis desviar-se de seguí-lo.' },
      { v: 22, en: 'Abner said again to Asahel, “Turn away from following me. Why should I strike you to the ground? How then could I look Joab your brother in the face?”', pt: 'Então Abner tornou a dizer a Asael: Desvia-te de detráz de mim; porque hei de ferir-te e dar contigo em terra? e como levantaria eu o meu rosto diante de Joabe, teu irmão?' },
      { v: 23, en: 'However he refused to turn away. Therefore Abner with the back end of the spear struck him in the body, so that the spear came out behind him; and he fell down there, and died in the same place. As many as came to the place where Asahel fell down and died stood still.', pt: 'Todavia ele recusou desviar-se; pelo que Abner o feriu com o conto da lança pelo ventre, de modo que a lança lhe saiu por detrás; e ele caiu ali, e morreu naquele mesmo lugar. E sucedeu que, todos os que chegavam ao lugar onde Asael caíra morto, paravam.' },
      { v: 24, en: 'But Joab and Abishai pursued Abner. The sun went down when they had come to the hill of Ammah, that lies before Giah by the way of the wilderness of Gibeon.', pt: 'Mas Joabe e Abisai perseguiram a Abner; e pôs-se o sol ao chegarem eles ao outeiro de Amá, que está diante de Giá, junto ao caminho do deserto de Gibeão.' },
      { v: 25, en: 'The children of Benjamin gathered themselves together after Abner, and became one band, and stood on the top of a hill.', pt: 'E os filhos de Benjamim se ajuntaram atrás de Abner e, formando-se num batalhão, puseram-se no cume dum outeiro.' },
      { v: 26, en: 'Then Abner called to Joab, and said, “Shall the sword devour forever? Don’t you know that it will be bitterness in the latter end? How long will it be then, before you ask the people to return from following their brothers?”', pt: 'Então Abner gritou a Joabe, e disse: Devorará a espada para sempre? não sabes que por fim haverá amargura? até quando te demorarás em ordenar ao povo que deixe de perseguir a seus irmãos?' },
      { v: 27, en: 'Joab said, “As God lives, if you had not spoken, surely then in the morning the people would have gone away, and not each followed his brother.”', pt: 'Respondeu Joabe: Vive Deus, que, se não tivesses falado, só amanhã cedo teria o povo cessado, cada um, de perseguir a seu irmao.' },
      { v: 28, en: 'So Joab blew the trumpet; and all the people stood still, and pursued Israel no more, and they fought no more.', pt: 'Então Joabe tocou a buzina, e todo o povo parou; e não perseguiram mais a Israel, e tampouco pelejaram mais.' },
      { v: 29, en: 'Abner and his men went all that night through the Arabah; and they passed over the Jordan, and went through all Bithron, and came to Mahanaim.', pt: 'E caminharam Abner e os seus homens toda aquela noite pela Arabá; e, passando o Jordão, caminharam por todo o Bitrom, e vieram a Maanaim.' },
      { v: 30, en: 'Joab returned from following Abner; and when he had gathered all the people together, nineteen men of David’s and Asahel were missing.', pt: 'Voltou, pois, Joabe de seguir a Abner; e quando ajuntou todo o povo, faltavam dos servos de Davi dezenove homens, e Asael.' },
      { v: 31, en: 'But David’s servants had struck Benjamin and of Abner’s men so that three hundred sixty men died.', pt: 'Mas os servos de Davi tinham ferido dentre os de Benjamim, e dentre os homens de Abner, a trezentos e sessenta homens, de tal maneira que morreram.' },
      { v: 32, en: 'They took up Asahel, and buried him in the tomb of his father, which was in Bethlehem. Joab and his men went all night, and the day broke on them at Hebron.', pt: 'E levantaram a Asael, e o sepultaram no sepulcro de seu pai, que estava em Belém. E Joabe e seus homens caminharam toda aquela noite, e amanheceu-lhes o dia em Hebrom.' },
    ],
    3: [
      { v: 1, en: 'Now there was long war between Saul’s house and David’s house. David grew stronger and stronger, but Saul’s house grew weaker and weaker.', pt: 'Ora, houve uma longa guerra entre a casa de Saul e a casa de Davi; porém Davi se fortalecia cada vez mais, enquanto a casa de Saul cada vez mais se enfraquecia.' },
      { v: 2, en: 'Sons were born to David in Hebron. His firstborn was Amnon, of Ahinoam the Jezreelitess;', pt: 'Nasceram filhos a Davi em Hebrom. Seu primogênito foi Amnom, de Ainoã, a jizreelita;' },
      { v: 3, en: 'and his second, Chileab, of Abigail the wife of Nabal the Carmelite; and the third, Absalom the son of Maacah the daughter of Talmai king of Geshur;', pt: 'o segundo Quileabe, de Abigail, que fôra mulher de Nabal, o carmelita; o terceiro Absalão, filho de Maacá, filha de Talmai, rei de Gesur;' },
      { v: 4, en: 'and the fourth, Adonijah the son of Haggith; and the fifth, Shephatiah the son of Abital;', pt: 'o quarto Adonias, filho de Hagite, o quinto Sefatias, filho de Abital;' },
      { v: 5, en: 'and the sixth, Ithream, of Eglah, David’s wife. These were born to David in Hebron.', pt: 'e o sexto Itreão, de Eglá, também mulher de Davi; estes nasceram a Davi em Hebrom.' },
      { v: 6, en: 'While there was war between Saul’s house and David’s house, Abner made himself strong in Saul’s house.', pt: 'Enquanto havia guerra entre a casa de Saul e a casa de Davi, Abner ia se tornando poderoso na casa de Saul:' },
      { v: 7, en: 'Now Saul had a concubine, whose name was Rizpah, the daughter of Aiah; and Ishbosheth said to Abner, “Why have you gone in to my father’s concubine?”', pt: 'Ora, Saul tivera uma concubina, cujo nome era Rizpa, filha de Aías. Perguntou, pois, Isbosete a Abner: Por que entraste à concubina de meu pai?' },
      { v: 8, en: 'Then Abner was very angry about Ishbosheth’s words, and said, “Am I a dog’s head that belongs to Judah? Today I show kindness to Saul’s house your father, to his brothers, and to his friends, and have not delivered you into the hand of David; and yet you charge me today with a fault concerning this woman!', pt: 'Então Abner, irando-se muito pelas palavras de Isbosete, disse: Sou eu cabeça de cão, que pertença a Judá? Ainda hoje uso de benevolência para com a casa de Saul, teu pai, e para com seus irmãos e seus amigos, e não te entreguei nas mãos de Davi; contudo tu hoje queres culpar-me no tocante a essa mulher.' },
      { v: 9, en: 'God do so to Abner, and more also, if, as Yahweh has sworn to David, I don’t do even so to him;', pt: 'Assim faça Deus a Abner, e outro tanto, se, como o Senhor jurou a Davi, assim eu não lhe fizer,' },
      { v: 10, en: 'to transfer the kingdom from Saul’s house, and to set up David’s throne over Israel and over Judah, from Dan even to Beersheba.”', pt: 'transferindo o reino da casa de Saul, e estabelecendo o trono de Davi sobre Israel, e sobre Judá, desde Dã até Berseba.' },
      { v: 11, en: 'He could not answer Abner another word, because he was afraid of him.', pt: 'E Isbosete não pôde responder a Abner mais uma palavra, porque o temia.' },
      { v: 12, en: 'Abner sent messengers to David on his behalf, saying, “Whose is the land?” and saying, “Make your alliance with me, and behold, my hand will be with you, to bring all Israel around to you.”', pt: 'Então enviou Abner da sua parte mensageiros a Davi, dizendo: De quem é a terra? Comigo faze a tua aliança, e eis que a minha mão será contigo, para fazer tornar a ti todo o Israel.' },
      { v: 13, en: 'He said, “Good. I will make a treaty with you, but one thing I require of you. That is, you will not see my face unless you first bring Michal, Saul’s daughter, when you come to see my face.”', pt: 'Respondeu Davi: Está bem; farei aliança contigo; mas uma coisa te exijo; não verás a minha face, se primeiro não me trouxeres Mical, filha de Saul, quando vieres ver a minha face.' },
      { v: 14, en: 'David sent messengers to Ishbosheth, Saul’s son, saying, “Deliver me my wife Michal, whom I was given to marry for one hundred foreskins of the Philistines.”', pt: 'Também enviou Davi mensageiros a Isbosete, filho de Saul, dizendo: Entrega-me minha mulher Mical, que eu desposei por cem prepúcios de filisteus.' },
      { v: 15, en: 'Ishbosheth sent and took her from her husband, even from Paltiel the son of Laish.', pt: 'Enviou, pois, Isbosete, e a tirou a seu marido, a Paltiel, filho de Laís,' },
      { v: 16, en: 'Her husband went with her, weeping as he went, and followed her to Bahurim. Then Abner said to him, “Go! Return!” and he returned.', pt: 'que a seguia, chorando atrás dela até Baurim. Então lhe disse Abner: Vai-te; volta! E ele voltou.' },
      { v: 17, en: 'Abner had communication with the elders of Israel, saying, “In times past, you sought for David to be king over you.', pt: 'Falou Abner com os anciãos de Israel, dizendo: De há muito procurais fazer com que Davi reine sobre vós;' },
      { v: 18, en: 'Now then do it; for Yahweh has spoken of David, saying, ‘By the hand of my servant David, I will save my people Israel out of the hand of the Philistines, and out of the hand of all their enemies.’”', pt: 'fazei-o, pois, agora, porque o Senhor falou de Davi, dizendo: Pela mão do meu servo Davi livrarei o meu povo da mão dos filisteus e da mão de todos os seus inimigos.' },
      { v: 19, en: 'Abner also spoke in the ears of Benjamin: and Abner went also to speak in the ears of David in Hebron all that seemed good to Israel, and to the whole house of Benjamin.', pt: 'Do mesmo modo falou Abner a Benjamim, e foi também dizer a Davi, em Hebrom, tudo o que Israel e toda a casa de Benjamim tinham resolvido.' },
      { v: 20, en: 'So Abner came to David to Hebron, and twenty men with him. David made Abner and the men who were with him a feast.', pt: 'Abner foi ter com Davi, em Hebrom, com vinte homens; e Davi fez um banquete a Abner e aos homens que com ele estavam.' },
      { v: 21, en: 'Abner said to David, “I will arise and go, and will gather all Israel to my lord the king, that they may make a covenant with you, and that you may reign over all that your soul desires.” David sent Abner away; and he went in peace.', pt: 'Então disse Abner a Davi: Eu me levantarei, e irei ajuntar ao rei meu senhor todo o Israel, para que faça aliança contigo; e tu reinarás sobre tudo o que desejar a sua alma: Assim despediu Davi a Abner, e ele se foi em paz.' },
      { v: 22, en: 'Behold, David’s servants and Joab came from a raid, and brought in a great plunder with them; but Abner was not with David in Hebron; for he had sent him away, and he had gone in peace.', pt: 'Eis que os servos de Davi e Joabe voltaram de uma sortida, e traziam consigo grande despojo; mas Abner já não estava com Davi em Hebrom, porque este o tinha despedido, e ele se fora em paz.' },
      { v: 23, en: 'When Joab and all the army who was with him had come, they told Joab, “Abner the son of Ner came to the king, and he has sent him away, and he has gone in peace.”', pt: 'Quando, pois, chegaram Joabe e todo o exército que vinha com ele, disseram-lhe: Abner, filho de Ner, veio ter com o rei; e o rei o despediu, e ele se foi em paz.' },
      { v: 24, en: 'Then Joab came to the king, and said, “What have you done? Behold, Abner came to you. Why is it that you have sent him away, and he is already gone?', pt: 'Então Joabe foi ao rei, e disse: Que fizeste? Eis que Abner veio ter contigo; por que, pois, o despediste, de maneira que se fosse assim livremente?' },
      { v: 25, en: 'You know Abner the son of Ner. He came to deceive you, and to know your going out and your coming in, and to know all that you do.”', pt: 'Bem conheces a Abner, filho de Ner; ele te veio enganar, e saber a tua saída e a tua entrada, e conhecer tudo quanto fazes.' },
      { v: 26, en: 'When Joab had come out from David, he sent messengers after Abner, and they brought him back from the well of Sirah; but David didn’t know it.', pt: 'E Joabe, retirando-se de Davi, enviou mensageiros atrás de Abner, que o fizeram voltar do poço de Sira, sem que Davi o soubesse.' },
      { v: 27, en: 'When Abner was returned to Hebron, Joab took him aside into the middle of the gate to speak with him quietly, and struck him there in the body, so that he died, for the blood of Asahel his brother.', pt: 'Quando Abner voltou a Hebrom, Joabe o tomou à parte, à entrada da porta, para lhe falar em segredo; e ali, por causa do sangue de Asael, seu irmão, o feriu no ventre, de modo que ele morreu.' },
      { v: 28, en: 'Afterward, when David heard it, he said, “I and my kingdom are guiltless before Yahweh forever of the blood of Abner the son of Ner.', pt: 'Depois Davi, quando o soube, disse: Inocente para sempre sou eu, e o meu reino, para com o Senhor, no tocante ao sangue de Abner, filho de Ner.' },
      { v: 29, en: 'Let it fall on the head of Joab, and on all his father’s house. Let there not fail from the house of Joab one who has an issue, or who is a leper, or who leans on a staff, or who falls by the sword, or who lacks bread.”', pt: 'Caia ele sobre a cabeça de Joabe e sobre toda a casa de seu pai, e nunca falte na casa de Joabe quem tenha fluxo, ou quem seja leproso, ou quem se atenha a bordão, ou quem caia à espada, ou quem necessite de pão.' },
      { v: 30, en: 'So Joab and Abishai his brother killed Abner, because he had killed their brother Asahel at Gibeon in the battle.', pt: 'Joabe, pois, e Abisai, seu irmão, mataram Abner, por ter ele morto a Asael, irmão deles, na peleja em Gibeão.' },
      { v: 31, en: 'David said to Joab, and to all the people who were with him, “Tear your clothes, and clothe yourselves with sackcloth, and mourn in front of Abner.” King David followed the bier.', pt: 'Disse Davi a Joabe e a todo o povo que com ele estava: Rasgai as vossas vestes, cingi-vos de sacos e ide pranteando diante de Abner. E o rei Davi ia seguindo o féretro.' },
      { v: 32, en: 'They buried Abner in Hebron; and the king lifted up his voice, and wept at Abner’s grave; and all the people wept.', pt: 'Sepultaram Abner em Hebrom; e o rei, levantando a sua voz, chorou junto da sepultura de Abner; chorou também todo o povo.' },
      { v: 33, en: 'The king lamented for Abner, and said, “Should Abner die as a fool dies?', pt: 'Pranteou o rei a Abner, dizendo: Devia Abner, porventura, morrer como morre o vilão?' },
      { v: 34, en: 'Your hands weren’t bound, and your feet weren’t put into fetters. As a man falls before the children of iniquity, so you fell.” All the people wept again over him.', pt: 'As tuas mãos não estavam atadas, nem os teus pés carregados de grilhões; mas caíste como quem cai diante dos filhos da iniqüidade. Então todo o povo tornou a chorar por ele.' },
      { v: 35, en: 'All the people came to urge David to eat bread while it was yet day; but David swore, saying, “God do so to me, and more also, if I taste bread, or anything else, until the sun goes down.”', pt: 'Depois todo o povo veio fazer com que Davi comesse pão, sendo ainda dia; porém Davi jurou, dizendo: Assim Deus me faça e outro tanto, se, antes que o sol se ponha, eu provar pão ou qualquer outra coisa.' },
      { v: 36, en: 'All the people took notice of it, and it pleased them; as whatever the king did pleased all the people.', pt: 'Todo o povo notou isso, e pareceu-lhe bem; assim como tudo quanto o rei fez pareceu bem a todo o povo.' },
      { v: 37, en: 'So all the people and all Israel understood that day that it was not of the king to kill Abner the son of Ner.', pt: 'Assim todo o povo e todo o Israel entenderam naquele mesmo dia que não fora a vontade do rei que matassem a Abner, filho de Ner.' },
      { v: 38, en: 'The king said to his servants, “Don’t you know that there a prince and a great man has fallen today in Israel?', pt: 'Então disse o rei aos seus servos: Não sabeis que hoje caiu em Israel um príncipe, um grande homem?' },
      { v: 39, en: 'I am weak today, though anointed king. These men, the sons of Zeruiah are too hard for me. May Yahweh reward the evildoer according to his wickedness.”', pt: 'E quanto a mim, hoje estou fraco, embora ungido rei; estes homens, filhos de Zeruia, são duros demais para mim. Retribua o Senhor ao malfeitor conforme a sua maldade.' },
    ],
    4: [
      { v: 1, en: 'When Saul’s son heard that Abner was dead in Hebron, his hands became feeble, and all the Israelites were troubled.', pt: 'Quando Isbosete, filho de Saul, soube que Abner morrera em Hebrom, esvaíram-se-lhe as forças, e todo o Israel ficou perturbado.' },
      { v: 2, en: 'Saul’s son had two men who were captains of raiding bands. The name of one was Baanah, and the name of the other Rechab, the sons of Rimmon the Beerothite, of the children of Benjamin (for Beeroth also is considered a part of Benjamin:', pt: 'Tinha Isbosete, filho de Saul, dois homens chefes de guerrilheiros; um deles se chamava Baaná, e o outro Recabe, filhos de Rimom, o beerotita, dos filhos de Benjamim (porque também Beerote era contado de Benjamim,' },
      { v: 3, en: 'and the Beerothites fled to Gittaim, and have lived as foreigners there until today).', pt: 'tendo os beerotitas fugido para Jitaim, onde têm peregrinado até o dia de hoje).' },
      { v: 4, en: 'Now Jonathan, Saul’s son, had a son who was lame in his feet. He was five years old when the news came about Saul and Jonathan out of Jezreel; and his nurse picked him up and fled. As she hurried to flee, he fell and became lame. His name was Mephibosheth.', pt: 'Ora, Jônatas, filho de Saul, tinha um filho aleijado dos pés. Este era da idade de cinco anos quando chegaram de Jizreel as novas a respeito de Saul e Jônatas; pelo que sua ama o tomou, e fugiu; e sucedeu que, apressando-se ela a fugir, ele caiu, e ficou coxo. O seu nome era Mefibosete.' },
      { v: 5, en: 'The sons of Rimmon the Beerothite, Rechab and Baanah, went and came at about the heat of the day to the house of Ishbosheth, as he took his rest at noon.', pt: 'Foram os filhos de Rimom, o beerotita, Recabe e Baanã, no maior calor de dia, e entraram em casa de Isbosete, estando ele deitado a dormir a sesta.' },
      { v: 6, en: 'They came there into the middle of the house, as though they would have fetched wheat; and they struck him in the body: and Rechab and Baanah his brother escaped.', pt: 'Entraram ali até o meio da casa, como que vindo apanhar trigo, e o feriram no ventre; e Recabe e Baaná, seu irmão, escaparam.' },
      { v: 7, en: 'Now when they came into the house, as he lay on his bed in his bedroom, they struck him, killed him, beheaded him, and took his head, and went by the way of the Arabah all night.', pt: 'Porque entraram na sua casa, estando ele deitado na cama, no seu quarto de dormir, e o feriram e mataram, e cortando-lhe a cabeça, tomaram-na e andaram a noite toda pelo caminho da Arabá.' },
      { v: 8, en: 'They brought the head of Ishbosheth to David to Hebron, and said to the king, “Behold, the head of Ishbosheth, the son of Saul, your enemy, who sought your life! Yahweh has avenged my lord the king today of Saul, and of his offspring. ”', pt: 'Assim trouxeram a cabeça de Isbosete a Davi em Hebrom, e disseram ao rei: Eis aqui a cabeça de Isbosete, filho de Saul, teu inimigo, que procurava a tua morte; assim o Senhor vingou hoje ao rei meu Senhor, de Saul e da sua descendência.' },
      { v: 9, en: 'David answered Rechab and Baanah his brother, the sons of Rimmon the Beerothite, and said to them, “As Yahweh lives, who has redeemed my soul out of all adversity,', pt: 'Mas Davi, respondendo a Recabe e a Baaná, seu irmão, filhos de Rimom, e beerotita, disse-lhes: Vive o Senhor, que remiu a minha alma de toda a angústia!' },
      { v: 10, en: 'when someone told me, ‘Behold, Saul is dead,’ thinking that he brought good news, I seized him and killed him in Ziklag, which was the reward I gave him for his news.', pt: 'Se àquele que me trouxe novas, dizendo: Eis que Saul é morto, cuidando que trazia boas novas, eu logo lancei mão dele, e o matei em Ziclague, sendo essa a recompensa que lhe dei pelas novas,' },
      { v: 11, en: 'How much more, when wicked men have slain a righteous person in his own house on his bed, should I not now require his blood from your hand, and rid the earth of you?”', pt: 'quanto mais quando homens cruéis mataram um homem justo em sua casa, sobre a sua cama, não requererei eu e seu sangue de vossas mãos, e não vos exterminarei da terra?' },
      { v: 12, en: 'David commanded his young men, and they killed them, cut off their hands and their feet, and hanged them up beside the pool in Hebron. But they took the head of Ishbosheth, and buried it in Abner’s grave in Hebron.', pt: 'E Davi deu ordem aos seus mancebos; e eles os mataram e, cortando-lhes as mãos e os pés, os penduraram junto ao tanque em Hebrom. Tomaram, porém, a cabeça de Isbosete, e a sepultaram na sepultura de Abner, em Hebrom.' },
    ],
    5: [
      { v: 1, en: 'Then all the tribes of Israel came to David at Hebron, and spoke, saying, “Behold, we are your bone and your flesh.', pt: 'Então todas as tribos de Israel vieram a Davi em Hebrom e disseram: Eis-nos aqui, teus ossos e tua carne!' },
      { v: 2, en: 'In times past, when Saul was king over us, it was you who led Israel out and in. Yahweh said to you, ‘You will be shepherd of my people Israel, and you will be prince over Israel.’”', pt: 'Além disso, outrora, quando Saul ainda reinava sobre nós, eras tu o que saías e entravas com Israel; e também o Senhor te disse: Tu apascentarás o meu povo de Israel, e tu serás chefe sobre Israel.' },
      { v: 3, en: 'So all the elders of Israel came to the king to Hebron, and king David made a covenant with them in Hebron before Yahweh; and they anointed David king over Israel.', pt: 'Assim, pois, todos os anciãos de Israel vieram ter com o rei em Hebrom; e o rei Davi fez aliança com eles em Hebrom, perante o Senhor; e ungiram a Davi rei sobre Israel.' },
      { v: 4, en: 'David was thirty years old when he began to reign, and he reigned forty years.', pt: 'Trinta anos tinha Davi quando começou a reinar, e reinou quarenta anos.' },
      { v: 5, en: 'In Hebron he reigned over Judah seven years and six months; and in Jerusalem he reigned thirty-three years over all Israel and Judah.', pt: 'Em Hebrom reinou sete anos e seis meses sobre Judá, e em Jerusalém reinou trinta e três anos sobre todo o Israel e Judá.' },
      { v: 6, en: 'The king and his men went to Jerusalem against the Jebusites, the inhabitants of the land, who spoke to David, saying, “The blind and the lame will keep you out of here”; thinking, “David can’t come in here.”', pt: 'Depois partiu o rei com os seus homens para Jerusalém, contra os jebuseus, que habitavam naquela terra, os quais disseram a Davi: Não entrarás aqui; os cegos e es coxos te repelirão; querendo dizer: Davi de maneira alguma entrará aqui.' },
      { v: 7, en: 'Nevertheless David took the stronghold of Zion. This is David’s city.', pt: 'Todavia Davi tomou a fortaleza de Sião; esta é a cidade de Davi.' },
      { v: 8, en: 'David said on that day, “Whoever strikes the Jebusites, let him go up to the watercourse and strike those lame and blind, who are hated by David’s soul.” Therefore they say, “The blind and the lame can’t come into the house.”', pt: 'Ora, Davi disse naquele dia: Todo o que ferir os jebuseus, suba ao canal, e fira a esses coxos e cegos, a quem a alma de Davi aborrece. Por isso se diz: Nem cego nem, coxo entrara na casa.' },
      { v: 9, en: 'David lived in the stronghold, and called it David’s city. David built around from Millo and inward.', pt: 'Assim habitou Davi na fortaleza, e chamou-a cidade de Davi; e foi levantando edifícios em redor, desde Milo para dentro.' },
      { v: 10, en: 'David grew greater and greater; for Yahweh, the God of Armies, was with him.', pt: 'Davi ia-se engrandecendo cada vez mais, porque o Senhor Deus dos exércitos era com ele.' },
      { v: 11, en: 'Hiram king of Tyre sent messengers to David, with cedar trees, carpenters, and masons; and they built David a house.', pt: 'Hirão, rei de Tiro, enviou mensageiros a Davi, e madeira de cedro, e carpinteiros e pedreiros, que edificaram para Davi uma casa.' },
      { v: 12, en: 'David perceived that Yahweh had established him king over Israel, and that he had exalted his kingdom for his people Israel’s sake.', pt: 'Entendeu, pois, Davi que o Senhor o confirmara rei sobre Israel, e que exaltara e reino dele por amar do seu povo Israel.' },
      { v: 13, en: 'David took more concubines and wives for himself out of Jerusalem, after he had come from Hebron; and more sons and daughters were born to David.', pt: 'Davi tomou ainda para si concubinas e mulheres de Jerusalém, depois que viera de Hebrom; e nasceram a Davi mais filhos e filhas.' },
      { v: 14, en: 'These are the names of those who were born to him in Jerusalem: Shammua, Shobab, Nathan, Solomon,', pt: 'São estes os nomes dos que lhe nasceram em Jerusalém: Samua, Sobabe, Natã, Salomão,' },
      { v: 15, en: 'Ibhar, Elishua, Nepheg, Japhia,', pt: 'Ibar, Elisua, Nefegue, Jafia,' },
      { v: 16, en: 'Elishama, Eliada, and Eliphelet.', pt: 'Elisama, e Eliadá e Elifelete.' },
      { v: 17, en: 'When the Philistines heard that they had anointed David king over Israel, all the Philistines went up to seek David, but David heard about it and went down to the stronghold.', pt: 'Quando os filisteus ouviram que Davi fora ungido rei sobre Israel, subiram todos em busca dele. Ouvindo isto, Davi desceu à fortaleza.' },
      { v: 18, en: 'Now the Philistines had come and spread themselves in the valley of Rephaim.', pt: 'Os filisteus vieram, e se estenderam pelo vale de Refaim.' },
      { v: 19, en: 'David inquired of Yahweh, saying, “Shall I go up against the Philistines? Will you deliver them into my hand?” Yahweh said to David, “Go up; for I will certainly deliver the Philistines into your hand.”', pt: 'Pelo que Davi consultou ao Senhor, dizendo: Subirei contra os filisteus? entregar-mos-ás nas mãos? Respondeu o Senhor a Davi: Sobe, pois eu entregarei os filisteus nas tuas mãos.' },
      { v: 20, en: 'David came to Baal Perazim, and David struck them there. Then he said, “Yahweh has broken my enemies before me, like the breach of waters.” Therefore he called the name of that place Baal Perazim.', pt: 'Então foi Davi a Baal-Perazim, e ali os derrotou; e disse: O Senhor rompeu os meus inimigos diante de mim, como as águas rompem barreiras. Por isso chamou o nome daquele lugar Baal-Perazim.' },
      { v: 21, en: 'They left their images there; and David and his men took them away.', pt: 'Os filisteus deixaram lá os seus ídolos, e Davi e os seus homens os levaram.' },
      { v: 22, en: 'The Philistines came up yet again, and spread themselves in the valley of Rephaim.', pt: 'Tornaram ainda os filisteus a subir, e se espalharam pelo vale de Refaim.' },
      { v: 23, en: 'When David inquired of Yahweh, he said, “You shall not go up. Circle around behind them, and attack them in front of the mulberry trees.', pt: 'E Davi consultou ao Senhor, que respondeu: Não subirás; mas rodeia-os por detrás, e virás sobre eles por defronte dos balsameiros.' },
      { v: 24, en: 'When you hear the sound of marching in the tops of the mulberry trees, then stir yourself up; for then Yahweh has gone out before you to strike the army of the Philistines.”', pt: 'E há de ser que, ouvindo tu o ruído de marcha pelas copas dos balsameiros, então te apressarás, porque é o Senhor que sai diante de ti, a ferir o arraial dos filisteus.' },
      { v: 25, en: 'David did so, as Yahweh commanded him, and struck the Philistines all the way from Geba to Gezer.', pt: 'Fez, pois, Davi como o Senhor lhe havia ordenado; e feriu os filisteus desde Geba, até chegar a Gezer.' },
    ],
    6: [
      { v: 1, en: 'David again gathered together all the chosen men of Israel, thirty thousand.', pt: 'Tornou Davi a ajuntar todos os escolhidos de Israel, em número de trinta mil.' },
      { v: 2, en: 'David arose, and went with all the people who were with him, from Baale Judah, to bring up from there God’s ark, which is called by the Name, even the name of Yahweh of Armies who sits above the cherubim.', pt: 'Depois levantou-se Davi, e partiu para Baal-Judá com todo o povo que tinha consigo, para trazerem dali para cima a arca de Deus, a qual é chamada pelo Nome, o nome do Senhor dos exércitos, que se assenta sobre os querubins.' },
      { v: 3, en: 'They set God’s ark on a new cart, and brought it out of Abinadab’s house that was on the hill; and Uzzah and Ahio, the sons of Abinadab, drove the new cart.', pt: 'Puseram a arca de Deus em um carro novo, e a levaram da casa de Abinadabe, que estava sobre o outeiro; e Uzá e Aiô, filhos de Abinadabe, guiavam o carro novo.' },
      { v: 4, en: 'They brought it out of Abinadab’s house, which was in the hill, with God’s ark; and Ahio went before the ark.', pt: 'Foram, pois, levando-o da casa de Abinadabe, que estava sobre o outeiro, com a arca de Deus; e Aiô ia adiante da arca.' },
      { v: 5, en: 'David and all the house of Israel played before Yahweh with all kinds of instruments made of cypress wood, with harps, with stringed instruments, with tambourines, with castanets, and with cymbals.', pt: 'E Davi, e toda a casa de Israel, tocavam perante o Senhor, com toda sorte de instrumentos de pau de faia, como também com harpas, saltérios, tamboris, pandeiros e címbalos.' },
      { v: 6, en: 'When they came to the threshing floor of Nacon, Uzzah reached for God’s ark, and took hold of it; for the cattle stumbled.', pt: 'Quando chegaram à eira de Nacom, Uzá estendeu a mão à arca de Deus, e pegou nela, porque os bois tropeçaram.' },
      { v: 7, en: 'Yahweh’s anger burned against Uzzah; and God struck him there for his error; and he died there by God’s ark.', pt: 'Então a ira do Senhor se acendeu contra Uzá, e Deus o feriu ali; e Uzá morreu ali junto à arca de Deus.' },
      { v: 8, en: 'David was displeased, because Yahweh had broken out against Uzzah; and he called that place Perez Uzzah, to this day.', pt: 'E Davi se contristou, porque o Senhor abrira rotura em Uzá; e passou-se a chamar àquele lugar, Pérez-Uzá, até o dia de hoje.' },
      { v: 9, en: 'David was afraid of Yahweh that day; and he said, “How could Yahweh’s ark come to me?”', pt: 'Davi, pois, teve medo do Senhor naquele dia, e disse: Como virá a mim a arca do Senhor?' },
      { v: 10, en: 'So David would not move Yahweh’s ark to be with him in David’s city; but David carried it aside into Obed-Edom the Gittite’s house.', pt: 'E não quis levar a arca do Senhor para a cidade de Davi; mas fê-la entrar na casa de Obede-Edom, o gitita.' },
      { v: 11, en: 'Yahweh’s ark remained in Obed-Edom the Gittite’s house three months; and Yahweh blessed Obed-Edom and all his house.', pt: 'E ficou a arca do Senhor três meses na casa de Obede-Edom, o gitita, e o Senhor o abençoou e a toda a sua casa.' },
      { v: 12, en: 'King David was told, “Yahweh has blessed the house of Obed-Edom, and all that belongs to him, because of God’s ark.” So David went and brought up God’s ark from the house of Obed-Edom into David’s city with joy.', pt: 'Então informaram a Davi, dizendo: O Senhor abençoou a casa de Obede-Edom, e tudo quanto é dele, por causa da arca de Deus. Foi, pois, Davi, e com alegria fez subir a arca de Deus, da casa de Obede-Edom para a cidade de Davi.' },
      { v: 13, en: 'When those who bore Yahweh’s ark had gone six paces, he sacrificed an ox and a fattened calf.', pt: 'Quando os que levavam a arca do Senhor tinham dado seis passos, ele sacrificou um boi e um animal cevado.' },
      { v: 14, en: 'David danced before Yahweh with all his might; and David was clothed in a linen ephod.', pt: 'E Davi dançava com todas as suas forças diante do Senhor; e estava Davi cingido dum éfode de linho.' },
      { v: 15, en: 'So David and all the house of Israel brought up Yahweh’s ark with shouting, and with the sound of the trumpet.', pt: 'Assim Davi e toda a casa de Israel subiam, trazendo a arca do Senhor com júbilo e ao som de trombetas.' },
      { v: 16, en: 'As Yahweh’s ark came into David’s city, Michal the daughter of Saul looked out through the window, and saw king David leaping and dancing before Yahweh; and she despised him in her heart.', pt: 'Quando entrava a arca do Senhor na cidade de Davi, Mical, filha de Saul, estava olhando pela janela; e, vendo ao rei Davi saltando e dançando diante do senhor, o desprezou no seu coraçao.' },
      { v: 17, en: 'They brought in Yahweh’s ark, and set it in its place, in the middle of the tent that David had pitched for it; and David offered burnt offerings and peace offerings before Yahweh.', pt: 'Introduziram, pois, a arca do Senhor, e a puseram no seu lugar, no meio da tenda que Davi lhe armara; e Davi ofereceu holocaustos e ofertas pacíficas perante o Senhor.' },
      { v: 18, en: 'When David had finished offering the burnt offering and the peace offerings, he blessed the people in the name of Yahweh of Armies.', pt: 'Quando Davi acabou de oferecer os holocaustos e ofertas pacíficas, abençoou o povo em nome do Senhor dos exércitos.' },
      { v: 19, en: 'He gave to all the people, even among the whole multitude of Israel, both to men and women, to everyone a portion of bread, dates, and raisins. So all the people departed, each to his own house.', pt: 'Depois repartiu a todo o povo, a toda a multidão de Israel, tanto a homens como a mulheres, a cada um, um bolo de pão, um bom pedaço de carne e um bolo de passas. Em seguida todo o povo se retirou, cada um para sua casa.' },
      { v: 20, en: 'Then David returned to bless his household. Michal the daughter of Saul came out to meet David, and said, “How glorious the king of Israel was today, who uncovered himself today in the eyes of the servants of his servants, as one of the vain fellows shamelessly uncovers himself!”', pt: 'Então Davi voltou para abençoar a sua casa; e Mical, filha de Saul, saiu a encontrar-se com Davi, e disse: Quão honrado foi o rei de Israel, descobrindo-se hoje aos olhos das servas de seus servos, como sem pejo se descobre um indivíduo qualquer.' },
      { v: 21, en: 'David said to Michal, “It was before Yahweh, who chose me above your father, and above all his house, to appoint me prince over the people of Yahweh, over Israel. Therefore I will celebrate before Yahweh.', pt: 'Disse, porém, Davi a Mical: Perante o Senhor, que teu escolheu a mim de preferência a teu pai e a toda a sua casa, estabelecendo-me por chefe sobre o povo do Senhor, sobre Israel, sim, foi perante Senhor que dancei; e perante ele ainda hei de dançar' },
      { v: 22, en: 'I will be yet more vile than this, and will be worthless in my own sight. But of the servants of whom you have spoken, they will honor me.”', pt: 'Também ainda mais do que isso me envilecerei, e me humilharei aos meus olhos; mas das servas, de quem falaste, delas serei honrado.' },
      { v: 23, en: 'Michal the daughter of Saul had no child to the day of her death.', pt: 'E Mical, filha de Saul não teve filhos, até o dia de sua morte.' },
    ],
    7: [
      { v: 1, en: 'When the king lived in his house, and Yahweh had given him rest from all his enemies all around,', pt: 'Ora, estando o rei Davi em sua casa e tendo-lhe dado o Senhor descanso de todos os seus inimigos em redor,' },
      { v: 2, en: 'the king said to Nathan the prophet, “See now, I dwell in a house of cedar, but God’s ark dwells within curtains.”', pt: 'disse ele ao profeta Natã: Eis que eu moro numa casa de cedro, enquanto que a arca de Deus dentro de uma tenda.' },
      { v: 3, en: 'Nathan said to the king, “Go, do all that is in your heart; for Yahweh is with you.”', pt: 'Respondeu Natã ao rei: Vai e faze tudo quanto está no teu coração, porque o Senhor é contigo.' },
      { v: 4, en: 'That same night, Yahweh’s word came to Nathan, saying,', pt: 'Mas naquela mesma noite a palavra do Senhor veio a Natã, dizendo:' },
      { v: 5, en: '“Go and tell my servant David, ‘Yahweh says, “Should you build me a house for me to dwell in?', pt: 'Vai, e dize a meu servo Davi: Assim diz o Senhor: Edificar-me-ás tu uma casa para eu nela habitar?' },
      { v: 6, en: 'For I have not lived in a house since the day that I brought the children of Israel up out of Egypt, even to this day, but have moved around in a tent and in a tabernacle.', pt: 'Porque em casa nenhuma habitei, desde o dia em que fiz subir do Egito os filhos de Israel até o dia de hoje, mas tenho andado em tenda e em tabernáculo.' },
      { v: 7, en: 'In all places in which I have walked with all the children of Israel, did I say a word to any of the tribes of Israel, whom I commanded to be shepherd of my people Israel, saying, ‘Why have you not built me a house of cedar?’”’', pt: 'E em todo lugar em que tenho andado com todos os filhos de Israel, falei porventura, alguma palavra a qualquer das suas tribos a que mandei apascentar o meu povo de Israel, dizendo: por que não me edificais uma casa de cedro?' },
      { v: 8, en: 'Now therefore tell my servant David this, ‘Yahweh of Armies says, “I took you from the sheep pen, from following the sheep, to be prince over my people, over Israel.', pt: 'Agora, pois, assim dirás ao meu servo Davi: Assim diz o Senhor dos exércitos: Eu te tomei da malhada, de detrás das ovelhas, para que fosses príncipe sobre o meu povo, sobre Israel;' },
      { v: 9, en: 'I have been with you wherever you went, and have cut off all your enemies from before you. I will make you a great name, like the name of the great ones who are in the earth.', pt: 'e fui contigo, por onde quer que foste, e destruí a todos os teus inimigos diante de ti; e te farei um grande nome, como o nome dos grandes que há na terra.' },
      { v: 10, en: 'I will appoint a place for my people Israel, and will plant them, that they may dwell in their own place, and be moved no more. The children of wickedness will not afflict them any more, as at the first,', pt: 'Também designarei lugar para o meu povo, para Israel, e o plantarei ali, para que ele habite no seu lugar, e não mais seja perturbado, e nunca mais os filhos da iniqüidade o aflijam, como dantes,' },
      { v: 11, en: 'and as from the day that I commanded judges to be over my people Israel. I will cause you to rest from all your enemies. Moreover Yahweh tells you that Yahweh will make you a house.', pt: 'e como desde o dia em que ordenei que houvesse juízes sobre o meu povo Israel. A ti, porém, darei descanso de todos os teus inimigos. Também o Senhor te declara que ele te fará casa.' },
      { v: 12, en: 'When your days are fulfilled, and you sleep with your fathers, I will set up your offspring after you, who will proceed out of your body, and I will establish his kingdom.', pt: 'Quando teus dias forem completos, e vieres a dormir com teus pais, então farei levantar depois de ti um dentre a tua descendência, que sair das tuas entranhas, e estabelecerei o seu reino.' },
      { v: 13, en: 'He will build a house for my name, and I will establish the throne of his kingdom forever.', pt: 'Este edificará uma casa ao meu nome, e eu estabelecerei para sempre o trono do seu reino.' },
      { v: 14, en: 'I will be his father, and he will be my son. If he commits iniquity, I will chasten him with the rod of men, and with the stripes of the children of men;', pt: 'Eu lhe serei pai, e ele me será filho. E, se vier a transgredir, castigá-lo-ei com vara de homens, e com açoites de filhos de homens;' },
      { v: 15, en: 'but my loving kindness will not depart from him, as I took it from Saul, whom I put away before you.', pt: 'mas não retirarei dele a minha benignidade como a retirei de Saul, a quem tirei de diante de ti.' },
      { v: 16, en: 'Your house and your kingdom will be made sure forever before you. Your throne will be established forever.”’”', pt: 'A tua casa, porém, e o teu reino serão firmados para sempre diante de ti; teu trono será estabelecido para sempre.' },
      { v: 17, en: 'Nathan spoke to David all these words, and according to all this vision.', pt: 'Conforme todas estas palavras, e conforme toda esta visão, assim falou Natã a Davi.' },
      { v: 18, en: 'Then David the king went in, and sat before Yahweh; and he said, “Who am I, Lord Yahweh, and what is my house, that you have brought me this far?', pt: 'Então entrou o rei Davi, e sentou-se perante o Senhor, e disse: Quem sou eu, Senhor Jeová, e que é a minha casa, para me teres trazido até aqui?' },
      { v: 19, en: 'This was yet a small thing in your eyes, Lord Yahweh; but you have spoken also of your servant’s house for a great while to come; and this among men, Lord Yahweh!', pt: 'E isso ainda foi pouco aos teus olhos, Senhor Jeová, senão que também falaste da casa do teu servo para tempos distantes; e me tens mostrado gerações futuras, ó Senhor Jeová?' },
      { v: 20, en: 'What more can David say to you? For you know your servant, Lord Yahweh.', pt: 'Que mais te poderá dizer Davi. pois tu conheces bem o teu servo, ó Senhor Jeová.' },
      { v: 21, en: 'For your word’s sake, and according to your own heart, you have worked all this greatness, to make your servant know it.', pt: 'Por causa da tua palavra, e segundo o teu coração, fizeste toda esta grandeza, revelando-a ao teu servo.' },
      { v: 22, en: 'Therefore you are great, Yahweh God. For there is no one like you, neither is there any God besides you, according to all that we have heard with our ears.', pt: 'Portanto és grandioso, ó Senhor Jeová, porque ninguém há semelhante a ti, e não há Deus senão tu só, segundo tudo o que temos ouvido com os nossos ouvidos.' },
      { v: 23, en: 'What one nation in the earth is like your people, even like Israel, whom God went to redeem to himself for a people, and to make himself a name, and to do great things for you, and awesome things for your land, before your people, whom you redeemed to yourself out of Egypt, from the nations and their gods?', pt: 'Que outra nação na terra é semelhante a teu povo Israel, a quem tu, ó Deus, foste resgatar para te ser povo, para te fazeres um nome, e para fazeres a seu favor estas grandes e terríveis coisas para a tua terra, diante do teu povo, que tu resgataste para ti do Egito, desterrando nações e seus deuses?' },
      { v: 24, en: 'You established for yourself your people Israel to be your people forever; and you, Yahweh, became their God.', pt: 'Assim estabeleceste o teu povo Israel por teu povo para sempre, e tu, Senhor, te fizeste o seu Deus.' },
      { v: 25, en: 'Now, Yahweh God, the word that you have spoken concerning your servant, and concerning his house, confirm it forever, and do as you have spoken.', pt: 'Agora, pois, o Senhor Jeová, confirma para sempre a palavra que falaste acerca do teu servo e acerca da sua casa, e faze como tens falado,' },
      { v: 26, en: 'Let your name be magnified forever, saying, ‘Yahweh of Armies is God over Israel; and the house of your servant David will be established before you.’', pt: 'para que seja engrandecido o teu nome para sempre, e se diga: O Senhor dos exércitos é Deus sobre Israel; e a casa do teu servo será estabelecida diante de ti.' },
      { v: 27, en: 'For you, Yahweh of Armies, the God of Israel, have revealed to your servant, saying, ‘I will build you a house.’ Therefore your servant has found in his heart to pray this prayer to you.', pt: 'Pois tu, Senhor dos exércitos, Deus de Israel, fizeste uma revelação ao teu servo, dizendo: Edificar-te-ei uma casa. Por isso o teu servo se animou a fazer-te esta oração.' },
      { v: 28, en: '“Now, O Lord Yahweh, you are God, and your words are truth, and you have promised this good thing to your servant.', pt: 'Agora, pois, Senhor Jeová, tu és Deus, e as tuas palavras são verdade, e tens prometido a teu servo este bem.' },
      { v: 29, en: 'Now therefore let it please you to bless the house of your servant, that it may continue forever before you; for you, Lord Yahweh, have spoken it. Let the house of your servant be blessed forever with your blessing.”', pt: 'Sê, pois, agora servido de abençoar a casa do teu servo, para que subsista para sempre diante de ti; pois tu, ó Senhor Jeová, o disseste; e com a tua bênção a casa do teu servo será, abençoada para sempre.' },
    ],
    8: [
      { v: 1, en: 'After this, David struck the Philistines and subdued them; and David took the bridle of the mother city out of the hand of the Philistines.', pt: 'Sucedeu depois disso que Davi derrotou os filisteus, e os sujeitou; e Davi tomou a Metegue-Ama das mãos dos filisteus.' },
      { v: 2, en: 'He struck Moab, and measured them with the line, making them to lie down on the ground; and he measured two lines to put to death, and one full line to keep alive. The Moabites became servants to David, and brought tribute.', pt: 'Também derrotou os moabitas, e os mediu com cordel, fazendo-os deitar por terra; e mediu dois cordéis para os matar, e um cordel inteiro para os deixar com vida. Ficaram assim os moabitas por servos de Davi, pagando-lhe tributos.' },
      { v: 3, en: 'David struck also Hadadezer the son of Rehob, king of Zobah, as he went to recover his dominion at the River.', pt: 'Davi também derrotou a Hadadézer, filho de Reobe, rei de Zobá, quando este ia estabelecer o seu domínio sobre o rio Eufrates.' },
      { v: 4, en: 'David took from him one thousand seven hundred horsemen and twenty thousand footmen. David hamstrung all the chariot horses, but reserved of them for one hundred chariots.', pt: 'E tomou-lhe Davi mil e setecentos cavaleiros e vinte mil homens de infantaria; e Davi jarretou a todos os cavalos dos carros, reservando apenas cavalos para cem carros.' },
      { v: 5, en: 'When the Syrians of Damascus came to help Hadadezer king of Zobah, David struck twenty two thousand men of the Syrians.', pt: 'Os sírios de Damasco vieram socorrer a Hadadézer, rei de Zobá, mas Davi matou deles vinte e dois mil homens.' },
      { v: 6, en: 'Then David put garrisons in Syria of Damascus; and the Syrians became servants to David, and brought tribute. Yahweh gave victory to David wherever he went.', pt: 'Então Davi pôs guarnições em Síria de Damasco, e os sírios ficaram por servos de Davi, pagando-lhe tributos. E o Senhor lhe dava a vitória por onde quer que ia.' },
      { v: 7, en: 'David took the shields of gold that were on the servants of Hadadezer, and brought them to Jerusalem.', pt: 'E Davi tomou os escudos de ouro que os servos de Hadadézer usavam, e os trouxe para Jerusalém.' },
      { v: 8, en: 'From Betah and from Berothai, cities of Hadadezer, king David took a great quantity of brass.', pt: 'De Betá e de Berotai, cidades de Hadadézer, o rei Davi tomou grande quantidade de bronze.' },
      { v: 9, en: 'When Toi king of Hamath heard that David had struck all the army of Hadadezer,', pt: 'Quando Toí, rei de Hamate, ouviu que Davi ferira todo o exército de Hadadézer,' },
      { v: 10, en: 'then Toi sent Joram his son to king David, to greet him, and to bless him, because he had fought against Hadadezer and struck him; for Hadadezer had wars with Toi. Joram brought with him vessels of silver, vessels of gold, and vessels of brass:', pt: 'mandou-lhe seu filho Jorão para saudá-lo, e para felicitá-lo por haver pelejado contra Hadadézer e o haver derrotado; pois Hadadézer de contínuo fazia guerra a Toí. E Jorão trouxe consigo vasos de prata de ouro e de bronze,' },
      { v: 11, en: 'King David also dedicated these to Yahweh, with the silver and gold that he dedicated of all the nations which he subdued;', pt: 'os quais o rei Davi consagrou ao Senhor, como já havia consagrado a prata e o ouro de todas as nações que sujeitara.' },
      { v: 12, en: 'of Syria, of Moab, of the children of Ammon, of the Philistines, of Amalek, and of the plunder of Hadadezer, son of Rehob, king of Zobah.', pt: 'da Síria, de Moabe, dos amonitas, dos filisteus, de Amaleque e dos despojos de Hadadézer, filho de Reobe, rei de Zobá.' },
      { v: 13, en: 'David earned a reputation when he returned from striking down eighteen thousand men of the Syrians in the Valley of Salt.', pt: 'Assim Davi ganhou nome para si. E quando voltou, matou no Vale do Sal a dezoito mil edomitas.' },
      { v: 14, en: 'He put garrisons in Edom. Throughout all Edom put he garrisons, and all the Edomites became servants to David. Yahweh gave victory to David wherever he went.', pt: 'E pôs guarnições em Edom; pô-las em todo o Edom, e todos os edomitas tornaram-se servos de Davi. E o Senhor lhe dava a vitória por onde quer que ia.' },
      { v: 15, en: 'David reigned over all Israel; and David executed justice and righteousness for all his people.', pt: 'Reinou, pois, Davi sobre todo o Israel, e administrava a justiça e a eqüidade a todo o seu povo.' },
      { v: 16, en: 'Joab the son of Zeruiah was over the army, Jehoshaphat the son of Ahilud was recorder,', pt: 'Joabe, filho de Zeruia, estava sobre o exército; Jeosafá, filho de Ailude, era cronista;' },
      { v: 17, en: 'Zadok the son of Ahitub and Ahimelech the son of Abiathar were priests, Seraiah was scribe,', pt: 'Zadoque, filho de Aitube, e Aimeleque, filho de Abiatar, eram sacerdotes; Seraías era escrivão;' },
      { v: 18, en: 'Benaiah the son of Jehoiada was over the Cherethites and the Pelethites, David’s sons were chief ministers.', pt: 'Benaías, filho de Jeoiada, tinha o cargo dos quereteus e peleteus; e os filhos de Davi eram ministros de estado.' },
    ],
    9: [
      { v: 1, en: 'David said, “Is there yet any who is left of Saul’s house, that I may show him kindness for Jonathan’s sake?”', pt: 'Disse Davi: Resta ainda alguém da casa de Saul, para que eu use de benevolência para com ele por amor de Jônatas?' },
      { v: 2, en: 'There was of Saul’s house a servant whose name was Ziba, and they called him to David; and the king said to him, “Are you Ziba?” He said, “I am your servant.”', pt: 'E havia um servo da casa de Saul, cujo nome era Ziba; e o chamaram à presença de Davi. perguntou-lhe o rei: Tu és Ziba? Respondeu ele: Teu servo!' },
      { v: 3, en: 'The king said, “Is there not yet any of Saul’s house, that I may show the kindness of God to him?” Ziba said to the king, “Jonathan still has a son, who is lame in his feet.”', pt: 'Prosseguiu o rei: Não há ainda alguém da casa de Saul para que eu possa usar com ele da benevolência de Deus? Então disse Ziba ao rei: Ainda há um filho de Jônatas, aleijado dos pés.' },
      { v: 4, en: 'The king said to him, “Where is he?” Ziba said to the king, “Behold, he is in the house of Machir the son of Ammiel, in Lo Debar.”', pt: 'Perguntou-lhe o rei: Onde está. Respondeu Ziba ao rei: Está em casa de Maquir, filho de Amiel, em Lo-Debar.' },
      { v: 5, en: 'Then king David sent, and brought him out of the house of Machir the son of Ammiel, from Lo Debar.', pt: 'Então mandou o rei Davi, e o tomou da casa de Maquir, filho de Amiel, em Lo-Debar.' },
      { v: 6, en: 'Mephibosheth, the son of Jonathan, the son of Saul, came to David, and fell on his face, and showed respect. David said, “Mephibosheth.” He answered, “Behold, your servant!”', pt: 'E Mefibosete, filho de Jônatas, filho de Saul, veio a Davi e, prostrando-se com o rosto em terra, lhe fez reverência. E disse Davi: Mefibosete! Respondeu ele: Eis aqui teu servo.' },
      { v: 7, en: 'David said to him, “Don’t be afraid; for I will surely show you kindness for Jonathan your father’s sake, and will restore to you all the land of Saul your father. You will eat bread at my table continually.”', pt: 'Então lhe disse Davi: Não temas, porque de certo usarei contigo de benevolência por amor de Jônatas, teu pai, e te restituirei todas as terras de Saul, teu pai; e tu sempre comerás à minha mesa.' },
      { v: 8, en: 'He bowed down, and said, “What is your servant, that you should look at such a dead dog as I am?”', pt: 'Então Mefibosete lhe fez reverência, e disse: Que é o teu servo, para teres olhado para um cão morto tal como eu?' },
      { v: 9, en: 'Then the king called to Ziba, Saul’s servant, and said to him, “All that belonged to Saul and to all his house I have given to your master’s son.', pt: 'Então chamou Davi a Ziba, servo de Saul, e disse-lhe: Tudo o que pertencia a Saul, e a toda a sua casa, tenho dado ao filho de teu senhor.' },
      { v: 10, en: 'Till the land for him, you, your sons, and your servants. Bring in the harvest, that your master’s son may have bread to eat; but Mephibosheth your master’s son will always eat bread at my table.” Now Ziba had fifteen sons and twenty servants.', pt: 'Cultivar-lhe-ás, pois, a terra, tu e teus filhos, e teus servos; e recolherás os frutos, para que o filho de teu senhor tenha pão para comer; mas Mefibosete, filho de teu senhor, comerá sempre à minha mesa. Ora, tinha Ziba quinze filhos e vinte servos.' },
      { v: 11, en: 'Then Ziba said to the king, “According to all that my lord the king commands his servant, so your servant will do.” So Mephibosheth ate at the king’s table, like one of the king’s sons.', pt: 'Respondeu Ziba ao rei: Conforme tudo quanto meu senhor, o rei, manda a seu servo, assim o fará ele. Disse o rei: Quanto a Mefibosete, ele comerá à minha mesa como um dos filhos do rei.' },
      { v: 12, en: 'Mephibosheth had a young son, whose name was Mica. All that lived in Ziba’s house were servants to Mephibosheth.', pt: 'E tinha Mefibosete um filho pequeno, cujo nome era Mica. E todos quantos moravam em casa de Ziba eram servos de Mefibosete.' },
      { v: 13, en: 'So Mephibosheth lived in Jerusalem; for he ate continually at the king’s table. He was lame in both his feet.', pt: 'Morava, pois, Mefibosete em Jerusalém, porquanto sempre comia à mesa do rei. E era coxo de ambos os pés.' },
    ],
    10: [
      { v: 1, en: 'After this, the king of the children of Ammon died, and Hanun his son reigned in his place.', pt: 'Depois disto morreu o rei dos amonitas, e seu filho Hanum reinou em seu lugar.' },
      { v: 2, en: 'David said, “I will show kindness to Hanun the son of Nahash, as his father showed kindness to me.” So David sent by his servants to comfort him concerning his father. David’s servants came into the land of the children of Ammon.', pt: 'Então disse Davi: usarei de benevolência para com Hanum, filho de Naás, como seu pai usou de benevolência para comigo. Davi, pois, enviou os seus servos para o consolar acerca de seu pai; e foram os servos de Davi à terra dos amonitas.' },
      { v: 3, en: 'But the princes of the children of Ammon said to Hanun their lord, “Do you think that David honors your father, in that he has sent comforters to you? Hasn’t David sent his servants to you to search the city, to spy it out, and to overthrow it?”', pt: 'Então disseram os príncipes dos amonitas a seu senhor, Hanum: Pensas, porventura, que foi para honrar teu pai que Davi te enviou consoladores? Não te enviou antes os seus servos para reconhecerem esta cidade e para a espiarem, a fim de transtorná-la?' },
      { v: 4, en: 'So Hanun took David’s servants, shaved off one half of their beards, and cut off their garments in the middle, even to their buttocks, and sent them away.', pt: 'Pelo que Hanum tomou os servos de Davi, rapou-lhes metade da barba, cortou-lhes metade dos vestidos, até as nádegas, e os despediu.' },
      { v: 5, en: 'When they told David this, he sent to meet them, for the men were greatly ashamed. The king said, “Wait at Jericho until your beards have grown, and then return.”', pt: 'Quando isso foi dito a Davi, enviou ele mensageiros a encontrá-los, porque aqueles homens estavam sobremaneira envergonhados; e mandou dizer-lhes: Deixai-vos estar em Jericó, até que vos torne a crescer a barba, e então voltai.' },
      { v: 6, en: 'When the children of Ammon saw that they had become odious to David, the children of Ammon sent and hired the Syrians of Beth Rehob, and the Syrians of Zobah, twenty thousand footmen, and the king of Maacah with one thousand men, and the men of Tob twelve thousand men.', pt: 'Vendo, pois, os amonitas que se haviam feito abomináveis para com Davi, enviaram e alugaram dos sírios de Bete-Reobe e dos sírios de Bete-Reobe e dos sírios de Sobá vinte mil homens de infantaria, e do rei de Maacá mil homens, e dos homens de Tobe doze mil.' },
      { v: 7, en: 'When David heard of it, he sent Joab, and all the army of the mighty men.', pt: 'O que ouvindo Davi, enviou contra eles a Joabe com todo o exército dos valentes.' },
      { v: 8, en: 'The children of Ammon came out, and put the battle in array at the entrance of the gate. The Syrians of Zobah and of Rehob, and the men of Tob and Maacah, were by themselves in the field.', pt: 'E saíram os amonitas, e ordenaram a batalha a entrada da porta; mas os sírios de Zobá e de Reobe, e os homens de Tobe e de Maacá estavam à parte no campo.' },
      { v: 9, en: 'Now when Joab saw that the battle was set against him before and behind, he chose of all the choice men of Israel, and put them in array against the Syrians.', pt: 'Vendo, pois, Joabe que a batalha estava preparada contra ele pela frente e pela retaguarda, escolheu alguns homens dentre a flor do exército de Israel, e formou-os em linha contra os sírios;' },
      { v: 10, en: 'The rest of the people he committed into the hand of Abishai his brother; and he put them in array against the children of Ammon.', pt: 'e entregou o resto do povo a seu irmão Abisai, para que o formasse em linha contra os amonitas.' },
      { v: 11, en: 'He said, “If the Syrians are too strong for me, then you shall help me; but if the children of Ammon are too strong for you, then I will come and help you.', pt: 'E disse-lhe: Se os sírios forem mais fortes do que eu, tu me virás em socorro; e se os amonitas forem mais fortes do que tu, eu irei em teu socorro.' },
      { v: 12, en: 'Be courageous, and let us be strong for our people, and for the cities of our God; and may Yahweh do what seems good to him.”', pt: 'Tem bom ânimo, e sejamos corajosos pelo nosso povo, e pelas cidades de nosso Deus; e faça o Senhor o que bem lhe parecer.' },
      { v: 13, en: 'So Joab and the people who were with him came near to the battle against the Syrians, and they fled before him.', pt: 'Então Joabe e o povo que estava com ele travaram a peleja contra os sírios; e estes fugiram diante dele.' },
      { v: 14, en: 'When the children of Ammon saw that the Syrians had fled, they likewise fled before Abishai, and entered into the city. Then Joab returned from the children of Ammon, and came to Jerusalem.', pt: 'E, vendo os amonitas que os sírios fugiam, também eles fugiram de diante de Abisai, e entraram na cidade. Então Joabe voltou dos amonitas e veio para Jerusalém.' },
      { v: 15, en: 'When the Syrians saw that they were defeated by Israel, they gathered themselves together.', pt: 'Os sírios, vendo que tinham sido derrotados diante de Israel, trataram de refazer-se.' },
      { v: 16, en: 'Hadadezer sent, and brought out the Syrians who were beyond the River: and they came to Helam, with Shobach the captain of the army of Hadadezer at their head.', pt: 'E Hadadézer mandou que viessem os sírios que estavam da outra banda do rio; e eles vieram a Helã, tendo à sua frente Sobaque, chefe do exército de Hadadézer.' },
      { v: 17, en: 'David was told that; and he gathered all Israel together, passed over the Jordan, and came to Helam. The Syrians set themselves in array against David, and fought with him.', pt: 'Davi, informado disto, ajuntou todo o Israel e, passando o Jordão, foi a Helã; e os sírios se puseram em ordem contra Davi, e pelejaram contra ele.' },
      { v: 18, en: 'The Syrians fled before Israel; and David killed seven hundred charioteers of the Syrians, and forty thousand horsemen, and struck Shobach the captain of their army, so that he died there.', pt: 'Os sírios, porém, fugiram de diante de Israel; e Davi matou deles os homens de setecentos carros, e quarenta mil homens de cavalaria; e feriu a Sobaque, general do exército, de sorte que ele morreu ali.' },
      { v: 19, en: 'When all the kings who were servants to Hadadezer saw that they were defeated before Israel, they made peace with Israel, and served them. So the Syrians were afraid to help the children of Ammon any more.', pt: 'Vendo, pois, todos os reis, servos de Hadadézer, que estavam derrotados diante de Israel, fizeram paz com Israel, e o serviram. E os sírios não ousaram mais socorrer aos amonitas.' },
    ],
    11: [
      { v: 1, en: 'At the return of the year, at the time when kings go out, David sent Joab, and his servants with him, and all Israel; and they destroyed the children of Ammon, and besieged Rabbah. But David stayed at Jerusalem.', pt: 'Tendo decorrido um ano, no tempo em que os reis saem à guerra, Davi enviou Joabe, e com ele os seus servos e todo o Israel; e eles destruíram os amonitas, e sitiaram a Rabá. Porém Davi ficou em Jerusalem.' },
      { v: 2, en: 'At evening, David arose from his bed and walked on the roof of the king’s house. From the roof, he saw a woman bathing, and the woman was very beautiful to look at.', pt: 'Ora, aconteceu que, numa tarde, Davi se levantou do seu leito e se pôs a passear no terraço da casa real; e do terraço viu uma mulher que se estava lavando; e era esta mulher mui formosa à vista.' },
      { v: 3, en: 'David sent and inquired after the woman. One said, “Isn’t this Bathsheba, the daughter of Eliam, Uriah the Hittite’s wife?”', pt: 'Tendo Davi enviado a indagar a respeito daquela mulher, disseram-lhe: Porventura não é Bate-Seba, filha de Eliã, mulher de Urias, o heteu?' },
      { v: 4, en: 'David sent messengers, and took her; and she came in to him, and he lay with her (for she was purified from her uncleanness); and she returned to her house.', pt: 'Então Davi mandou mensageiros para trazê-la; e ela veio a ele, e ele se deitou com ela (pois já estava purificada da sua imundícia); depois ela voltou para sua casa.' },
      { v: 5, en: 'The woman conceived; and she sent and told David, and said, “I am with child.”', pt: 'A mulher concebeu; e mandou dizer a Davi: Estou grávida.' },
      { v: 6, en: 'David sent to Joab, “Send me Uriah the Hittite.” Joab sent Uriah to David.', pt: 'Então Davi mandou dizer a Joabe: Envia-me Urias, o heteu. E Joabe o enviou a Davi.' },
      { v: 7, en: 'When Uriah had come to him, David asked him how Joab did, and how the people fared, and how the war prospered.', pt: 'Vindo, pois, Urias a Davi, este lhe perguntou como passava Joabe, e como estava o povo, e como ia a guerra.' },
      { v: 8, en: 'David said to Uriah, “Go down to your house and wash your feet.” Uriah departed out of the king’s house, and a gift from the king was sent after him.', pt: 'Depois disse Davi a Urias: Desce a tua casa, e lava os teus pés. E, saindo Urias da casa real, logo foi mandado após ele um presente do rei.' },
      { v: 9, en: 'But Uriah slept at the door of the king’s house with all the servants of his lord, and didn’t go down to his house.', pt: 'Mas Urias dormiu à porta da casa real, com todos os servos do seu senhor, e não desceu a sua casa.' },
      { v: 10, en: 'When they had told David, saying, “Uriah didn’t go down to his house,” David said to Uriah, “Haven’t you come from a journey? Why didn’t you go down to your house?”', pt: 'E o contaram a Davi, dizendo: Urias não desceu a sua casa. Então perguntou Davi a Urias: Não vens tu duma jornada? por que não desceste a tua casa?' },
      { v: 11, en: 'Uriah said to David, “The ark, Israel, and Judah, are staying in tents; and my lord Joab and the servants of my lord, are encamped in the open field. Shall I then go into my house to eat and to drink, and to lie with my wife? As you live, and as your soul lives, I will not do this thing!”', pt: 'Respondeu Urias a Davi: A arca, e Israel, e Judá estão em tendas; e Joabe, meu senhor, e os servos de meu senhor estão acampados ao relento; e entrarei eu na minha casa, para comer e beber, e para me deitar com minha mulher? Como vives tu, e como vive a tua alma, não farei tal coisa.' },
      { v: 12, en: 'David said to Uriah, “Stay here today also, and tomorrow I will let you depart.” So Uriah stayed in Jerusalem that day, and the next day.', pt: 'Então disse Davi a Urias: Fica ainda hoje aqui, e amanhã te despedirei. Urias, pois, ficou em Jerusalém aquele dia e o seguinte.' },
      { v: 13, en: 'When David had called him, he ate and drink before him; and he made him drunk. At evening, he went out to lie on his bed with the servants of his lord, but didn’t go down to his house.', pt: 'E Davi o convidou a comer e a beber na sua presença, e o embebedou; e à tarde saiu Urias a deitar-se na sua cama com os servos de seu senhor, porém não desceu a sua casa.' },
      { v: 14, en: 'In the morning, David wrote a letter to Joab, and sent it by the hand of Uriah.', pt: 'Pela manhã Davi escreveu uma carta a Joabe, e mandou-lha por mão de Urias.' },
      { v: 15, en: 'He wrote in the letter, saying, “Send Uriah to the forefront of the hottest battle, and retreat from him, that he may be struck, and die.”', pt: 'Escreveu na carta: Ponde Urias na frente onde for mais renhida a peleja, e retirai-vos dele, para que seja ferido e morra.' },
      { v: 16, en: 'When Joab kept watch on the city, he assigned Uriah to the place where he knew that valiant men were.', pt: 'Enquanto Joabe sitiava a cidade, pôs Urias no lugar onde sabia que havia homens valentes.' },
      { v: 17, en: 'The men of the city went out, and fought with Joab. Some of the people fell, even of David’s servants; and Uriah the Hittite died also.', pt: 'Quando os homens da cidade saíram e pelejaram contra Joabe, caíram alguns do povo, isto é, dos servos de Davi; morreu também Urias, o heteu.' },
      { v: 18, en: 'Then Joab sent and told David all the things concerning the war;', pt: 'Então Joabe mandou dizer a Davi tudo o que sucedera na peleja;' },
      { v: 19, en: 'and he commanded the messenger, saying, “When you have finished telling all the things concerning the war to the king,', pt: 'e deu ordem ao mensageiro, dizendo: Quando tiveres acabado de contar ao rei tudo o que sucedeu nesta peleja,' },
      { v: 20, en: 'it shall be that, if the king’s wrath arise, and he asks you, ‘Why did you go so near to the city to fight? Didn’t you know that they would shoot from the wall?', pt: 'caso o rei se encolerize, e te diga: Por que vos chegastes tão perto da cidade a pelejar. Não sabíeis vós que haviam de atirar do muro?' },
      { v: 21, en: 'Who struck Abimelech the son of Jerubbesheth? Didn’t a woman cast an upper millstone on him from the wall, so that he died at Thebez? Why did you go so near the wall?’ then you shall say, ‘Your servant Uriah the Hittite is also dead.’”', pt: 'Quem matou a Abimeleque, filho de Jerubesete? Não foi uma mulher que lançou sobre ele, do alto do muro, a pedra superior dum moinho, de modo que morreu em Tebez? Por que chegastes tão perto do muro? Então dirás: Também morreu teu servo Urias, o heteu.' },
      { v: 22, en: 'So the messenger went, and came and showed David all that Joab had sent him for.', pt: 'Partiu, pois, o mensageiro e, tendo chegado, referiu a Davi tudo o que Joabe lhe ordenara.' },
      { v: 23, en: 'The messenger said to David, “The men prevailed against us, and came out to us into the field, and we were on them even to the entrance of the gate.', pt: 'Disse o mensageiro a Davi: Os homens ganharam uma vantagem sobre nós, e sairam contra nos ao campo; porém nos os repelimos até a entrada da porta.' },
      { v: 24, en: 'The shooters shot at your servants from off the wall; and some of the king’s servants are dead, and your servant Uriah the Hittite is also dead.”', pt: 'Então os flecheiros atiraram contra os teus servos desde o alto do muro, e morreram alguns servos do rei; e também morreu o teu servo Urias, o heteu.' },
      { v: 25, en: 'Then David said to the messenger, “Tell Joab, ‘Don’t let this thing displease you, for the sword devours one as well as another. Make your battle stronger against the city, and overthrow it.’ Encourage him.”', pt: 'Disse Davi ao mensageiro: Assim dirás a Joabe: Não te preocupes com isso, pois a espada tanto devora este como aquele; aperta a tua peleja contra a cidade, e a derrota. Encoraja-o tu assim.' },
      { v: 26, en: 'When Uriah’s wife heard that Uriah her husband was dead, she mourned for her husband.', pt: 'Ouvindo, pois, a mulher de Urias que seu marido era morto, o chorou.' },
      { v: 27, en: 'When the mourning was past, David sent and took her home to his house, and she became his wife, and bore him a son. But the thing that David had done displeased Yahweh.', pt: 'E, passado o tempo do luto, mandou Davi recolhê-la a sua casa: e ela lhe foi por mulher, e lhe deu um filho. Mas isto que Davi fez desagradou ao Senhor.' },
    ],
    12: [
      { v: 1, en: 'Yahweh sent Nathan to David. He came to him, and said to him, “There were two men in one city; the one rich, and the other poor.', pt: 'O Senhor, pois, enviou Natã a Davi. E, entrando ele a ter com Davi, disse-lhe: Havia numa cidade dois homens, um rico e outro pobre.' },
      { v: 2, en: 'The rich man had very many flocks and herds,', pt: 'O rico tinha rebanhos e manadas em grande número;' },
      { v: 3, en: 'but the poor man had nothing, except one little ewe lamb, which he had bought and raised. It grew up together with him, and with his children. It ate of his own food, drank of his own cup, and lay in his bosom, and was like a daughter to him.', pt: 'mas o pobre não tinha coisa alguma, senão uma pequena cordeira que comprara e criara; ela crescera em companhia dele e de seus filhos; do seu bocado comia, do seu copo bebia, e dormia em seu regaço; e ele a tinha como filha.' },
      { v: 4, en: 'A traveler came to the rich man, and he spared to take of his own flock and of his own herd, to prepare for the wayfaring man who had come to him, but took the poor man’s lamb, and prepared it for the man who had come to him.”', pt: 'Chegou um viajante à casa do rico; e este, não querendo tomar das suas ovelhas e do seu gado para guisar para o viajante que viera a ele, tomou a cordeira do pobre e a preparou para o seu hóspede.' },
      { v: 5, en: 'David’s anger burned hot against the man, and he said to Nathan, “As Yahweh lives, the man who has done this deserves to die!', pt: 'Então a ira de Davi se acendeu em grande maneira contra aquele homem; e disse a Natã: Vive o Senhor, que digno de morte é o homem que fez isso.' },
      { v: 6, en: 'He must restore the lamb fourfold, because he did this thing, and because he had no pity!”', pt: 'Pela cordeira restituirá o quádruplo, porque fez tal coisa, e não teve compaixão.' },
      { v: 7, en: 'Nathan said to David, “You are the man. This is what Yahweh, the God of Israel, says: ‘I anointed you king over Israel, and I delivered you out of the hand of Saul.', pt: 'Então disse Natã a Davi: Esse homem és tu! Assim diz o Senhor Deus de Israel: Eu te ungi rei sobre Israel, livrei-te da mão de Saul,' },
      { v: 8, en: 'I gave you your master’s house, and your master’s wives into your bosom, and gave you the house of Israel and of Judah; and if that would have been too little, I would have added to you many more such things.', pt: 'e te dei a casa de teu senhor, e as mulheres de teu senhor em teu seio; também te dei a casa de Israel e de Judá. E se isso fosse pouco, te acrescentaria outro tanto.' },
      { v: 9, en: 'Why have you despised Yahweh’s word, to do that which is evil in his sight? You have struck Uriah the Hittite with the sword, and have taken his wife to be your wife, and have slain him with the sword of the children of Ammon.', pt: 'Por que desprezaste a palavra do Senhor, fazendo o mal diante de seus olhos? A Urias, o heteu, mataste à espada, e a sua mulher tomaste para ser tua mulher; sim, a ele mataste com a espada dos amonitas.' },
      { v: 10, en: 'Now therefore the sword will never depart from your house, because you have despised me, and have taken Uriah the Hittite’s wife to be your wife.’', pt: 'Agora, pois, a espada jamais se apartará da tua casa, porquanto me desprezaste, e tomaste a mulher de Urias, o heteu, para ser tua mulher.' },
      { v: 11, en: '“This is what Yahweh says: ‘Behold, I will raise up evil against you out of your own house; and I will take your wives before your eyes, and give them to your neighbor, and he will lie with your wives in the sight of this sun.', pt: 'Assim diz o Senhor: Eis que suscitarei da tua própria casa o mal sobre ti, e tomarei tuas mulheres perante os teus olhos, e as darei a teu próximo, o qual se deitará com tuas mulheres à luz deste sol.' },
      { v: 12, en: 'For you did this secretly, but I will do this thing before all Israel, and before the sun.’”', pt: 'Pois tu o fizeste em oculto; mas eu farei este negócio perante todo o Israel e à luz do sol.' },
      { v: 13, en: 'David said to Nathan, “I have sinned against Yahweh.” Nathan said to David, “Yahweh also has put away your sin. You will not die.', pt: 'Então disse Davi a Natã: Pequei contra o Senhor. Tornou Natã a Davi: Também o Senhor perdoou o teu pecado; não morreras.' },
      { v: 14, en: 'However, because by this deed you have given great occasion to Yahweh’s enemies to blaspheme, the child also who is born to you will surely die.”', pt: 'Todavia, porquanto com este feito deste lugar a que os inimigos do Senhor blasfemem, o filho que te nasceu certamente morrerá.' },
      { v: 15, en: 'Nathan departed to his house. Yahweh struck the child that Uriah’s wife bore to David, and it was very sick.', pt: 'Então Natã foi para sua casa. Depois o Senhor feriu a criança que a mulher de Urias dera a Davi, de sorte que adoeceu gravemente.' },
      { v: 16, en: 'David therefore begged God for the child; and David fasted, and went in, and lay all night on the ground.', pt: 'Davi, pois, buscou a Deus pela criança, e observou rigoroso jejum e, recolhendo-se, passava a noite toda prostrado sobre a terra.' },
      { v: 17, en: 'The elders of his house arose beside him, to raise him up from the earth: but he would not, and he didn’t eat bread with them.', pt: 'Então os anciãos da sua casa se puseram ao lado dele para o fazerem levantar-se da terra; porém ele não quis, nem comeu com eles.' },
      { v: 18, en: 'On the seventh day, the child died. David’s servants were afraid to tell him that the child was dead, for they said, “Behold, while the child was yet alive, we spoke to him, and he didn’t listen to our voice. How will he then harm himself, if we tell him that the child is dead?”', pt: 'Ao sétimo dia a criança morreu; e temiam os servos de Davi dizer-lhe que a criança tinha morrido; pois diziam: Eis que, sendo a criança ainda viva, lhe falávamos, porém ele não dava ouvidos à nossa voz; como, pois, lhe diremos que a criança morreu? Poderá cometer um desatino.' },
      { v: 19, en: 'But when David saw that his servants were whispering together, David perceived that the child was dead; and David said to his servants, “Is the child dead?” They said, “He is dead.”', pt: 'Davi, porém, percebeu que seus servos cochichavam entre si, e entendeu que a criança havia morrido; pelo que perguntou a seus servos: Morreu a criança? E eles responderam: Morreu.' },
      { v: 20, en: 'Then David arose from the earth, and washed, and anointed himself, and changed his clothing; and he came into Yahweh’s house, and worshiped. Then he came to his own house; and when he requested, they set bread before him, and he ate.', pt: 'Então Davi se levantou da terra, lavou-se, ungiu-se, e mudou de vestes; e, entrando na casa do Senhor, adorou. Depois veio a sua casa, e pediu o que comer; e lho deram, e ele comeu.' },
      { v: 21, en: 'Then his servants said to him, “What is this that you have done? You fasted and wept for the child while he was alive, but when the child was dead, you rose up and ate bread.”', pt: 'Então os seus servos lhe disseram: Que é isso que fizeste? pela criança viva jejuaste e choraste; porém depois que a criança morreu te levantaste e comeste.' },
      { v: 22, en: 'He said, “While the child was yet alive, I fasted and wept; for I said, ‘Who knows whether Yahweh will not be gracious to me, that the child may live?’', pt: 'Respondeu ele: Quando a criança ainda vivia, jejuei e chorei, pois dizia: Quem sabe se o Senhor não se compadecerá de mim, de modo que viva a criança?' },
      { v: 23, en: 'But now he is dead, why should I fast? Can I bring him back again? I will go to him, but he will not return to me.”', pt: 'Todavia, agora que é morta, por que ainda jejuaria eu? Poderei eu fazê-la voltar? Eu irei para ela, porém ela não voltará para mim.' },
      { v: 24, en: 'David comforted Bathsheba his wife, and went in to her, and lay with her. She bore a son, and he called his name Solomon. Yahweh loved him;', pt: 'Então consolou Davi a Bate-Seba, sua mulher, e entrou, e se deitou com ela. E teve ela um filho, e Davi lhe deu o nome de Salomão. E o Senhor o amou;' },
      { v: 25, en: 'and he sent by the hand of Nathan the prophet, and he named him Jedidiah, for Yahweh’s sake.', pt: 'e mandou, por intermédio do profeta Natã, dar-lhe o nome de Jedidias, por amor do Senhor.' },
      { v: 26, en: 'Now Joab fought against Rabbah of the children of Ammon, and took the royal city.', pt: 'Ora, pelejou Joabe contra Rabá, dos amonitas, e tomou a cidade real.' },
      { v: 27, en: 'Joab sent messengers to David, and said, “I have fought against Rabbah. Yes, I have taken the city of waters.', pt: 'Então mandou Joabe mensageiros a Davi, e disse: Pelejei contra Rabá, e já tomei a cidade das águas.' },
      { v: 28, en: 'Now therefore gather the rest of the people together, and encamp against the city, and take it; lest I take the city, and it be called by my name.”', pt: 'Ajunta, pois, agora o resto do povo, acampa contra a cidade e toma-a, para que eu não a tome e seja o meu nome aclamado sobre ela.' },
      { v: 29, en: 'David gathered all the people together, and went to Rabbah, and fought against it, and took it.', pt: 'Então Davi ajuntou todo o povo, e marchou para Rabá; pelejou contra ela, e a tomou.' },
      { v: 30, en: 'He took the crown of their king from off his head; and its weight was a talent of gold, and in it were precious stones; and it was set on David’s head. He brought a great quantity of plunder out of the city.', pt: 'Também tirou a coroa da cabeça do seu rei; e o peso dela era de um talento de ouro e havia nela uma pedra preciosa; e foi posta sobre a cabeça de Davi, que levou da cidade mui grande despojo.' },
      { v: 31, en: 'He brought out the people who were in it, and put them under saws, under iron picks, under axes of iron, and made them pass through the brick kiln; and he did so to all the cities of the children of Ammon. Then David and all the people returned to Jerusalem.', pt: 'E, trazendo os seus habitantes, os pôs a trabalhar com serras, trilhos de ferro, machados de ferro, e em fornos de tijolos; e assim fez a todas as cidades dos amonitas. Depois voltou Davi e todo o povo para Jerusalém.' },
    ],
    13: [
      { v: 1, en: 'After this, Absalom the son of David had a beautiful sister, whose name was Tamar; and Amnon the son of David loved her.', pt: 'Ora, Absalão, filho de Davi, tinha uma irmã formosa, cujo nome era Tamar; e sucedeu depois de algum tempo que Amnom, filho de Davi enamorou-se dela.' },
      { v: 2, en: 'Amnon was so troubled that he became sick because of his sister Tamar; for she was a virgin; and it seemed hard to Amnon to do anything to her.', pt: 'E angustiou-se Amnom, até adoecer, por amar, sua irmã; pois era virgem, e parecia impossível a Amnom fazer coisa alguma com ela.' },
      { v: 3, en: 'But Amnon had a friend, whose name was Jonadab, the son of Shimeah, David’s brother; and Jonadab was a very subtle man.', pt: 'Tinha, porém, Amnom um amigo, cujo nome era Jonadabe, filho de Siméia, irmão de Davi; e era Jonadabe homem mui sagaz.' },
      { v: 4, en: 'He said to him, “Why, son of the king, are you so sad from day to day? Won’t you tell me?” Amnon said to him, “I love Tamar, my brother Absalom’s sister.”', pt: 'Este lhe perguntou: Por que tu de dia para dia tanto emagreces, ó filho do rei? não mo dirás a mim? Então lhe respondeu Amnom: Amo a Tamar, irmã de Absalão, meu irmao.' },
      { v: 5, en: 'Jonadab said to him, “Lay down on your bed, and pretend to be sick. When your father comes to see you, tell him, ‘Please let my sister Tamar come and give me bread to eat, and prepare the food in my sight, that I may see it, and eat it from her hand.’”', pt: 'Tornou-lhe Jonadabe: Deita-te na tua cama, e finge-te doente; e quando teu pai te vier visitar, dize-lhe: Peço-te que minha irmã Tamar venha dar-me de comer, preparando a comida diante dos meus olhos, para que eu veja e coma da sua mão.' },
      { v: 6, en: 'So Amnon lay down and faked being sick. When the king came to see him, Amnon said to the king, “Please let my sister Tamar come, and make me a couple of cakes in my sight, that I may eat from her hand.”', pt: 'Deitou-se, pois, Amnom, e fingiu-se doente. Vindo o rei visitá-lo, disse-lhe Amnom: Peço-te que minha irmã Tamar venha e prepare dois bolos diante dos meus olhos, para que eu coma da sua mão.' },
      { v: 7, en: 'Then David sent home to Tamar, saying, “Go now to your brother Amnon’s house, and prepare food for him.”', pt: 'Mandou, então, Davi a casa, a dizer a Tamar: Vai a casa de Amnom, teu irmão, e faze-lhe alguma comida.' },
      { v: 8, en: 'So Tamar went to her brother Amnon’s house; and he was lying down. She took dough, and kneaded it, made cakes in his sight, and baked the cakes.', pt: 'Foi, pois, Tamar a casa de Amnom, seu irmão; e ele estava deitado. Ela tomou massa e, amassando-a, fez bolos e os cozeu diante dos seus olhos.' },
      { v: 9, en: 'She took the pan, and poured them out before him; but he refused to eat. Amnon said, “Have all men leave me.” Then every man went out from him.', pt: 'E tomou a panela, e os tirou diante dele; porém ele recusou comer. E disse Amnom: Fazei retirar a todos da minha presença. E todos se retiraram dele.' },
      { v: 10, en: 'Amnon said to Tamar, “Bring the food into the room, that I may eat from your hand.” Tamar took the cakes which she had made, and brought them into the room to Amnon her brother.', pt: 'Então disse Amnom a Tamar: Traze a comida a câmara, para que eu coma da tua mão. E Tamar, tomando os bolos que fizera, levou-os à câmara, ao seu irmão Amnom.' },
      { v: 11, en: 'When she had brought them near to him to eat, he took hold of her, and said to her, “Come, lie with me, my sister!”', pt: 'Quando lhos chegou, para que ele comesse, Amnom pegou dela, e disse-lhe: Vem, deita-te comigo, minha irmã.' },
      { v: 12, en: 'She answered him, “No, my brother, do not force me! For no such thing ought to be done in Israel. Don’t you do this folly.', pt: 'Ela, porém, lhe respondeu: Não, meu irmão, não me forces, porque não se faz assim em Israel; não faças tal loucura.' },
      { v: 13, en: 'As for me, where would I carry my shame? And as for you, you will be as one of the fools in Israel. Now therefore, please speak to the king; for he will not withhold me from you.”', pt: 'Quanto a mim, para onde levaria o meu opróbrio? E tu passarias por um dos insensatos em Israel. Rogo-te, pois, que fales ao rei, porque ele não me negará a ti.' },
      { v: 14, en: 'However he would not listen to her voice; but being stronger than she, he forced her, and lay with her.', pt: 'Todavia ele não quis dar ouvidos à sua voz; antes, sendo mais forte do que ela, forçou-a e se deitou com ela.' },
      { v: 15, en: 'Then Amnon hated her with exceedingly great hatred; for the hatred with which he hated her was greater than the love with which he had loved her. Amnon said to her, “Arise, be gone!”', pt: 'Depois sentiu Amnom grande aversão por ela, pois maior era a aversão que se sentiu por ela do que o amor que lhe tivera. E disse-lhe Amnom: Levanta-te, e vai-te.' },
      { v: 16, en: 'She said to him, “Not so, because this great wrong in sending me away is worse than the other that you did to me!” But he would not listen to her.', pt: 'Então ela lhe respondeu: Não há razão de me despedires; maior seria este mal do que o outro já me tens feito. Porém ele não lhe quis dar ouvidos,' },
      { v: 17, en: 'Then he called his servant who ministered to him, and said, “Now put this woman out from me, and bolt the door after her.”', pt: 'mas, chamando o moço que o servia, disse-lhe: Deita fora a esta mulher, e fecha a porta após ela.' },
      { v: 18, en: 'She had a garment of various colors on her; for the king’s daughters who were virgins dressed in such robes. Then his servant brought her out and bolted the door after her.', pt: 'Ora, trazia ela uma túnica talar; porque assim se vestiam as filhas virgens dos reis. Então o criado dele a deitou fora, e fechou a porta após ela.' },
      { v: 19, en: 'Tamar put ashes on her head, and tore her garment of various colors that was on her; and she laid her hand on her head, and went her way, crying aloud as she went.', pt: 'Pelo que Tamar, lançando cinza sobre a cabeça, e rasgando a túnica talar que trazia, pôs as mãos sobre a cabeça, e se foi andando e clamando.' },
      { v: 20, en: 'Absalom her brother said to her, “Has Amnon your brother been with you? But now hold your peace, my sister. He is your brother. Don’t take this thing to heart.” So Tamar remained desolate in her brother Absalom’s house.', pt: 'Mas Absalão, seu irmão, lhe perguntou: Esteve Amnom, teu irmão, contigo? Ora pois, minha irmã, cala-te; é teu irmão. Não se angustie o seu coração por isto. Assim ficou Tamar, desolada, em casa de Absalão, seu irmão.' },
      { v: 21, en: 'But when king David heard of all these things, he was very angry.', pt: 'Quando o rei Davi ouviu todas estas coisas, muito se lhe acendeu a ira.' },
      { v: 22, en: 'Absalom spoke to Amnon neither good nor bad; for Absalom hated Amnon, because he had forced his sister Tamar.', pt: 'Absalão, porém, não falou com Amnom, nem mal nem bem, porque odiava a Amnom por ter ele forçado a Tamar, sua irmã.' },
      { v: 23, en: 'After two full years, Absalom had sheep shearers in Baal Hazor, which is beside Ephraim: and Absalom invited all the king’s sons.', pt: 'Decorridos dois anos inteiros, tendo Absalão tosquiadores em Baal-Hazor, que está junto a Efraim, convidou todos os filhos do rei.' },
      { v: 24, en: 'Absalom came to the king, and said, “See now, your servant has sheep shearers. Please let the king and his servants go with your servant.”', pt: 'Foi, pois, Absalão ter com o rei, e disse: Eis que agora o teu servo faz a tosquia. Peço que o rei e os seus servos venham com o teu servo.' },
      { v: 25, en: 'The king said to Absalom, “No, my son, let us not all go, lest we be burdensome to you.” He pressed him; however he would not go, but blessed him.', pt: 'O rei, porém, respondeu a Absalão: Não, meu filho, não vamos todos, para não te sermos pesados. Absalão instou com ele; todavia ele não quis ir, mas deu-lhe a sua bençao.' },
      { v: 26, en: 'Then Absalom said, “If not, please let my brother Amnon go with us.” The king said to him, “Why should he go with you?”', pt: 'Disse-lhe Absalão: Ao menos, deixa ir conosco Amnom, meu irmão. O rei, porém, lhe perguntou: Para que iria ele contigo?' },
      { v: 27, en: 'But Absalom pressed him, and he let Amnon and all the king’s sons go with him.', pt: 'Mas como Absalão instasse com o rei, este deixou ir com ele Amnom, e os demais filhos do rei.' },
      { v: 28, en: 'Absalom commanded his servants, saying, “Mark now, when Amnon’s heart is merry with wine; and when I tell you, ‘Strike Amnon,’ then kill him. Don’t be afraid. Haven’t I commanded you? Be courageous, and be valiant!”', pt: 'Ora, Absalão deu ordem aos seus servos, dizendo: Tomai sentido; quando o coração de Amnom estiver alegre do vinho, e eu vos disser: Feri a Amnom; então matai-o. Não tenhais medo; não sou eu quem vo-lo ordenou? Esforçai-vos, e sede valentes.' },
      { v: 29, en: 'The servants of Absalom did to Amnon as Absalom had commanded. Then all the king’s sons arose, and every man got up on his mule, and fled.', pt: 'E os servos de Absalão fizeram a Amnom como Absalão lhes havia ordenado. Então todos os filhos do rei se levantaram e, montando cada um no seu mulo, fugiram.' },
      { v: 30, en: 'While they were on the way, the news came to David, saying, “Absalom has slain all the king’s sons, and there is not one of them left!”', pt: 'Enquanto eles ainda estavam em caminho, chegou a Davi um rumor, segundo o qual se dizia: Absalão matou todos os filhos do rei; nenhum deles ficou.' },
      { v: 31, en: 'Then the king arose, and tore his garments, and lay on the earth; and all his servants stood by with their clothes torn.', pt: 'Então o rei se levantou e, rasgando as suas vestes, lançou-se por terra; da mesma maneira todos os seus servos que lhe assistiam rasgaram as suas vestes.' },
      { v: 32, en: 'Jonadab, the son of Shimeah, David’s brother, answered, “Don’t let my lord suppose that they have killed all the young men the king’s sons; for Amnon only is dead; for by the appointment of Absalom this has been determined from the day that he forced his sister Tamar.', pt: 'Mas Jonadabe, filho de Siméia, irmão de Davi, disse-lhe: Não presuma o meu senhor que mataram todos os mancebos filhos do rei, porque só morreu Amnom; porque assim o tinha resolvido fazer Absalão, desde o dia em que ele forçou a Tamar, sua irmã.' },
      { v: 33, en: 'Now therefore don’t let my lord the king take the thing to his heart, to think that all the king’s sons are dead; for only Amnon is dead.”', pt: 'Não se lhe meta, pois, agora no coração ao rei meu senhor o pensar que morreram todos os filhos do rei; porque só morreu Amnom.' },
      { v: 34, en: 'But Absalom fled. The young man who kept the watch lifted up his eyes, and looked, and behold, many people were coming by way of the hillside behind him.', pt: 'Absalão, porém, fugiu. E o mancebo que estava de guarda, levantando os olhos, orou, e eis que vinha muito povo pelo caminho por detrás dele, ao lado do monte.' },
      { v: 35, en: 'Jonadab said to the king, “Behold, the king’s sons are coming! It is as your servant said.”', pt: 'Então disse Jonadabe ao rei: Eis aí vêm os filhos do rei; conforme a palavra de teu servo, assim sucedeu.' },
      { v: 36, en: 'As soon as he had finished speaking, behold, the king’s sons came, and lifted up their voice, and wept. The king also and all his servants wept bitterly.', pt: 'Acabando ele de falar, chegaram os filhos do rei e, levantando a sua voz, choraram; e também o rei e todos os seus servos choraram amargamente.' },
      { v: 37, en: 'But Absalom fled, and went to Talmai the son of Ammihur, king of Geshur. David mourned for his son every day.', pt: 'Absalão, porém, fugiu, e foi ter com Talmai, filho de Amiur, rei de Gesur. E Davi pranteava a seu filho todos os dias.' },
      { v: 38, en: 'So Absalom fled, and went to Geshur, and was there three years.', pt: 'Tendo Absalão fugido para Gesur, esteve ali três anos.' },
      { v: 39, en: 'King David longed to go out to Absalom; for he was comforted concerning Amnon, since he was dead.', pt: 'Então o rei Davi sentiu saudades de Absalão, pois já se tinha consolado acerca da morte de Amnom.' },
    ],
    14: [
      { v: 1, en: 'Now Joab the son of Zeruiah perceived that the king’s heart was toward Absalom.', pt: 'Percebendo Joabe, filho de Zeruia, que o coração do rei estava inclinado para Absalão,' },
      { v: 2, en: 'Joab sent to Tekoa, and brought a wise woman from there, and said to her, “Please act like a mourner, and put on mourning clothing, please, and don’t anoint yourself with oil, but be as a woman who has mourned a long time for the dead.', pt: 'mandou a Tecoa trazer de lá uma mulher sagaz, e disse-lhe: Ora, finge que estás de nojo; põe vestidos de luto, não te unjas com óleo, e faze-te como uma mulher que há muitos dias chora algum morto;' },
      { v: 3, en: 'Go in to the king, and speak like this to him.” So Joab put the words in her mouth.', pt: 'vai ter com o rei, e fala-lhe desta maneira. Então Joabe lhe pôs as palavras na boca.' },
      { v: 4, en: 'When the woman of Tekoa spoke to the king, she fell on her face to the ground, showed respect, and said, “Help, O king!”', pt: 'A mulher tecoíta, pois, indo ter com o rei e prostrando-se com o rosto em terra, fez-lhe uma reverência e disse: Salva-me, o rei.' },
      { v: 5, en: 'The king said to her, “What ails you?” She answered, “Truly I am a widow, and my husband is dead.', pt: 'Ao que lhe perguntou o rei: Que tens? Respondeu ela: Na verdade eu sou viúva; morreu meu marido.' },
      { v: 6, en: 'Your servant had two sons, and they both fought together in the field, and there was no one to part them, but the one struck the other, and killed him.', pt: 'Tinha a tua serva dois filhos, os quais tiveram uma briga no campo e, não havendo quem os apartasse, um feriu ao outro, e o matou.' },
      { v: 7, en: 'Behold, the whole family has risen against your servant, and they say, ‘Deliver him who struck his brother, that we may kill him for the life of his brother whom he killed, and so destroy the heir also.’ Thus they would quench my coal which is left, and would leave to my husband neither name nor remainder on the surface of the earth.”', pt: 'E eis que toda a parentela se levantou contra a tua serva, dizendo: Dá-nos aquele que matou a seu irmão, para que o matemos pela vida de seu irmão, a quem ele matou, de modo que exterminemos também o herdeiro. Assim apagarão a brasa que me ficou, de sorte a não deixarem a meu marido nem nome, nem remanescente sobre a terra.' },
      { v: 8, en: 'The king said to the woman, “Go to your house, and I will give a command concerning you.”', pt: 'Então disse o rei à mulher: Vai para tua casa, e eu darei ordem a teu respeito.' },
      { v: 9, en: 'The woman of Tekoa said to the king, “My lord, O king, may the iniquity be on me, and on my father’s house; and may the king and his throne be guiltless.”', pt: 'Respondeu a mulher tecoíta ao rei: A iniqüidade, ó rei meu senhor, venha sobre mim e sobre a casa de meu pai; e fique inculpável o rei e o seu trono.' },
      { v: 10, en: 'The king said, “Whoever says anything to you, bring him to me, and he will not bother you any more.”', pt: 'Tornou o rei: Quem falar contra ti, traze-mo a mim, e nunca mais te tocará.' },
      { v: 11, en: 'Then she said, “Please let the king remember Yahweh your God, that the avenger of blood destroy not any more, lest they destroy my son.” He said, “As Yahweh lives, not one hair of your son shall fall to the earth.”', pt: 'Disse ela: Ora, lembre-se o rei do Senhor seu Deus, para que o vingador do sangue não prossiga na destruição, e não extermine a meu filho. Então disse ele: Vive o Senhor, que não há de cair no chão nem um cabelo de teu filho.' },
      { v: 12, en: 'Then the woman said, “Please let your servant speak a word to my lord the king.” He said, “Say on.”', pt: 'Então disse a mulher: Permite que a tua serva fale uma palavra ao rei meu senhor. Respondeu ele: Fala.' },
      { v: 13, en: 'The woman said, “Why then have you devised such a thing against the people of God? For in speaking this word the king is as one who is guilty, in that the king does not bring home again his banished one.', pt: 'Ao que disse a mulher: Por que, pois, pensas tu tal coisa contra o povo de Deus? Pois, falando o rei esta palavra, fica como culpado, visto que o rei não torna a trazer o seu desterrado.' },
      { v: 14, en: 'For we must die, and are like water spilled on the ground, which can’t be gathered up again; neither does God take away life, but devises means, that he who is banished not be an outcast from him.', pt: 'Porque certamente morreremos, e serereos como águas derramadas na terra, que não se podem ajuntar mais; Deus, todavia, não tira a vida, mas cogita meios para que não fique banido dele o seu desterrado.' },
      { v: 15, en: 'Now therefore seeing that I have come to speak this word to my lord the king, it is because the people have made me afraid. Your servant said, ‘I will now speak to the king; it may be that the king will perform the request of his servant.’', pt: 'E se eu agora vim falar esta palavra ao rei meu senhor, e porque o povo me atemorizou; pelo que dizia a tua serva: Falarei, pois, ao rei; porventura fará o rei segundo a palavra da sua serva.' },
      { v: 16, en: 'For the king will hear, to deliver his servant out of the hand of the man who would destroy me and my son together out of the inheritance of God.', pt: 'Porque o rei ouvirá, para livrar a sua serva da mão do homem que intenta exterminar da herança de Deus tanto a mim como a meu filho.' },
      { v: 17, en: 'Then your servant said, ‘Please let the word of my lord the king bring rest; for as an angel of God, so is my lord the king to discern good and bad. May Yahweh, your God, be with you.’”', pt: 'Dizia mais a tua serva: Que a palavra do rei meu senhor me dê um descanso; porque como o anjo de Deus é o rei, meu senhor, para discernir o bem e o mal; e o Senhor teu Deus seja contigo.' },
      { v: 18, en: 'Then the king answered the woman, “Please don’t hide anything from me that I ask you.” The woman said, “Let my lord the king now speak.”', pt: 'Então respondeu o rei à mulher: Peço-te que não me encubras o que eu te perguntar. Tornou a mulher: Fale agora o rei meu senhor.' },
      { v: 19, en: 'The king said, “Is the hand of Joab with you in all this?” The woman answered, “As your soul lives, my lord the king, no one can turn to the right hand or to the left from anything that my lord the king has spoken; for your servant Joab urged me, and he put all these words in the mouth of your servant;', pt: 'Perguntou, pois, o rei: Não é verdade que a mão de Joabe está contigo em tudo isso? Respondeu a mulher: Vive a tua alma, ó rei meu senhor, que ninguém se poderá desviar, nem para a direita nem para a esquerda, de tudo quanto diz o rei meu senhor; porque Joabe, teu servo, é quem me deu ordem, e foi ele que pôs na boca da tua serva todas estas palavras;' },
      { v: 20, en: 'to change the face of the matter has your servant Joab done this thing. My lord is wise, according to the wisdom of an angel of God, to know all things that are in the earth.”', pt: 'para mudar a feição do negócio é que Joabe, teu servo, fez isso. Sábio, porém, é meu senhor, conforme a sabedoria do anjo de Deus, para entender tudo o que há na terra.' },
      { v: 21, en: 'The king said to Joab, “Behold now, I have done this thing. Go therefore, and bring the young man Absalom back.”', pt: 'Então o rei disse a Joabe: Eis que faço o que pedes; vai, pois, e faze voltar o mancebo Absalão.' },
      { v: 22, en: 'Joab fell to the ground on his face, showed respect, and blessed the king. Joab said, “Today your servant knows that I have found favor in your sight, my lord, king, in that the king has performed the request of his servant.”', pt: 'Então Joabe se prostrou com o rosto em terra e, fazendo uma reverência, abençoou o rei; e disse Joabe: Hoje conhece o teu servo que achei graça aos teus olhos, ó rei meu senhor, porque o rei fez segundo a palavra do teu servo.' },
      { v: 23, en: 'So Joab arose and went to Geshur, and brought Absalom to Jerusalem.', pt: 'Levantou-se, pois, Joabe, foi a Gesue e trouxe Absalão para Jerusalém.' },
      { v: 24, en: 'The king said, “Let him return to his own house, but let him not see my face.” So Absalom returned to his own house, and didn’t see the king’s face.', pt: 'E disse o rei: Torne ele para sua casa, mas não venha à minha presença. Tornou, pois, Absalão para sua casa, e não foi à presença do rei.' },
      { v: 25, en: 'Now in all Israel there was no one to be so much praised as Absalom for his beauty. From the sole of his foot even to the crown of his head there was no defect in him.', pt: 'Não havia em todo o Israel homem tão admirável pela sua beleza como Absalão; desde a planta do pé até o alto da cabeça não havia nele defeito algum.' },
      { v: 26, en: 'When he cut the hair of his head (now it was at every year’s end that he cut it; because it was heavy on him, therefore he cut it); he weighed the hair of his head at two hundred shekels, after the king’s weight.', pt: 'E, quando ele cortava o cabelo, o que costumava fazer no fim de cada ano, porquanto lhe pesava muito, o peso do cabelo era de duzentos siclos, segundo o peso real.' },
      { v: 27, en: 'Three sons were born to Absalom, and one daughter, whose name was Tamar. She was a woman with a beautiful face.', pt: 'Nasceram a Absalão três filhos, e uma filha cujo nome era Tamar; e esta era mulher formosa à vista.' },
      { v: 28, en: 'Absalom lived two full years in Jerusalem, and he didn’t see the king’s face.', pt: 'Assim ficou Absalão dois anos inteiros em Jerusalém, sem ver a face do rei.' },
      { v: 29, en: 'Then Absalom sent for Joab, to send him to the king, but he would not come to him. Then he sent again a second time, but he would not come.', pt: 'Então Absalão mandou chamar Joabe, para o enviar ao rei; porém Joabe não quis vir a ele. Mandou chamá-lo segunda vez, mas ele não quis vir.' },
      { v: 30, en: 'Therefore he said to his servants, “Behold, Joab’s field is near mine, and he has barley there. Go and set it on fire.” So Absalom’s servants set the field on fire.', pt: 'Pelo que disse aos seus servos: Vede ali o campo de Joabe pegado ao meu, onde ele tem cevada; ide, e ponde-lhe fogo. E os servos de Absalão puseram fogo ao campo:' },
      { v: 31, en: 'Then Joab arose, and came to Absalom to his house, and said to him, “Why have your servants set my field on fire?”', pt: 'Então Joabe se levantou, e veio ter com Absalão, em casa, e lhe perguntou: Por que os teus servos puseram fogo ao meu campo.' },
      { v: 32, en: 'Absalom answered Joab, “Behold, I sent to you, saying, ‘Come here, that I may send you to the king, to say, “Why have I come from Geshur? It would be better for me to be there still. Now therefore let me see the king’s face, and if there is iniquity in me, let him kill me.”’”', pt: 'Respondeu Absalão a Joabe: Eis que enviei a ti, dizendo: Vem cá, para que te envie ao rei, a dizer-lhe: Para que vim de Gesur? Melhor me fora estar ainda lá. Agora, pois, veja eu a face do rei; e, se há em mim alguma culpa, que me mate.' },
      { v: 33, en: 'So Joab came to the king, and told him; and when he had called for Absalom, he came to the king, and bowed himself on his face to the ground before the king; and the king kissed Absalom.', pt: 'Foi, pois, Joabe à presença do rei, e lho disse. Então o rei chamou Absalão, e ele entrou à presença do rei, e se prostrou com o rosto em terra diante do rei; e o rei beijou Absalão.' },
    ],
    15: [
      { v: 1, en: 'After this, Absalom prepared a chariot and horses for himself, and fifty men to run before him.', pt: 'Aconteceu depois disso que Absalão adquiriu para si um carro e cavalos, e cinqüenta homens que corressem adiante dele.' },
      { v: 2, en: 'Absalom rose up early, and stood beside the way of the gate. When any man had a suit which should come to the king for judgment, then Absalom called to him, and said, “What city are you from?” He said, “Your servant is of one of the tribes of Israel.”', pt: 'E levantando-se Absalão cedo, parava ao lado do caminho da porta; e quando algum homem tinha uma demanda para, vir ao rei a juízo, Absalão o chamava a si e lhe dizia: De que cidade és tu? E, dizendo ele: De tal tribo de Israel é teu servo;' },
      { v: 3, en: 'Absalom said to him, “Behold, your matters are good and right; but there is no man deputized by the king to hear you.”', pt: 'Absalão lhe dizia: Olha, a tua causa é boa e reta, porém não há da parte do rei quem te ouça.' },
      { v: 4, en: 'Absalom said moreover, “Oh that I were made judge in the land, that every man who has any suit or cause might come to me, and I would do him justice!”', pt: 'Dizia mais Absalão: Ah, quem me dera ser constituído juiz na terra! para que viesse ter comigo todo homem que tivesse demanda ou questão, e eu lhe faria justiça.' },
      { v: 5, en: 'It was so, that when any man came near to bow down to him, he stretched out his hand, and took hold of him, and kissed him.', pt: 'Sucedia também que, quando alguém se chegava a ele para lhe fazer reverência, ele estendia a mão e, pegando nele o beijava.' },
      { v: 6, en: 'Absalom did this sort of thing to all Israel who came to the king for judgment. So Absalom stole the hearts of the men of Israel.', pt: 'Assim fazia Absalão a todo o Israel que vinha ao rei para juízo; desse modo Absalão furtava o coração dos homens de Israel.' },
      { v: 7, en: 'At the end of forty years, Absalom said to the king, “Please let me go and pay my vow, which I have vowed to Yahweh, in Hebron.', pt: 'Aconteceu, ao cabo de quatro anos, que Absalão disse ao rei: Deixa-me ir pagar em Hebrom o voto que fiz ao Senhor.' },
      { v: 8, en: 'For your servant vowed a vow while I stayed at Geshur in Syria, saying, ‘If Yahweh shall indeed bring me again to Jerusalem, then I will serve Yahweh.’”', pt: 'Porque, morando eu em Gesur, na Síria, fez o teu servo um voto, dizendo: Se o Senhor, na verdade, me fizer tornar a Jerusalém, servirei ao Senhor.' },
      { v: 9, en: 'The king said to him, “Go in peace.” So he arose, and went to Hebron.', pt: 'Então lhe disse o rei: Vai em paz. Levantou-se, pois, e foi para Hebrom.' },
      { v: 10, en: 'But Absalom sent spies throughout all the tribes of Israel, saying, “As soon as you hear the sound of the trumpet, then you shall say, ‘Absalom is king in Hebron!’”', pt: 'Absalão, porém, enviou emissários por todas as tribos de Israel, dizendo: Quando ouvirdes o som da trombeta, direis: Absalão reina em Hebrom.' },
      { v: 11, en: 'Two hundred men went with Absalom out of Jerusalem, who were invited, and went in their simplicity; and they didn’t know anything.', pt: 'E de Jerusalém foram com Absalão duzentos homens que tinham sido convidados; mas iam na sua simplicidade, pois nada sabiam daquele desígnio.' },
      { v: 12, en: 'Absalom sent for Ahithophel the Gilonite, David’s counselor, from his city, even from Giloh, while he was offering the sacrifices. The conspiracy was strong; for the people increased continually with Absalom.', pt: 'Também Absalão, enquanto oferecia os seus sacrifícios, mandou vir da cidade de Siló, Aitofel, o gilonita, conselheiro de Davi. E a conspiração tornava-se poderosa, crescendo cada vez mais o número do povo que estava com Absalão.' },
      { v: 13, en: 'A messenger came to David, saying, “The hearts of the men of Israel are after Absalom.”', pt: 'Então veio um mensageiro a Davi, dizendo: O coração de todo o Israel vai após Absalão.' },
      { v: 14, en: 'David said to all his servants who were with him at Jerusalem, “Arise, and let us flee; or else none of us will escape from Absalom. Hurry to depart, lest he overtake us quickly, and bring down evil on us, and strike the city with the edge of the sword.”', pt: 'Disse, pois, Davi a todos os seus servos que estavam com ele em Jerusalém: Levantai-vos, e fujamos, porque doutra forma não poderemos escapar diante de Absalão. Apressai-vos a sair; não seja caso que ele nos apanhe de súbito, e lance sobre nós a ruína, e fira a cidade ao fio da espada.' },
      { v: 15, en: 'The king’s servants said to the king, “Behold, your servants are ready to do whatever my lord the king chooses.”', pt: 'Então os servos do rei lhe disseram: Eis aqui os teus servos para tudo quanto determinar o rei, nosso senhor.' },
      { v: 16, en: 'The king went out, and all his household after him. The king left ten women, who were concubines, to keep the house.', pt: 'Assim saiu o rei, com todos os de sua casa, deixando, porém, dez concubinas para guardarem a casa.' },
      { v: 17, en: 'The king went out, and all the people after him; and they stayed in Beth Merhak.', pt: 'Tendo, pois, saído o rei com todo o povo, pararam na última casa:' },
      { v: 18, en: 'All his servants passed on beside him; and all the Cherethites, and all the Pelethites, and all the Gittites, six hundred men who came after him from Gath, passed on before the king.', pt: 'E todos os seus servos iam ao seu lado; mas todos os quereteus, e todos os peleteus, e todos os giteus, seiscentos homens que o seguiram de Gate, caminhavam adiante do rei.' },
      { v: 19, en: 'Then the king said to Ittai the Gittite, “Why do you also go with us? Return, and stay with the king; for you are a foreigner, and also an exile. Return to your own place.', pt: 'Disse o rei a Itai, o giteu: Por que irias tu também conosco? Volta e fica-te com o rei, porque és estrangeiro e exilado; torna a teu lugar.' },
      { v: 20, en: 'Whereas you came but yesterday, should I today make you go up and down with us, since I go where I may? Return, and take back your brothers. Mercy and truth be with you.”', pt: 'Ontem vieste, e te levaria eu hoje conosco a vaguear? Pois eu vou para onde puder ir; volta, e lei, e contigo teus irmãos; a misericórdia e a fidelidade sejam contigo.' },
      { v: 21, en: 'Ittai answered the king, and said, “As Yahweh lives, and as my lord the king lives, surely in what place my lord the king is, whether for death or for life, your servant will be there also.”', pt: 'Respondeu, porém, Itai ao rei, e disse: Vive o Senhor, e vive o rei meu senhor, que no lugar em que estiver o rei meu senhor, seja para morte, seja para vida, aí estará também o eu servo.' },
      { v: 22, en: 'David said to Ittai, “Go and pass over.” Ittai the Gittite passed over, and all his men, and all the little ones who were with him.', pt: 'Então disse Davi a Itai: Vai, pois, e passa adiante. Assim passou Itai, o giteu, e todos os seus homens, e todos os pequeninos que havia com ele.' },
      { v: 23, en: 'All the country wept with a loud voice, and all the people passed over. The king also himself passed over the brook Kidron, and all the people passed over, toward the way of the wilderness.', pt: 'Toda a terra chorava em alta voz, enquanto todo o povo passava; e o rei atravessou o ribeiro de Cedrom, e todo o povo caminhava na direção do deserto.' },
      { v: 24, en: 'Behold, Zadok also came, and all the Levites with him, bearing the ark of the covenant of God; and they set down God’s ark; and Abiathar went up, until all the people finished passing out of the city.', pt: 'E chegou Abiatar; e veio também Zadoque, e com ele todos os levitas que levavam a arca do pacto de Deus; e puseram ali a arca de Deus, até que todo o povo acabou de sair da cidade.' },
      { v: 25, en: 'The king said to Zadok, “Carry God’s ark back into the city. If I find favor in Yahweh’s eyes, he will bring me again, and show me both it, and his habitation;', pt: 'Então disse o rei a Zadoque: Torna a levar a arca de Deus à cidade; pois, se eu achar graça aos olhos do Senhor, ele me fará voltar para lá, e me deixará ver a arca e a sua habitação.' },
      { v: 26, en: 'but if he says, ‘I have no delight in you;’ behold, here am I. Let him do to me as seems good to him.”', pt: 'Se ele, porém, disser: Não tenho prazer em ti; eis-me aqui, faça a mim o que bem lhe parecer.' },
      { v: 27, en: 'The king said also to Zadok the priest, “Aren’t you a seer? Return into the city in peace, and your two sons with you, Ahimaaz your son, and Jonathan the son of Abiathar.', pt: 'Disse mais o rei a Zadoque, o sacerdote: Não és tu porventura vidente? volta, pois, para a cidade em paz, e contigo também teus dois filhos, Aimaaz, teu filho, e Jônatas, filho de Abiatar.' },
      { v: 28, en: 'Behold, I will stay at the fords of the wilderness, until word comes from you to inform me.”', pt: 'Vede eu me demorarei nos vaus do deserto até que tenha notícias da vossa parte.' },
      { v: 29, en: 'Zadok therefore and Abiathar carried God’s ark to Jerusalem again; and they stayed there.', pt: 'Zadoque, pois, e Abiatar tornaram a levar para Jerusalém a arca de Deus, e ficaram ali.' },
      { v: 30, en: 'David went up by the ascent of the Mount of Olives, and wept as he went up; and he had his head covered, and went barefoot: and all the people who were with him each covered his head, and they went up, weeping as they went up.', pt: 'Mas Davi, subindo pela encosta do monte das Oliveiras, ia chorando; tinha a cabeça coberta, e caminhava com os pés descalços. Também todo o povo que ia com ele tinha a cabeça coberta, e subia chorando sem cessar.' },
      { v: 31, en: 'Someone told David, saying, “Ahithophel is among the conspirators with Absalom.” David said, “Yahweh, please turn the counsel of Ahithophel into foolishness.”', pt: 'Então disseram a Davi: Aitofel está entre os que conspiraram com Absalão. Pelo que disse Davi: ç Senhor, torna o conselho de Aitofel em loucura!' },
      { v: 32, en: 'When David had come to the top, where God was worshiped, behold, Hushai the Archite came to meet him with his coat torn, and earth on his head.', pt: 'Ora, aconteceu que, chegando Davi ao cume, onde se costumava adorar a Deus, Husai, o arquita, veio encontrar-se com ele, com a roupa rasgada e a cabeça coberta de terra.' },
      { v: 33, en: 'David said to him, “If you pass on with me, then you will be a burden to me;', pt: 'Disse-lhe Davi: Se fores comigo, ser-me-ás pesado;' },
      { v: 34, en: 'but if you return to the city, and tell Absalom, ‘I will be your servant, O king. As I have been your father’s servant in time past, so will I now be your servant; then will you defeat for me the counsel of Ahithophel.’', pt: 'porém se voltares para a cidade, e disseres a Absalão: Eu serei, ó rei, teu servo; como fui dantes servo de teu pai, assim agora serei teu servo; dissipar-me-ás então a conselho de Aitofel.' },
      { v: 35, en: 'Don’t you have Zadok and Abiathar the priests there with you? Therefore whatever you hear out of the king’s house, tell it to Zadok and Abiathar the priests.', pt: 'E não estão ali contigo Zadoque e Abiatar, sacerdotes? Portanto, tudo o que ouvires da casa do rei lhes dirás.' },
      { v: 36, en: 'Behold, they have there with them their two sons, Ahimaaz, Zadok’s son, and Jonathan, Abiathar’s son. Send to me everything that you shall hear by them.”', pt: 'Eis que estão também ali com eles seus dois filhos, Aimaaz, filho de Zadoque, e Jônatas, filho de Abiatar; por eles me avisareis de tudo o que ouvirdes.' },
      { v: 37, en: 'So Hushai, David’s friend, came into the city; and Absalom came into Jerusalem.', pt: 'Husai, pois, amigo de Davi, voltou para a cidade. E Absalão entrou em Jerusalém.' },
    ],
    16: [
      { v: 1, en: 'When David was a little past the top, behold, Ziba the servant of Mephibosheth met him with a couple of donkeys saddled, and on them two hundred loaves of bread, and one hundred clusters of raisins, and one hundred summer fruits, and a bottle of wine.', pt: 'Tendo Davi passado um pouco além do cume, eis que Ziba, o moço de Mefibosete, veio encontrar-se com ele, com um par de jumentos albardados, e sobre eles duzentos pães, cem cachos de passas, e cem de frutas de verão e um odre de vinho.' },
      { v: 2, en: 'The king said to Ziba, “What do you mean by these?” Ziba said, “The donkeys are for the king’s household to ride on; and the bread and summer fruit for the young men to eat; and the wine, that those who are faint in the wilderness may drink.”', pt: 'Perguntou, pois, o rei a Ziba: Que pretendes com isso? Respondeu Ziba: Os jumentos são para a casa do rei, para se montarem neles; e o pão e as frutas de verão para os moços comerem; e o vinho para os cansados no deserto beberem.' },
      { v: 3, en: 'The king said, “Where is your master’s son?” Ziba said to the king, “Behold, he is staying in Jerusalem; for he said, ‘Today the house of Israel will restore me the kingdom of my father.’”', pt: 'Perguntou ainda o rei: E onde está o filho de teu senhor? Respondeu Ziba ao rei: Eis que permanece em Jerusalém, pois disse: Hoje a casa de Israel me restituirá o reino de meu pai.' },
      { v: 4, en: 'Then the king said to Ziba, “Behold, all that belongs to Mephibosheth is yours.” Ziba said, “I bow down. Let me find favor in your sight, my lord, O king.”', pt: 'Então disse o rei a Ziba: Eis que tudo quanto pertencia a Mefibosete é teu. Ao que Ziba, inclinando-se, disse: Que eu ache graça aos teus olhos, ó rei meu senhor.' },
      { v: 5, en: 'When king David came to Bahurim, behold, a man of the family of Saul’s house came out, whose name was Shimei, the son of Gera. He came out and cursed as he came.', pt: 'Tendo o rei Davi chegado a Baurim, veio saindo dali um homem da linhagem da casa de Saul, cujo nome era Simei, filho de Gêra; e, adiantando-se, proferia maldições.' },
      { v: 6, en: 'He cast stones at David, and at all the servants of king David, and all the people and all the mighty men were on his right hand and on his left.', pt: 'Também atirava pedras contra Davi e todos os seus servos, ainda que todo o povo e todos os valorosos iam à direita e à esquerda do rei.' },
      { v: 7, en: 'Shimei said when he cursed, “Be gone, be gone, you man of blood, and wicked fellow!', pt: 'E, amaldiçoando-o Simei, assim dizia: Sai, sai, homem sanguinário, homem de Belial!' },
      { v: 8, en: 'Yahweh has returned on you all the blood of Saul’s house, in whose place you have reigned! Yahweh has delivered the kingdom into the hand of Absalom your son! Behold, you are caught by your own mischief, because you are a man of blood!”', pt: 'O Senhor te deu agora a paga de todo o sangue da casa de Saul, em cujo lugar tens reinado; já entregou o Senhor o reino na mão de Absalão, teu filho; e eis-te agora na desgraça, pois és um homem sanguinário.' },
      { v: 9, en: 'Then Abishai the son of Zeruiah said to the king, “Why should this dead dog curse my lord the king? Please let me go over and take off his head.”', pt: 'Então Abisai, filho de Zeruia, disse ao rei: Por que esse cão morto amaldiçoaria ao rei meu senhor? Deixa-me passar e tirar-lhe a cabeça.' },
      { v: 10, en: 'The king said, “What have I to do with you, you sons of Zeruiah? Because he curses, and because Yahweh has said to him, ‘Curse David;’ who then shall say, ‘Why have you done so?’”', pt: 'Disse, porém, o rei: Que tenho eu convosco, filhos de Zeruia? Por ele amaldiçoar e por lhe ter dito o Senhor: Amaldiçoa a Davi; quem dirá: Por que assim fizeste?' },
      { v: 11, en: 'David said to Abishai, and to all his servants, “Behold, my son, who came out of my bowels, seeks my life. How much more this Benjamite, now? Leave him alone, and let him curse; for Yahweh has invited him.', pt: 'Disse mais Davi a Abisai, e a todos os seus servos: Eis que meu filho, que saiu das minhas entranhas, procura tirar-me a vida; quanto mais ainda esse benjamita? Deixai-o; deixai que amaldiçõe, porque o Senhor lho ordenou.' },
      { v: 12, en: 'It may be that Yahweh will look on the wrong done to me, and that Yahweh will repay me good for the cursing of me today.”', pt: 'Porventura o Senhor olhará para a minha aflição, e me pagará com bem a maldição deste dia.' },
      { v: 13, en: 'So David and his men went by the way; and Shimei went along on the hillside opposite him, and cursed as he went, threw stones at him, and threw dust.', pt: 'Prosseguiam, pois, o seu caminho, Davi e os seus homens, enquanto Simei ia pela encosta do monte, defronte dele, caminhando e amaldiçoando, e atirava pedras contra ele, e levantava poeira.' },
      { v: 14, en: 'The king, and all the people who were with him, came weary; and he refreshed himself there.', pt: 'E o rei e todo o povo que ia com ele chegaram cansados ao Jordão; e ali descansaram.' },
      { v: 15, en: 'Absalom and all the people, the men of Israel, came to Jerusalem, and Ahithophel with him.', pt: 'Absalão e todo o povo, os homens de Israel, vieram a Jerusalém; e Aitofel estava com ele.' },
      { v: 16, en: 'When Hushai the Archite, David’s friend, had come to Absalom, Hushai said to Absalom, “Long live the king! Long live the king!”', pt: 'E chegando Husai, o arquita, amigo de Davi, a Absalão, disse-lhe: Viva o rei, viva o rei!' },
      { v: 17, en: 'Absalom said to Hushai, “Is this your kindness to your friend? Why didn’t you go with your friend?”', pt: 'Absalão, porém, perguntou a Husai: E esta a tua benevolência para com o teu amigo? Por que não foste com o teu amigo?' },
      { v: 18, en: 'Hushai said to Absalom, “No; but whomever Yahweh, and this people, and all the men of Israel have chosen, his will I be, and with him I will stay.', pt: 'Respondeu-lhe Husai: Não; pois aquele a quem o Senhor, e este povo, e todos os homens de Israel têm escolhido, dele serei e com ele ficarei.' },
      { v: 19, en: 'Again, whom should I serve? Shouldn’t I serve in the presence of his son? As I have served in your father’s presence, so will I be in your presence.”', pt: 'E, demais disto, a quem serviria eu? Porventura não seria a seu filho? como servi a teu pai, assim servirei a ti.' },
      { v: 20, en: 'Then Absalom said to Ahithophel, “Give your counsel what we shall do.”', pt: 'Então disse Absalão a Aitofel: Dai o vosso conselho sobre o que devemos fazer.' },
      { v: 21, en: 'Ahithophel said to Absalom, “Go in to your father’s concubines that he has left to keep the house. Then all Israel will hear that you are abhorred by your father. Then the hands of all who are with you will be strong.”', pt: 'Respondeu Aitofel a Absalão: Entra às concubinas de teu pai, que ele deixou para guardarem a casa; e assim todo o Israel ouvirá que te fizeste aborrecível para com teu pai, e se fortalecerão as mãos de todos os que estão contigo.' },
      { v: 22, en: 'So they spread a tent for Absalom on the top of the house, and Absalom went in to his father’s concubines in the sight of all Israel.', pt: 'Estenderam, pois, para Absalão uma tenda no terraço; e entrou Absalão às concubinas de seu pai, à vista de todo o Israel.' },
      { v: 23, en: 'The counsel of Ahithophel, which he gave in those days, was as if a man inquired at the inner sanctuary of God. So was all the counsel of Ahithophel both with David and with Absalom.', pt: 'E o conselho que Aitofel dava naqueles dias era como se o oráculo de Deus se consultara; tal era todo o conselho de Aitofel, tanto para com Davi como para Absalão.' },
    ],
    17: [
      { v: 1, en: 'Moreover Ahithophel said to Absalom, “Let me now choose twelve thousand men, and I will arise and pursue after David tonight.', pt: 'Disse mais Aitofel a Absalão: Deixa-me escolher doze mil homens, e me levantarei, e perseguirei a Davi esta noite.' },
      { v: 2, en: 'I will come on him while he is weary and exhausted, and will make him afraid. All the people who are with him will flee. I will strike the king only,', pt: 'Irei sobre ele, enquanto está cansado, e fraco de mãos, e o espantarei: então fugirá todo o povo que está com ele. Ferirei tão-somente o rei;' },
      { v: 3, en: 'and I will bring back all the people to you. The man whom you seek is as if all returned. All the people shall be in peace.”', pt: 'e farei tornar a ti todo o povo, como uma noiva à casa do seu esposo; pois é a vida dum só homem que tu buscas; assim todo o povo estará em paz.' },
      { v: 4, en: 'The saying pleased Absalom well, and all the elders of Israel.', pt: 'E este conselho agradou a Absalão, e a todos os anciãos de Israel.' },
      { v: 5, en: 'Then Absalom said, “Now call Hushai the Archite also, and let us hear likewise what he says.”', pt: 'Disse, porém, Absalão: Chamai agora a Husai, o arquita, e ouçamos também o que ele diz.' },
      { v: 6, en: 'When Hushai had come to Absalom, Absalom spoke to him, saying, “Ahithophel has spoken like this. Shall we do what he says? If not, speak up.”', pt: 'Quando Husai chegou a Absalão, este lhe disse: Desta maneira falou Aitofel; faremos conforme a sua palavra? Se não, fala tu.' },
      { v: 7, en: 'Hushai said to Absalom, “The counsel that Ahithophel has given this time is not good.”', pt: 'Então disse Husai a Absalão: O conselho que Aitofel deu esta vez não é bom.' },
      { v: 8, en: 'Hushai said moreover, “You know your father and his men, that they are mighty men, and they are fierce in their minds, like a bear robbed of her cubs in the field. Your father is a man of war, and will not lodge with the people.', pt: 'Acrescentou Husai: Tu bem sabes que teu pai e os seus homens são valentes, e que estão com o espírito amargurado, como a ursa no campo, roubada dos seus cachorros; além disso teu pai é homem de guerra, e não passará a noite com o povo.' },
      { v: 9, en: 'Behold, he is now hidden in some pit, or in some other place. It will happen, when some of them have fallen at the first, that whoever hears it will say, ‘There is a slaughter among the people who follow Absalom!’', pt: 'Eis que agora está ele escondido nalguma cova, ou em qualquer outro lugar; e será que, caindo alguns no primeiro ataque, todo o que o ouvir dirá: Houve morticínio entre o povo que segue a Absalão.' },
      { v: 10, en: 'Even he who is valiant, whose heart is as the heart of a lion, will utterly melt; for all Israel knows that your father is a mighty man, and those who are with him are valiant men.', pt: 'Então até o homem valente, cujo coração é como coração de leão, sem dúvida desmaiará; porque todo o Israel sabe que teu pai é valoroso, e que são valentes os que estão com ele.' },
      { v: 11, en: 'But I counsel that all Israel be gathered together to you, from Dan even to Beersheba, as the sand that is by the sea for multitude; and that you go to battle in your own person.', pt: 'Eu, porém, aconselho que com toda a pressa se ajunte a ti todo o Israel, desde Dã até Berseba, em multidão como a areia do mar; e que tu em pessoa vás à peleja.' },
      { v: 12, en: 'So shall we come on him in some place where he shall be found, and we will light on him as the dew falls on the ground; and of him and of all the men who are with him we will not leave so much as one.', pt: 'Então iremos a ele, em qualquer lugar em que se achar, e desceremos sobre ele, como o orvalho cai sobre a terra; e nao ficará dele e de todos os homens que estão com ele nem sequer um só.' },
      { v: 13, en: 'Moreover, if he has gone into a city, then shall all Israel bring ropes to that city, and we will draw it into the river, until there isn’t one small stone found there.”', pt: 'se ele, porém, se retirar para alguma cidade, todo o Israel trará cordas àquela cidade, e arrastá-la-emos até o ribeiro, até que não se ache ali nem uma só pedrinha' },
      { v: 14, en: 'Absalom and all the men of Israel said, “The counsel of Hushai the Archite is better than the counsel of Ahithophel.” For Yahweh had ordained to defeat the good counsel of Ahithophel, to the intent that Yahweh might bring evil on Absalom.', pt: 'Então Absalão e todos os homens e Israel disseram: Melhor é o conselho de Husai, o arquita, do que o conselho de Aitofel: Porque assim o Senhor o ordenara, para aniquilar o bom conselho de Aitofel, a fim de trazer o mal sobre Absalão.' },
      { v: 15, en: 'Then Hushai said to Zadok and to Abiathar the priests, “Ahithophel counseled Absalom and the elders of Israel that way; and I have counseled this way.', pt: 'Também disse Husai a Zadoque e a Abiatar, sacerdotes: Assim e assim aconselhou Aitofel a Absalão e aos anciãos de Israel; porém eu aconselhei assim e assim.' },
      { v: 16, en: 'Now therefore send quickly, and tell David, saying, ‘Don’t lodge tonight at the fords of the wilderness, but by all means pass over; lest the king be swallowed up, and all the people who are with him.’”', pt: 'Agora, pois, mandai apressadamente avisar a Davi, dizendo: Não passes esta noite nos vaus do deserto; mas passa sem falta à outra banda, para que não seja devorado o rei, e todo o povo que com ele está.' },
      { v: 17, en: 'Now Jonathan and Ahimaaz were staying by En Rogel; and a female servant used to go and tell them; and they went and told king David. For they might not be seen to come into the city.', pt: 'Ora, Jônatas e Aimaaz estavam esperando junto a En-Rogel; e foi uma criada, e lhes avisou, para que eles fossem e o dissessem ao rei Davi; pois não deviam ser vistos entrando na cidade.' },
      { v: 18, en: 'But a boy saw them, and told Absalom. Then they both went away quickly, and came to the house of a man in Bahurim, who had a well in his court; and they went down there.', pt: 'Viu-os todavia um moço, e avisou a Absalão. Ambos, porém, partiram apressadamente, e entraram em casa de um homem, em Baurim, o qual tinha no pátio de sua casa um poço, para o qual eles desceram.' },
      { v: 19, en: 'The woman took and spread the covering over the well’s mouth, and spread out bruised grain on it; and nothing was known.', pt: 'E a mulher, tomando a tampa, colocou-a sobre a boca do poço, e espalhou grão triturado sobre ela; assim nada se soube.' },
      { v: 20, en: 'Absalom’s servants came to the woman to the house; and they said, “Where are Ahimaaz and Jonathan?” The woman said to them, “They have gone over the brook of water.” When they had sought and could not find them, they returned to Jerusalem.', pt: 'Chegando, pois, os servos de Absalão àquela casa, perguntaram à mulher: Onde estão Aimaaz e Jônatas? Respondeu-lhes a mulher: Já passaram a corrente das águas. E, havendo-os procurado sem os encontrarem, voltaram para Jerusalém.' },
      { v: 21, en: 'After they had departed, they came up out of the well, and went and told king David; and they said to David, “Arise and pass quickly over the water; for thus has Ahithophel counseled against you.”', pt: 'Depois que eles partiram, Aimaaz e Jônatas, saindo do poço, foram e avisaram a Davi; e disseram-lhe: Levantai-vos, e passai depressa as águas, porque assim e assim aconselhou contra vós Aitofel.' },
      { v: 22, en: 'Then David arose, and all the people who were with him, and they passed over the Jordan. By the morning light there lacked not one of them who had not gone over the Jordan.', pt: 'Então se levantou Davi e todo o povo que com ele estava, e passaram o Jordão; e ao raiar da manhã não faltava nem um só que não o tivesse passado.' },
      { v: 23, en: 'When Ahithophel saw that his counsel was not followed, he saddled his donkey, arose, and went home, to his city, and set his house in order, and hanged himself; and he died, and was buried in the tomb of his father.', pt: 'Vendo, pois, Aitofel que não se havia seguido o seu conselho, albardou o jumento e, partindo, foi para casa, para a sua cidade; e, tendo posto em ordem a sua casa, se enforcou e morreu; e foi sepultado na sepultura de seu pai.' },
      { v: 24, en: 'Then David came to Mahanaim. Absalom passed over the Jordan, he and all the men of Israel with him.', pt: 'Então Davi veio a Maanaim; e Absalão passou o Jordão, ele e todos os homens de Israel com ele.' },
      { v: 25, en: 'Absalom set Amasa over the army instead of Joab. Now Amasa was the son of a man whose name was Ithra the Israelite, who went in to Abigail the daughter of Nahash, sister to Zeruiah, Joab’s mother.', pt: 'E Absalão colocou Amasa em lugar de Joabe sobre o exército. Ora, Amasa era filho de um homem que se chamava Itra, o jizreelita, o qual entrara a Abigail, filha de Naás e irmã de Zeruia, mãe de Joabe.' },
      { v: 26, en: 'Israel and Absalom encamped in the land of Gilead.', pt: 'Israel e Absalão se acamparam na terra de Gileade.' },
      { v: 27, en: 'When David had come to Mahanaim, Shobi the son of Nahash of Rabbah of the children of Ammon, and Machir the son of Ammiel of Lodebar, and Barzillai the Gileadite of Rogelim,', pt: 'Tendo Davi chegado a Maanaim, Sobi, filho de Naás, de Rabá dos filhos de Amom, e Maquir, filho de Amiel, de Lo-Debar, e Barzilai, o gileadita, de Rogelim,' },
      { v: 28, en: 'brought beds, basins, earthen vessels, wheat, barley, meal, parched grain, beans, lentils, roasted grain,', pt: 'tomaram camas, bacias e vasilhas de barro; trigo, cevada, farinha, grão tostado, favas, lentilhas e torradas;' },
      { v: 29, en: 'honey, butter, sheep, and cheese of the herd, for David, and for the people who were with him, to eat; for they said, “The people are hungry, and weary, and thirsty in the wilderness.”', pt: 'mel, manteiga, ovelhas e queijos de vaca, e os trouxeram a Davi e ao povo que com ele estava, para comerem; pois diziam: O povo está faminto, cansado e sedento, no deserto.' },
    ],
    18: [
      { v: 1, en: 'David counted the people who were with him, and set captains of thousands and captains of hundreds over them.', pt: 'Então Davi contou o povo que tinha consigo, e pôs sobre ele chefes de mil e chefes de cem.' },
      { v: 2, en: 'David sent the people out, a third part under the hand of Joab, and a third part under the hand of Abishai the son of Zeruiah, Joab’s brother, and a third part under the hand of Ittai the Gittite. The king said to the people, “I will also surely go out with you myself.”', pt: 'E Davi enviou o exército, um terço sob o mando de Joabe, outro terço sob o mando de Abisai, filho de Zeruia, irmão de Joabe, e outro terço sob o mando de Itai, o giteu. E disse o rei ao povo: Eu também sairei convosco.' },
      { v: 3, en: 'But the people said, “You shall not go out; for if we flee away, they will not care for us; neither if half of us die, will they care for us. But you are worth ten thousand of us. Therefore now it is better that you are ready to help us out of the city.”', pt: 'Mas o povo respondeu: Não sairás; porque se fugirmos, eles não se importarão conosco; nem se importarão conosco ainda que morra metade de nós; porque tu vales por dez mil tais como nós. Melhor será que da cidade nos mandes socorro.' },
      { v: 4, en: 'The king said to them, “I will do what seems best to you.” The king stood beside the gate, and all the people went out by hundreds and by thousands.', pt: 'Respondeu-lhes o rei: Farei o que vos parecer bem. E o rei se pôs ao lado da porta, e todo o povo saiu em centenas e em milhares.' },
      { v: 5, en: 'The king commanded Joab and Abishai and Ittai, saying, “Deal gently for my sake with the young man, even with Absalom.” All the people heard when the king commanded all the captains concerning Absalom.', pt: 'E o rei deu ordem a Joabe, a Abisai e a Itai, dizendo: Tratai brandamente, por amor de mim, o mancebo Absalão. E todo o povo ouviu quando o rei deu ordem a todos os chefes acerca de Absalão.' },
      { v: 6, en: 'So the people went out into the field against Israel; and the battle was in the forest of Ephraim.', pt: 'Assim saiu o povo a campo contra Israel; e deu-se a batalha no bosque de Efraim.' },
      { v: 7, en: 'The people of Israel were struck there before David’s servants, and there was a great slaughter there that day of twenty thousand men.', pt: 'Ali o povo de Israel foi derrotado pelos servos de Davi; e naquele dia houve ali grande morticínio, de vinte mil homens.' },
      { v: 8, en: 'For the battle was there spread over the surface of all the country, and the forest devoured more people that day than the sword devoured.', pt: 'Pois a batalha se estendeu sobre a face de toda aquela terra, e o bosque consumiu mais gente naquele dia do que a espada.' },
      { v: 9, en: 'Absalom happened to meet David’s servants. Absalom was riding on his mule, and the mule went under the thick boughs of a great oak, and his head caught hold of the oak, and he was taken up between the sky and earth; and the mule that was under him went on.', pt: 'Por acaso Absalão se encontrou com os servos de Davi; e Absalão ia montado num mulo e, entrando o mulo debaixo dos espessos ramos de um grande carvalho, pegou-se a cabeça de Absalão no carvalho, e ele ficou pendurado entre o céu e a terra; e o mulo que estava debaixo dele passou adiante.' },
      { v: 10, en: 'A certain man saw it, and told Joab, and said, “Behold, I saw Absalom hanging in an oak.”', pt: 'um homem, vendo isso, contou-o a Joabe, dizendo: Eis que vi Absalão pendurado dum carvalho.' },
      { v: 11, en: 'Joab said to the man who told him, “Behold, you saw it, and why didn’t you strike him there to the ground? I would have given you ten pieces of silver, and a sash.”', pt: 'Então disse Joabe ao homem que lho contara: Pois que o viste, por que não o derrubaste logo por terra? E eu te haveria dado dez siclos de prata e um cinto.' },
      { v: 12, en: 'The man said to Joab, “Though I should receive a thousand pieces of silver in my hand, I still wouldn’t stretch out my hand against the king’s son; for in our hearing the king commanded you and Abishai and Ittai, saying, ‘Beware that no one touch the young man Absalom.’', pt: 'Respondeu, porém, o homem a Joabe: Ainda que eu pudesse pesar nas minhas mãos mil siclos de prata, não estenderia a mão contra o filho do rei; pois bem ouvimos que o rei deu ordem a ti, e a Abisai, e a Itai, dizendo: Guardai-vos, cada um, de tocar no mancebo Absalão.' },
      { v: 13, en: 'Otherwise if I had dealt falsely against his life (and there is no matter hidden from the king), then you yourself would have set yourself against me.”', pt: 'E se eu tivesse procedido falsamente contra a sua vida, coisa nenhuma se esconderia ao rei, e tu mesmo te oporias a mim:' },
      { v: 14, en: 'Then Joab said, “I’m not going to wait like this with you.” He took three darts in his hand, and thrust them through the heart of Absalom, while he was yet alive in the middle of the oak.', pt: 'Então disse Joabe: Não posso demorar-me assim contigo aqui. E tomou na mão três dardos, e traspassou com eles o coração de Absalão, estando ele ainda vivo no meio do carvalho.' },
      { v: 15, en: 'Ten young men who bore Joab’s armor surrounded and struck Absalom, and killed him.', pt: 'E o cercaram dez mancebos, que levavam as armas de Joabe; e feriram a Absalão, e o mataram.' },
      { v: 16, en: 'Joab blew the trumpet, and the people returned from pursuing after Israel; for Joab held the people back.', pt: 'Então tocou Joabe a buzina, e o povo voltou de perseguir a Israel; porque Joabe deteve o povo.' },
      { v: 17, en: 'They took Absalom and cast him into the great pit in the forest, and raised over him a very great heap of stones. Then all Israel fled, each to his own tent.', pt: 'E tomaram a Absalão e, lançando-o numa grande cova no bosque, levantaram sobre ele mui grande montão de pedras. E todo o Israel fugiu, cada um para a sua tenda.' },
      { v: 18, en: 'Now Absalom in his lifetime had taken and reared up for himself the pillar which is in the king’s valley, for he said, “I have no son to keep my name in memory.” He called the pillar after his own name. It is called Absalom’s monument, to this day.', pt: 'Ora, Absalão, quando ainda vivia, tinha feito levantar para si a coluna que está no vale do rei; pois dizia: Nenhum filho tenho para conservar a memoria o meu nome. E deu o seu próprio nome àquela coluna, a qual até o dia de hoje se chama o Pilar de Absalão.' },
      { v: 19, en: 'Then Ahimaaz the son of Zadok said, “Let me now run, and carry the king news, how Yahweh has avenged him of his enemies.”', pt: 'Então disse Aimaaz, filho de Zadoque: Deixa-me correr, e anunciarei ao rei que o Senhor o vingou a mão e seus inimigos.' },
      { v: 20, en: 'Joab said to him, “You must not be the bearer of news today, but you must carry news another day. But today you must carry no news, because the king’s son is dead.”', pt: 'Mas Joabe lhe disse: Tu não serás hoje o portador das novas; outro dia as levarás, mas hoje não darás a nova, porque é morto o filho do rei.' },
      { v: 21, en: 'Then Joab said to the Cushite, “Go, tell the king what you have seen!” The Cushite bowed himself to Joab, and ran.', pt: 'Disse, porém, Joabe ao cuchita: Vai tu, e dize ao rei o que viste. O cuchita se inclinou diante de Joabe, e saiu correndo.' },
      { v: 22, en: 'Then Ahimaaz the son of Zadok said yet again to Joab, “But come what may, please let me also run after the Cushite.” Joab said, “Why do you want to run, my son, since that you will have no reward for the news?”', pt: 'Então prosseguiu Aimaaz, filho de Zadoque, e disse a Joabe: Seja o que for, deixa-me também correr após o cuchita. Respondeu Joabe: Para que agora correrias tu, meu filho, pois não receberias recompensa pelas novas?' },
      { v: 23, en: '“But come what may,” he said, “I will run.” He said to him, “Run!” Then Ahimaaz ran by the way of the Plain, and outran the Cushite.', pt: 'seja o que for, disse Aimaaz, correrei. Disse-lhe, pois, Joabe: Corre. Então Aimaaz correu pelo caminho da planície, e passou adiante do cuchita.' },
      { v: 24, en: 'Now David was sitting between the two gates; and the watchman went up to the roof of the gate to the wall, and lifted up his eyes, and looked, and, behold, a man running alone.', pt: 'Ora, Davi estava sentado entre as duas portas; e a sentinela subiu ao terraçorém, percebeu que seus servos cochichavam entre si, um homem que corria só.' },
      { v: 25, en: 'The watchman cried, and told the king. The king said, “If he is alone, there is news in his mouth.” He came closer and closer.', pt: 'Gritou, pois, a sentinela, e o disse ao rei. Respondeu o rei: Se vem só, é portador de novas. Vinha, pois, o mensageiro aproximando-se cada vez mais.' },
      { v: 26, en: 'The watchman saw another man running; and the watchman called to the gatekeeper, and said, “Behold, a man running alone!” The king said, “He also brings news.”', pt: 'Então a sentinela viu outro homem que corria, e gritou ao porteiro, e disse: Eis que lá vem outro homem correndo só. Então disse o rei: Também esse traz novas.' },
      { v: 27, en: 'The watchman said, “I think the running of the first one is like the running of Ahimaaz the son of Zadok.” The king said, “He is a good man, and comes with good news.”', pt: 'Disse mais a sentinela: O correr do primeiro parece ser o correr de Aimaaz, filho de Zadoque. Então disse o rei: Este é homem de bem, e virá com boas novas.' },
      { v: 28, en: 'Ahimaaz called, and said to the king, “All is well.” He bowed himself before the king with his face to the earth, and said, “Blessed is Yahweh your God, who has delivered up the men who lifted up their hand against my lord the king!”', pt: 'Gritou, pois, Aimaaz, e disse ao rei: Paz! E inclinou-se ao rei com o rosto em terra, e disse: Bendito seja o Senhor teu Deus, que entregou os homens que levantaram a mão contra o rei meu senhor.' },
      { v: 29, en: 'The king said, “Is it well with the young man Absalom?” Ahimaaz answered, “When Joab sent the king’s servant, even me your servant, I saw a great tumult, but I don’t know what it was.”', pt: 'Então perguntou o rei: Vai bem o mancebo Absalão? Respondeu Aimaaz: Quando Joabe me mandou a mim, o servo do rei, vi um grande alvoroço; porem nao sei o que era.' },
      { v: 30, en: 'The king said, “Come and stand here.” He came, and stood still.', pt: 'Disse-lhe o rei: Põe-te aqui ao lado. E ele se pôs ao lado, e esperou de pé.' },
      { v: 31, en: 'Behold, the Cushite came. The Cushite said, “News for my lord the king, for Yahweh has avenged you today of all those who rose up against you.”', pt: 'Nisso chegou o cuchita, e disse: Novas para o rei meu senhor. Pois que hoje o Senhor te vingou da mão de todos os que se levantaram contra ti.' },
      { v: 32, en: 'The king said to the Cushite, “Is it well with the young man Absalom?” The Cushite answered, “May the enemies of my lord the king, and all who rise up against you to do you harm, be as that young man is.”', pt: 'Então perguntou o rei ao cuchita: Vai bem o mancebo Absalão? Respondeu o cuchita: Sejam como aquele mancebo os inimigos do rei meu senhor, e todos os que se levantam contra ti para te fazerem mal.' },
      { v: 33, en: 'The king was much moved, and went up to the room over the gate, and wept. As he went, he said, “My son Absalom! My son, my son Absalom! I wish I had died for you, Absalom, my son, my son!”', pt: 'Pelo que o rei ficou muito comovido e, subindo à sala que estava por cima da porta, pôs-se a chorar; e andando, dizia assim: Meu filho Absalão, meu filho, meu filho Absalão! quem me dera que eu morrera por ti, Absalão, meu filho, meu filho!' },
    ],
    19: [
      { v: 1, en: 'Joab was told, “Behold, the king weeps and mourns for Absalom.”', pt: 'Disseram a Joabe: Eis que o rei está chorando e se lamentando por Absalão.' },
      { v: 2, en: 'The victory that day was turned into mourning among all the people; for the people heard it said that day, “The king grieves for his son.”', pt: 'Então a vitória se tornou naquele dia em tristeza para todo o povo, porque nesse dia o povo ouviu dizer: O rei está muito triste por causa de seu filho.' },
      { v: 3, en: 'The people sneaked into the city that day, as people who are ashamed steal away when they flee in battle.', pt: 'E nesse dia o povo entrou furtivamente na cidade, como o faz quando, envergonhado, foge da peleja.' },
      { v: 4, en: 'The king covered his face, and the king cried with a loud voice, “My son Absalom, Absalom, my son, my son!”', pt: 'Estava, pois, o rei com o rosto coberto, e clamava em alta voz: Meu filho Absalão, Absalão meu filho, meu filho!' },
      { v: 5, en: 'Joab came into the house to the king, and said, “Today you have shamed the faces of all your servants, who today have saved your life, and the lives of your sons and of your daughters, and the lives of your wives, and the lives of your concubines;', pt: 'Então entrou Joabe na casa onde estava o rei, e disse: Hoje envergonhaste todos os teus servos, que livraram neste dia a tua vida, a vida de teus filhos e filhas, e a vida de tuas mulheres e concubinas,' },
      { v: 6, en: 'in that you love those who hate you, and hate those who love you. For you have declared today, that princes and servants are nothing to you. For today I perceive that if Absalom had lived, and all we had died today, then it would have pleased you well.', pt: 'amando aos que te odeiam, e odiando aos que te amam. Porque hoje dás a entender que nada valem para ti nem chefes nem servos; pois agora entendo que se Absalão vivesse, e todos nós hoje fôssemos mortos, ficarias bem contente.' },
      { v: 7, en: 'Now therefore arise, go out, and speak to comfort your servants; for I swear by Yahweh, if you don’t go out, not a man will stay with you this night. That would be worse to you than all the evil that has happened to you from your youth until now.”', pt: 'Levanta-te, pois, agora; sai e fala ao coração de teus servos. Porque pelo Senhor te juro que, se não saíres, nem um só homem ficará contigo esta noite; e isso te será pior do que todo o mal que tem vindo sobre ti desde a tua mocidade até agora.' },
      { v: 8, en: 'Then the king arose, and sat in the gate. They told to all the people, saying, “Behold, the king is sitting in the gate.” All the people came before the king. Now Israel had fled every man to his tent.', pt: 'Pelo que o rei se levantou, e se sentou à porta; e avisaram a todo o povo, dizendo: Eis que o rei está sentado à porta. Então todo o povo veio apresentar-se diante do rei. Ora, Israel havia fugido, cada um para a sua tenda.' },
      { v: 9, en: 'All the people were at strife throughout all the tribes of Israel, saying, “The king delivered us out of the hand of our enemies, and he saved us out of the hand of the Philistines; and now he has fled out of the land from Absalom.', pt: 'Entrementes todo o povo, em todas as tribos de Israel, andava altercando entre si, dizendo: O rei nos tirou das mãos de nossos inimigos, e nos livrou das mãos dos filisteus; e agora fugiu da terra por causa de Absalão.' },
      { v: 10, en: 'Absalom, whom we anointed over us, is dead in battle. Now therefore why don’t you speak a word of bringing the king back?”', pt: 'Também Absalão, a quem ungimos sobre nós, morreu na peleja. Agora, pois, porque vos calais, e não fazeis voltar o rei?' },
      { v: 11, en: 'King David sent to Zadok and to Abiathar the priests, saying, “Speak to the elders of Judah, saying, ‘Why are you the last to bring the king back to his house? Since the speech of all Israel has come to the king, to return him to his house.', pt: 'Então o rei Davi mandou dizer a Zadoque e a Abiatar, sacerdotes: Falai aos anciãos de Judá, dizendo: Por que seríeis vós os últimos em tornar a trazer o rei para sua casa? Porque a palavra de todo o Israel tem chegado ao rei, até a sua casa.' },
      { v: 12, en: 'You are my brothers. You are my bone and my flesh. Why then are you the last to bring back the king?’', pt: 'Vós sois meus irmãos; meus ossos e minha carne sois vós; por que, pois, seríeis os últimos em tornar a trazer o rei?' },
      { v: 13, en: 'Say to Amasa, ‘Aren’t you my bone and my flesh? God do so to me, and more also, if you aren’t captain of the army before me continually instead of Joab.’”', pt: 'Dizei a Amasa: Porventura não és tu meu osso e minha carne? Assim me faça Deus e outro tanto, se não fores chefe do exercito diante e mim para sempre, em lugar de Joabe.' },
      { v: 14, en: 'He bowed the heart of all the men of Judah, even as one man; so that they sent to the king, saying, “Return, you and all your servants.”', pt: 'Assim moveu ele o coração de todos os homens de Judá, como se fosse o de um só homem; e enviaram ao rei, dizendo: Volta, com todos os teus servos.' },
      { v: 15, en: 'So the king returned, and came to the Jordan. Judah came to Gilgal, to go to meet the king, to bring the king over the Jordan.', pt: 'Então o rei voltou, e chegou até o Jordão; e Judá veio a Gilgal, para encontrar-se com o rei, a fim de fazê-lo passar o Jordão.' },
      { v: 16, en: 'Shimei the son of Gera, the Benjamite, who was of Bahurim, hurried and came down with the men of Judah to meet king David.', pt: 'Ora, apressou-se Simei, filho de Gêra, benjamita, que era de Baurim, e desceu com os homens de Judá a encontrar-se com o rei Davi;' },
      { v: 17, en: 'There were a thousand men of Benjamin with him, and Ziba the servant of Saul’s house, and his fifteen sons and his twenty servants with him; and they went through the Jordan in the presence of the king.', pt: 'e com ele mil homens de Benjamim, como também Ziba, servo da casa de Saul, e seus quinze filhos, e seus vinte servos com ele; desceram apressadamente ao Jordão adiante do rei,' },
      { v: 18, en: 'A ferry boat went to bring over the king’s household, and to do what he thought good. Shimei the son of Gera fell down before the king, when he had come over the Jordan.', pt: 'atravessando o vau para trazer a casa do rei e para fazer o que aprouvesse a ele. Quando o rei ia passar o Jordão, Simei, filho de Gêra, se prostrou diante dele,' },
      { v: 19, en: 'He said to the king, “Don’t let my lord impute iniquity to me, or remember that which your servant did perversely the day that my lord the king went out of Jerusalem, that the king should take it to his heart.', pt: 'e lhe disse: Não me impute meu senhor à minha culpa, e não te lembres do que tão perversamente fez teu servo, no dia em que o rei meu senhor saiu de Jerusalém; não conserve o rei isso no coração.' },
      { v: 20, en: 'For your servant knows that I have sinned. Therefore behold, I have come today as the first of all the house of Joseph to go down to meet my lord the king.”', pt: 'Porque eu, teu servo, deveras confesso que pequei; por isso eis que eu sou o primeiro, de toda a casa de José, a descer ao encontro do rei meu senhor.' },
      { v: 21, en: 'But Abishai the son of Zeruiah answered, “Shouldn’t Shimei be put to death for this, because he cursed Yahweh’s anointed?”', pt: 'Respondeu Abisai, filho de Zeruia, dizendo: Não há de ser morto Simei por haver amaldiçoado ao ungido do Senhor?' },
      { v: 22, en: 'David said, “What have I to do with you, you sons of Zeruiah, that you should be adversaries to me today? Shall any man be put to death today in Israel? For don’t I know that I am king over Israel today?”', pt: 'Mas Davi disse: Que tenho eu convosco, filhos de Zeruia, para que hoje me sejais adversários? Será morto alguém hoje em Israel? pois não sei eu que hoje sou rei sobre Israel?' },
      { v: 23, en: 'The king said to Shimei, “You will not die.” The king swore to him.', pt: 'Então disse o rei a Simei: Não morrerás. E o rei lho jurou.' },
      { v: 24, en: 'Mephibosheth the son of Saul came down to meet the king; and he had neither groomed his feet, nor trimmed his beard, nor washed his clothes, from the day the king departed until the day he came home in peace.', pt: 'Também Mefibosete, filho de Saul, desceu a encontrar-se com o rei, e não cuidara dos pés, nem fizera a barba, nem lavara as suas vestes desde o dia em que o rei saíra até o dia em que voltou em paz.' },
      { v: 25, en: 'When he had come to Jerusalem to meet the king, the king said to him, “Why didn’t you go with me, Mephibosheth?”', pt: 'E sucedeu que, vindo ele a Jerusalém a encontrar-se com o rei, este lhe perguntou: Por que não foste comigo, Mefibosete?' },
      { v: 26, en: 'He answered, “My lord, O king, my servant deceived me. For your servant said, I will saddle me a donkey, that I may ride on it, and go with the king; because your servant is lame.', pt: 'Respondeu ele: O rei meu senhor, o meu servo me enganou. Porque o teu servo dizia: Albardarei um jumento, para nele montar e ir com o rei; pois o teu servo é coxo.' },
      { v: 27, en: 'He has slandered your servant to my lord the king, but my lord the king is as an angel of God. Do therefore what is good in your eyes.', pt: 'E ele acusou falsamente o teu servo diante do rei meu senhor; porém o rei meu senhor é como um anjo de Deus; faze, pois, o que bem te parecer.' },
      { v: 28, en: 'For all my father’s house were but dead men before my lord the king; yet you set your servant among those who ate at your own table. What right therefore have I yet that I should cry any more to the king?”', pt: 'Pois toda a casa de meu pai não era senão de homens dignos de morte diante do rei meu senhor; contudo, puseste teu servo entre os que comem à tua mesa. E que direito mais tenho eu de clamar ainda ao rei.' },
      { v: 29, en: 'The king said to him, “Why do you speak any more of your matters? I say, you and Ziba divide the land.”', pt: 'Ao que lhe respondeu o rei: Por que falas ainda de teus negócios? Já decidi: Tu e Ziba reparti as terras.' },
      { v: 30, en: 'Mephibosheth said to the king, “Yes, let him take all, because my lord the king has come in peace to his own house.”', pt: 'Então disse Mefibosete ao rei: Deixe que ele tome tudo, uma vez que o rei meu senhor já voltou em paz à sua casa.' },
      { v: 31, en: 'Barzillai the Gileadite came down from Rogelim; and he went over the Jordan with the king, to conduct him over the Jordan.', pt: 'Também Barzilai, o gileadita, desceu de Rogelim, e passou com o rei o Jordão, para acompanhá-lo até a outra banda do rio.' },
      { v: 32, en: 'Now Barzillai was a very aged man, even eighty years old. He had provided the king with sustenance while he stayed at Mahanaim; for he was a very great man.', pt: 'E era Barzilai mui velho, da idade de oitenta anos; e ele tinha provido o rei de víveres enquanto este se demorara em Maanaim, pois era homem muito rico.' },
      { v: 33, en: 'The king said to Barzillai, “Come over with me, and I will sustain you with me in Jerusalem.”', pt: 'Disse, pois, o rei a Barzilai: Passa tu comigo e eu te sustentarei em Jerusalém, em minha companhia.' },
      { v: 34, en: 'Barzillai said to the king, “How many are the days of the years of my life, that I should go up with the king to Jerusalem?', pt: 'Barzilai, porém, respondeu ao rei: Quantos anos viverei ainda, para que suba com o rei a Jerusalém.' },
      { v: 35, en: 'I am eighty years old, today. Can I discern between good and bad? Can your servant taste what I eat or what I drink? Can I hear the voice of singing men and singing women any more? Why then should your servant be a burden to my lord the king?', pt: 'Oitenta anos tenho hoje; poderei eu discernir entre e bom e o mau? poderá o teu servo perceber sabor no que comer e beber? poderei eu mais ouvir a voz dos cantores e das cantoras? e por que será o teu servo ainda pesado ao rei meu senhor?' },
      { v: 36, en: 'Your servant would but just go over the Jordan with the king. Why should the king repay me with such a reward?', pt: 'O teu servo passará com o rei até um pouco além do Jordão. Por que me daria o rei tal recompensa?' },
      { v: 37, en: 'Please let your servant turn back again, that I may die in my own city, by the grave of my father and my mother. But behold, your servant Chimham; let him go over with my lord the king; and do to him what shall seem good to you.”', pt: 'Deixa voltar o teu servo, para que eu morra na minha cidade, junto à sepultura de meu pai e de minha mãe. Mas eis aí o teu servo Quimã; passe ele com o rei meu senhor, e faze-lhe o que for do teu agrado.' },
      { v: 38, en: 'The king answered, “Chimham shall go over with me, and I will do to him that which shall seem good to you. Whatever you request of me, that I will do for you.”', pt: 'Ao que disse o rei: Quimã passará comigo, e eu lhe farei o que te parecer bem, e tudo quanto me pedires te farei.' },
      { v: 39, en: 'All the people went over the Jordan, and the king went over. Then the king kissed Barzillai, and blessed him; and he returned to his own place.', pt: 'Havendo, pois, todo o povo passado o Jordão, e tendo passado também o rei, beijou o rei a Barzilai, e o abençoou; e este voltou para o seu lugar.' },
      { v: 40, en: 'So the king went over to Gilgal, and Chimham went over with him. All the people of Judah brought the king over, and also half the people of Israel.', pt: 'Dali passou o rei a Gilgal, e Quimã com ele; e todo o povo de Judá, juntamente com a metade do povo de Israel, conduziu o rei.' },
      { v: 41, en: 'Behold, all the men of Israel came to the king, and said to the king, “Why have our brothers the men of Judah stolen you away, and brought the king, and his household, over the Jordan, and all David’s men with him?”', pt: 'Então todos os homens de Israel vieram ter com o rei, e lhe disseram: Por que te furtaram nossos irmãos, os homens de Judá, e fizeram passar o Jordão o rei e a sua casa, e todos os seus homens com ele?' },
      { v: 42, en: 'All the men of Judah answered the men of Israel, “Because the king is a close relative to us. Why then are you angry about this matter? Have we eaten at all at the king’s cost? Or has he given us any gift?”', pt: 'Responderam todos os homens de Judá aos homens de Israel: Porquanto o rei é nosso parente: Por que vos irais por isso. Acaso temos comido à custa do rei, ou nos deu ele algum presente?' },
      { v: 43, en: 'The men of Israel answered the men of Judah, and said, “We have ten parts in the king, and we have also more claim to David than you. Why then did you despise us, that our advice should not be first had in bringing back our king?” The words of the men of Judah were fiercer than the words of the men of Israel.', pt: 'Ao que os homens de Israel responderam aos homens de Judá: Dez partes temos no rei; mais temos nós em Davi do que vós. Por que, pois, fizestes pouca conta de nós. Não foi a nossa palavra a primeira, para tornar a trazer o nosso rei? Porém a palavra dos homens de Judá foi mais forte do que a palavra dos homens de Israel.' },
    ],
    20: [
      { v: 1, en: 'There happened to be there a wicked fellow, whose name was Sheba, the son of Bichri, a Benjamite; and he blew the trumpet, and said, “We have no portion in David, neither have we inheritance in the son of Jesse. Every man to his tents, Israel!”', pt: 'Ora, sucedeu achar-se ali um homem de Belial, cujo nome era Sebá, filho de Bicri, homem de Benjamim, o qual tocou a buzina, e disse: Não temos parte em Davi, nem herança no filho de Jessé; cada um à sua tenda, ó Israel!' },
      { v: 2, en: 'So all the men of Israel went up from following David, and followed Sheba the son of Bichri; but the men of Judah joined with their king, from the Jordan even to Jerusalem.', pt: 'Então todos os homens de Israel se separaram de Davi, e seguiram a Sebá, filho de Bicri; porém os homens de Judá seguiram ao seu rei desde o Jordão até Jerusalém.' },
      { v: 3, en: 'David came to his house at Jerusalem; and the king took the ten women his concubines, whom he had left to keep the house, and put them in custody, and provided them with sustenance, but didn’t go in to them. So they were shut up to the day of their death, living in widowhood.', pt: 'Quando Davi chegou à sua casa em Jerusalém, tomou as dez concubinas que deixara para guardarem a casa, e as pôs numa casa, sob guarda, e as sustentava; porém não entrou a elas. Assim estiveram encerradas até o dia da sua morte, vivendo como viúvas.' },
      { v: 4, en: 'Then the king said to Amasa, “Call me the men of Judah together within three days, and be here present.”', pt: 'Disse então o rei a Amasa: Convoca-me dentro de três dias os homens de Judá, e apresenta-te aqui.' },
      { v: 5, en: 'So Amasa went to call the men of Judah together; but he stayed longer than the set time which he had appointed him.', pt: 'Foi, pois, Amasa para convocar a Judá, porém demorou-se além do tempo que o rei lhe designara.' },
      { v: 6, en: 'David said to Abishai, “Now Sheba the son of Bichri will do us more harm than Absalom did. Take your lord’s servants, and pursue after him, lest he get himself fortified cities, and escape out of our sight.”', pt: 'Então disse Davi a Abisai: Mais mal agora nos fará Sebá, filho de Bicri, do que Absalão; toma, pois, tu os servos de teu senhor, e persegue-o, para que ele porventura não ache para si cidades fortificadas, e nos escape à nossa vista.' },
      { v: 7, en: 'Joab’s men went out after him, and the Cherethites and the Pelethites, and all the mighty men; and they went out of Jerusalem, to pursue Sheba the son of Bichri.', pt: 'Então saíram atrás dele os homens de Joabe, e os quereteus, e os peleteus, e todos os valentes; saíram de Jerusalém para perseguirem a Sebá, filho de Bicri.' },
      { v: 8, en: 'When they were at the great stone which is in Gibeon, Amasa came to meet them. Joab was clothed in his apparel of war that he had put on, and on it was a sash with a sword fastened on his waist in its sheath; and as he went along it fell out.', pt: 'Quando chegaram à pedra grande que está junto a Gibeão, Amasa lhes veio ao encontro. Estava Joabe cingido do seu traje de guerra que vestira, e sobre ele um cinto com a espada presa aos seus lombos, na sua bainha; e, adiantando-se ele, a espada caiu da bainha.' },
      { v: 9, en: 'Joab said to Amasa, “Is it well with you, my brother?” Joab took Amasa by the beard with his right hand to kiss him.', pt: 'E disse Joabe a Amasa: Vais bem, meu irmão? E Joabe, com a mão direita, pegou da barba de Amasa, para o beijar.' },
      { v: 10, en: 'But Amasa took no heed to the sword that was in Joab’s hand. So he struck him with it in the body, and shed out his bowels to the ground, and didn’t strike him again; and he died. Joab and Abishai his brother pursued Sheba the son of Bichri.', pt: 'Amasa, porém, não reparou na espada que está na mão de Joabe; de sorte que este o feriu com ela no ventre, derramando-lhe por terra as entranhas, sem feri-lo segunda vez; e ele morreu. Então Joabe e Abisai, seu irmão, perseguiram a Sebá, filho de Bicri.' },
      { v: 11, en: 'One of Joab’s young men stood by him, and said, “He who favors Joab, and he who is for David, let him follow Joab!”', pt: 'Mas um homem dentre os servos de Joabe ficou junto a Amasa, e dizia: Quem favorece a Joabe, e quem é por Davi, siga a Joabe.' },
      { v: 12, en: 'Amasa lay wallowing in his blood in the middle of the highway. When the man saw that all the people stood still, he carried Amasa out of the highway into the field, and cast a garment over him, when he saw that everyone who came by him stood still.', pt: 'E Amasa se revolvia no seu sangue no meio do caminho. E aquele homem, vendo que todo o povo parava, removeu Amasa do caminho para o campo, e lançou sobre ele um manto, porque viu que todo aquele que chegava ao pé dele parava.' },
      { v: 13, en: 'When he was removed out of the highway, all the people went on after Joab, to pursue Sheba the son of Bichri.', pt: 'Mas removido Amasa do caminho, todos os homens seguiram a Joabe, para perseguirem a Sebá, filho de Bicri.' },
      { v: 14, en: 'He went through all the tribes of Israel to Abel, and to Beth Maacah, and all the Berites. They were gathered together, and went also after him.', pt: 'Então Sebá passou por todas as tribos de Israel até Abel e Bete-Maacá; e todos os beritas, ajuntando-se, também o seguiram.' },
      { v: 15, en: 'They came and besieged him in Abel of Beth Maacah, and they cast up a mound against the city, and it stood against the rampart; and all the people who were with Joab battered the wall, to throw it down.', pt: 'Vieram, pois, e cercaram a Sebá em Abel de Bete-Maacá; e levantaram contra a cidade um montão, que se elevou defronte do muro; e todo o povo que estava com Joabe batia o muro para derrubá-lo.' },
      { v: 16, en: 'Then a wise woman cried out of the city, “Hear, hear! Please say to Joab, ‘Come near here, that I may speak with you.’”', pt: 'Então uma mulher sábia gritou de dentro da cidade: Ouvi! ouvi! Dizei a Joabe: Chega-te cá, para que eu te fale.' },
      { v: 17, en: 'He came near to her; and the woman said, “Are you Joab?” He answered, “I am.” Then she said to him, “Hear the words of your servant.” He answered, “I’m listening.”', pt: 'Ele, pois, se chegou perto dela; e a mulher perguntou: Tu és Joabe? Respondeu ele: Sou. Ela lhe disse: Ouve as palavras de tua serva. Disse ele: Estou ouvindo.' },
      { v: 18, en: 'Then she spoke, saying, “They used to say in old times, ‘They shall surely ask counsel at Abel;’ and so they settled a matter.', pt: 'Então falou ela, dizendo: Antigamente costumava-se dizer: Que se peça conselho em Abel; e era assim que se punha termo às questões.' },
      { v: 19, en: 'I am among those who are peaceable and faithful in Israel. You seek to destroy a city and a mother in Israel. Why will you swallow up Yahweh’s inheritance?”', pt: 'Eu sou uma das pacíficas e das fiéis em Israel; e tu procuras destruir uma cidade que é mãe em Israel; por que, pois, devorarias a herança do Senhor?' },
      { v: 20, en: 'Joab answered, “Far be it, far be it from me, that I should swallow up or destroy.', pt: 'Então respondeu Joabe, e disse: Longe, longe de mim que eu tal faça, que eu devore ou arruíne!' },
      { v: 21, en: 'The matter is not so. But a man of the hill country of Ephraim, Sheba the son of Bichri by name, has lifted up his hand against the king, even against David. Just deliver him, and I will depart from the city.” The woman said to Joab, “Behold, his head will be thrown to you over the wall.”', pt: 'A coisa não é assim; porém um só homem da região montanhosa de Efraim, cujo nome é Sebá, filho de Bicri, levantou a mão contra o rei, contra Davi; entregai-me só este, e retirar-me-ei da cidade. E disse a mulher a Joabe: Eis que te será lançada a sua cabeça pelo muro.' },
      { v: 22, en: 'Then the woman went to all the people in her wisdom. They cut off the head of Sheba the son of Bichri, and threw it out to Joab. He blew the trumpet, and they were dispersed from the city, every man to his tent. Then Joab returned to Jerusalem to the king.', pt: 'A mulher, na sua sabedoria, foi ter com todo o povo; e cortaram a cabeça de Sebá, filho de Bicri, e a lançaram a Joabe. Este, pois, tocou a buzina, e eles se retiraram da cidade, cada um para sua tenda. E Joabe voltou a Jerusalém, ao rei.' },
      { v: 23, en: 'Now Joab was over all the army of Israel, Benaiah the son of Jehoiada was over the Cherethites and over the Pelethites,', pt: 'Ora, Joabe estava sobre todo o exército de Israel; e Benaías, filho de Jeoiada, sobre os quereteus e os peleteus;' },
      { v: 24, en: 'Adoram was over the men subject to forced labor, Jehoshaphat the son of Ahilud was the recorder,', pt: 'e Adorão sobre a gente de trabalhos forçados; Jeosafá, filho de Ailude, era cronista;' },
      { v: 25, en: 'Sheva was scribe, and Zadok and Abiathar were priests,', pt: 'Seva era escrivão; Zadoque e Abiatar, sacerdotes;' },
      { v: 26, en: 'and Ira the Jairite was chief minister to David.', pt: 'e Ira, o jairita, era o oficial-mor de Davi.' },
    ],
    21: [
      { v: 1, en: 'There was a famine in the days of David for three years, year after year; and David sought the face of Yahweh. Yahweh said, “It is for Saul, and for his bloody house, because he put the Gibeonites to death.”', pt: 'Nos dias de Davi houve uma fome de três anos consecutivos; pelo que Davi consultou ao Senhor; e o Senhor lhe disse: E por causa de Saul e da sua casa sanguinária, porque matou os gibeonitas.' },
      { v: 2, en: 'The king called the Gibeonites, and said to them (now the Gibeonites were not of the children of Israel, but of the remnant of the Amorites, and the children of Israel had sworn to them; and Saul sought to kill them in his zeal for the children of Israel and Judah);', pt: 'Então o rei chamou os gibeonitas e falou com eles (ora, os gibeonitas não eram dos filhos de Israel, mas do restante dos amorreus; e os filhos de Israel tinham feito pacto com eles; porém Saul, no seu zelo pelos filhos de Israel e de Judá, procurou feri-los);' },
      { v: 3, en: 'and David said to the Gibeonites, “What should I do for you? And with what should I make atonement, that you may bless Yahweh’s inheritance?”', pt: 'perguntou, pois, Davi aos gibeonitas: Que quereis que eu vos faça. e como hei de fazer expiação, para que abençoeis a herança do Senhor?' },
      { v: 4, en: 'The Gibeonites said to him, “It is no matter of silver or gold between us and Saul, or his house; neither is it for us to put any man to death in Israel.” He said, “Whatever you say, that I will do for you.”', pt: 'Então os gibeonitas lhe disseram: Não é por prata nem ouro que temos questão com Saul e com a sua casa; nem tampouco cabe a nós matar pessoa alguma em Israel. Disse-lhes Davi: Que quereis que vos faça?' },
      { v: 5, en: 'They said to the king, “The man who consumed us, and who devised against us, that we should be destroyed from remaining in any of the borders of Israel,', pt: 'Responderam ao rei: Quanto ao homem que nos consumia, e procurava destruir-nos, de modo que não pudéssemos subsistir em termo algum de Israel,' },
      { v: 6, en: 'let seven men of his sons be delivered to us, and we will hang them up to Yahweh in Gibeah of Saul, the chosen of Yahweh.” The king said, “I will give them.”', pt: 'de seus filhos se nos dêem sete homens, para que os enforquemos ao Senhor em Gibeá de Saul, o eleito do Senhor. E o rei disse: Eu os darei.' },
      { v: 7, en: 'But the king spared Mephibosheth, the son of Jonathan the son of Saul, because of Yahweh’s oath that was between them, between David and Jonathan the son of Saul.', pt: 'O rei, porém, poupou a Mefibosete, filho de Jônatas, filho de Saul, por causa do juramento do Senhor que entre eles houvera, isto é, entre Davi e Jônatas, filho de Saul.' },
      { v: 8, en: 'But the king took the two sons of Rizpah the daughter of Aiah, whom she bore to Saul, Armoni and Mephibosheth; and the five sons of Michal the daughter of Saul, whom she bore to Adriel the son of Barzillai the Meholathite.', pt: 'Mas o rei tomou os dois filhos de Rizpa, filha de Aías, que ela tivera de Saul, a saber, a Armoni e a Mefibosete, como também os cinco filhos de Merabe, filha de Saul, que ela tivera de Adriel, filho de Barzilai, meolatita,' },
      { v: 9, en: 'He delivered them into the hands of the Gibeonites, and they hanged them on the mountain before Yahweh, and all seven of them fell together. They were put to death in the days of harvest, in the first days, at the beginning of barley harvest.', pt: 'e os entregou na mão dos gibeonitas, os quais os enforcaram no monte, perante o Senhor; e os sete caíram todos juntos. Foi nos primeiros dias da sega que foram mortos, no princípio a sega da cevada.' },
      { v: 10, en: 'Rizpah the daughter of Aiah took sackcloth, and spread it for herself on the rock, from the beginning of harvest until water poured on them from the sky. She allowed neither the birds of the sky to rest on them by day, nor the animals of the field by night.', pt: 'Então Rizpa, filha de Aías, tomando um pano de cilício, estendeu-o para si sobre uma pedra e, desde o princípio da sega até que a água caiu do céu sobre os corpos, não deixou que se aproximassem deles as aves do céu de dia, nem os animais do campo de noite:' },
      { v: 11, en: 'David was told what Rizpah the daughter of Aiah, the concubine of Saul, had done.', pt: 'Quando foi anunciado a Davi o que fizera Rizpa, filha de Aías, concubina de Saul,' },
      { v: 12, en: 'So David went and took the bones of Saul and the bones of Jonathan his son from the men of Jabesh Gilead, who had stolen them from the street of Beth Shan, where the Philistines had hanged them, in the day that the Philistines killed Saul in Gilboa;', pt: 'ele foi e tomou os ossos de Saul e os de Jônatas seu filho, aos homens de Jabes-Gileade, que os haviam furtado da praça de Bete-Sã, onde os filisteus os tinham pendurado quando mataram a Saul em Gilboa;' },
      { v: 13, en: 'and he brought up from there the bones of Saul and the bones of Jonathan his son. They also gathered the bones of those who were hanged.', pt: 'e trouxe dali os ossos de Saul e os de Jônatas seu filho; e ajuntaram a eles também os ossos dos enforcados.' },
      { v: 14, en: 'They buried the bones of Saul and Jonathan his son in the country of Benjamin in Zela, in the tomb of Kish his father: and they performed all that the king commanded. After that, God answered prayer for the land.', pt: 'Enterraram os ossos de Saul e de Jônatas seu filho, na terra de Benjamim, em Zela, na sepultura de Quis, seu pai; e fizeram tudo o que o rei ordenara. Depois disto Deus se aplacou para com a terra.' },
      { v: 15, en: 'The Philistines had war again with Israel; and David went down, and his servants with him, and fought against the Philistines. David grew faint;', pt: 'De novo tiveram os filisteus uma guerra contra Israel. E desceu Davi, e com ele os seus servos; e tanto pelejara contra os filisteus, que Davi se cansou.' },
      { v: 16, en: 'and Ishbibenob, who was of the sons of the giant, the weight of whose spear was three hundred shekels of brass in weight, he being armed with a new sword, thought he would kill David.', pt: 'E Isbi-Benobe, que era dos filhos do gigante, cuja lança tinha o peso de trezentos, siclos de bronze, e que cingia uma espada nova, intentou matar Davi.' },
      { v: 17, en: 'But Abishai the son of Zeruiah helped him, and struck the Philistine, and killed him. Then the men of David swore to him, saying, “Don’t go out with us to battle any more, so that you don’t quench the lamp of Israel.”', pt: 'Porém, Abisai, filho de Zeruia, o socorreu; e, ferindo ao filisteu, o matou. Então os homens de Davi lhe juraram, dizendo: Nunca mais sairás conosco à batalha, para que não apagues a lâmpada de Israel.' },
      { v: 18, en: 'After this, that there was again war with the Philistines at Gob. Then Sibbecai the Hushathite killed Saph, who was of the sons of the giant.', pt: 'Aconteceu depois disto que houve em Gobe ainda outra peleja contra os filisteus; então Sibecai, o husatita, matou Safe, que era dos filhos do gigante.' },
      { v: 19, en: 'There was again war with the Philistines at Gob; and Elhanan the son of Jaare-Oregim the Bethlehemite killed Goliath the Gittite’s brother, the staff of whose spear was like a weaver’s beam.', pt: 'Houve mais outra peleja contra os filisteus em Gobe; e El-Hanã, filho de Jaaré-Oregim, o belemita, matou Golias, o giteu, de cuja lança a haste era como órgão de tecelão.' },
      { v: 20, en: 'There was again war at Gath, where there was a man of great stature, who had six fingers on every hand, and six toes on every foot, twenty four in count; and he also was born to the giant.', pt: 'Houve ainda também outra peleja em Gate, onde estava um homem de alta estatura, que tinha seis dedos em cada mão, e seis em cada pé, vinte e quatro por todos; também este era descendente do gigante.' },
      { v: 21, en: 'When he defied Israel, Jonathan the son of Shimei, David’s brother, killed him.', pt: 'Tendo ele desafiado a Israel, Jônatas, filho de Simei, irmão de Davi, o matou.' },
      { v: 22, en: 'These four were born to the giant in Gath; and they fell by the hand of David, and by the hand of his servants.', pt: 'Estes quatro nasceram ao gigante em Gate; e caíram pela mão de Davi e pela mão de seus servos.' },
    ],
    22: [
      { v: 1, en: 'David spoke to Yahweh the words of this song in the day that Yahweh delivered him out of the hand of all his enemies, and out of the hand of Saul,', pt: 'Davi dirigiu ao Senhor as palavras deste cântico, no dia em que o Senhor o livrou das mãos de todos os seus inimigos e das mãos de Saul, dizendo:' },
      { v: 2, en: 'and he said: “Yahweh is my rock, my fortress, and my deliverer, even mine;', pt: 'O Senhor é o meu rochedo, a minha fortaleza e o meu libertador.' },
      { v: 3, en: 'God is my rock in whom I take refuge; my shield, and the horn of my salvation, my high tower, and my refuge. My savior, you save me from violence.', pt: 'É meu Deus, a minha rocha, nele confiarei; é o meu escudo, e a força da minha salvação, o meu alto retiro, e o meu refúgio. O meu Salvador; da violência tu me livras.' },
      { v: 4, en: 'I call on Yahweh, who is worthy to be praised; So shall I be saved from my enemies.', pt: 'Ao Senhor invocarei, pois é digno de louvor; assim serei salvo dos meus inimigos.' },
      { v: 5, en: 'For the waves of death surrounded me. The floods of ungodliness made me afraid.', pt: 'As ondas da morte me cercaram, as torrentes de Belial me atemorizaram.' },
      { v: 6, en: 'The cords of Sheol were around me. The snares of death caught me.', pt: 'Cordas do Seol me cingiram, laços de morte me envolveram.' },
      { v: 7, en: 'In my distress, I called on Yahweh. Yes, I called to my God. He heard my voice out of his temple. My cry came into his ears.', pt: 'Na minha angústia invoquei ao Senhor; sim, a meu Deus clamei; do seu templo ouviu ele a minha voz, e o meu clamor chegou aos seus ouvidos.' },
      { v: 8, en: 'Then the earth shook and trembled. The foundations of heaven quaked and were shaken, because he was angry.', pt: 'Então se abalou e tremeu a terra, os fundamentos dos céus se moveram; abalaram-se porque ele se irou.' },
      { v: 9, en: 'Smoke went up out of his nostrils. Consuming fire came out of his mouth. Coals were kindled by it.', pt: 'Das suas narinas subiu fumaça, e da sua boca um fogo devorador, que pôs carvões em chamas.' },
      { v: 10, en: 'He bowed the heavens also, and came down. Thick darkness was under his feet.', pt: 'Ele abaixou os céus, e desceu; e havia escuridão debaixo dos seus pés.' },
      { v: 11, en: 'He rode on a cherub, and flew. Yes, he was seen on the wings of the wind.', pt: 'Montou num querubim, e voou; apareceu sobre as asas do vento.' },
      { v: 12, en: 'He made darkness a shelter around himself: gathering of waters, and thick clouds of the skies.', pt: 'E por tendas pôs trevas ao redor de si, ajuntamento de águas, espessas nuvens do céu.' },
      { v: 13, en: 'At the brightness before him, coals of fire were kindled.', pt: 'Pelo resplendor da sua presença acenderam-se brasas de fogo.' },
      { v: 14, en: 'Yahweh thundered from heaven. The Most High uttered his voice.', pt: 'Do céu trovejou o Senhor, o Altíssimo fez soar a sua vóz.' },
      { v: 15, en: 'He sent out arrows, and scattered them; lightning, and confused them.', pt: 'Disparou flechas, e os dissipou; raios, e os desbaratou.' },
      { v: 16, en: 'Then the channels of the sea appeared. The foundations of the world were laid bare by Yahweh’s rebuke, at the blast of the breath of his nostrils.', pt: 'Então apareceram as profundezas do mar; os fundamentos do mundo se descobriram, pela repreensão do Senhor, pelo assopro do vento das suas narinas.' },
      { v: 17, en: 'He sent from on high and he took me. He drew me out of many waters.', pt: 'Estendeu do alto a sua mão e tomou-me; tirou-me das muitas águas.' },
      { v: 18, en: 'He delivered me from my strong enemy, from those who hated me, for they were too mighty for me.', pt: 'Livrou-me do meu possante inimigo, e daqueles que me odiavam; porque eram fortes demais para mim.' },
      { v: 19, en: 'They came on me in the day of my calamity, but Yahweh was my support.', pt: 'Encontraram-me no dia da minha calamidade, porém o Senhor se fez o meu esteio.' },
      { v: 20, en: 'He also brought me out into a large place. He delivered me, because he delighted in me.', pt: 'Conduziu-me para um lugar espaçoso; livrou-me, porque tinha prazer em mim.' },
      { v: 21, en: 'Yahweh rewarded me according to my righteousness. He rewarded me according to the cleanness of my hands.', pt: 'Recompensou-me o Senhor conforme a minha justiça; conforme a pureza e minhas mãos me retribuiu.' },
      { v: 22, en: 'For I have kept Yahweh’s ways, and have not wickedly departed from my God.', pt: 'Porque guardei os caminhos do Senhor, e não me apartei impiamente do meu Deus.' },
      { v: 23, en: 'For all his ordinances were before me. As for his statutes, I did not depart from them.', pt: 'Pois todos os seus preceitos estavam diante de mim, e dos seus estatutos não me desviei.' },
      { v: 24, en: 'I was also perfect toward him. I kept myself from my iniquity.', pt: 'Fui perfeito para com ele, e guardei-me da minha iniqüidade.' },
      { v: 25, en: 'Therefore Yahweh has rewarded me according to my righteousness, According to my cleanness in his eyesight.', pt: 'Por isso me retribuiu o Senhor conforme a minha justiça, conforme a minha pureza diante dos meus olhos.' },
      { v: 26, en: 'With the merciful you will show yourself merciful. With the perfect man you will show yourself perfect.', pt: 'Para com o benigno te mostras benigno; para com o perfeito te mostras perfeito,' },
      { v: 27, en: 'With the pure you will show yourself pure. With the crooked you will show yourself shrewd.', pt: 'para com o puro te mostras puro, mas para com o perverso te mostras avesso.' },
      { v: 28, en: 'You will save the afflicted people, But your eyes are on the haughty, that you may bring them down.', pt: 'Livrarás o povo que se humilha, mas teus olhos são contra os altivos, e tu os abaterás.' },
      { v: 29, en: 'For you are my lamp, Yahweh. Yahweh will light up my darkness.', pt: 'Porque tu, Senhor, és a minha candeia; e o Senhor alumiará as minhas trevas.' },
      { v: 30, en: 'For by you, I run against a troop. By my God, I leap over a wall.', pt: 'Pois contigo passarei pelo meio dum esquadrão; com o meu Deus transporei um muro.' },
      { v: 31, en: 'As for God, his way is perfect. Yahweh’s word is tested. He is a shield to all those who take refuge in him.', pt: 'Quanto a Deus, o seu caminho é perfeito, e a palavra do Senhor é fiel; é ele o escudo de todos os que nele se refugiam.' },
      { v: 32, en: 'For who is God, besides Yahweh? Who is a rock, besides our God?', pt: 'Pois quem é Deus, senão o Senhor? e quem é rocha, senão o nosso Deus?' },
      { v: 33, en: 'God is my strong fortress. He makes my way perfect.', pt: 'Deus é a minha grande fortaleza; e ele torna perfeito o meu caminho.' },
      { v: 34, en: 'He makes his feet like hinds’ feet, and sets me on my high places.', pt: 'Faz ele os meus pés como os das gazelas, e me põe sobre as minhas alturas.' },
      { v: 35, en: 'He teaches my hands to war, so that my arms bend a bow of brass.', pt: 'Ele instrui as minhas mãos para a peleja, de modo que os meus braços podem entesar um arco de bronze.' },
      { v: 36, en: 'You have also given me the shield of your salvation. Your gentleness has made me great.', pt: 'Também me deste o escudo da tua salvação, e tua brandura me engrandece.' },
      { v: 37, en: 'You have enlarged my steps under me. My feet have not slipped.', pt: 'Alargaste os meus passos debaixo de mim, e não vacilaram os meus artelhos.' },
      { v: 38, en: 'I have pursued my enemies and destroyed them. I didn’t turn again until they were consumed.', pt: 'Persegui os meus inimigos e os destruí, e nunca voltei atrás sem que os consumisse.' },
      { v: 39, en: 'I have consumed them, and struck them through, so that they can’t arise. Yes, they have fallen under my feet.', pt: 'Eu os consumi, e os atravessei, de modo que nunca mais se levantaram; sim, cairam debaixo dos meus pés.' },
      { v: 40, en: 'For you have armed me with strength for the battle. You have subdued under me those who rose up against me.', pt: 'Pois tu me cingiste de força para a peleja; prostraste debaixo de mim os que se levantaram contra mim.' },
      { v: 41, en: 'You have also made my enemies turn their backs to me, that I might cut off those who hate me.', pt: 'Fizeste que me voltassem as costas os meus inimigos, aqueles que me odiavam, para que eu os destruísse.' },
      { v: 42, en: 'They looked, but there was no one to save; even to Yahweh, but he didn’t answer them.', pt: 'Olharam ao redor, mas não houve quem os salvasse; clamaram ao Senhor, mas ele não lhes respondeu.' },
      { v: 43, en: 'Then I beat them as small as the dust of the earth. I crushed them as the mire of the streets, and spread them abroad.', pt: 'Então os moí como o pó da terra; como a lama das ruas os trilhei e dissipei.' },
      { v: 44, en: 'You also have delivered me from the strivings of my people. You have kept me to be the head of the nations. A people whom I have not known will serve me.', pt: 'Também me livraste das contendas do meu povo; guardaste-me para ser o cabeça das nações; um povo que eu não conhecia me serviu.' },
      { v: 45, en: 'The foreigners will submit themselves to me. As soon as they hear of me, they will obey me.', pt: 'Estrangeiros, com adulação, se submeteram a mim; ao ouvirem de mim, me obedeceram.' },
      { v: 46, en: 'The foreigners will fade away, and will come trembling out of their close places.', pt: 'Os estrangeiros desfaleceram e, tremendo, sairam os seus esconderijos.' },
      { v: 47, en: 'Yahweh lives! Blessed be my rock! Exalted be God, the rock of my salvation,', pt: 'O Senhor vive; bendita seja a minha rocha, e exaltado seja Deus, a rocha da minha salvação,' },
      { v: 48, en: 'even the God who executes vengeance for me, who brings down peoples under me,', pt: 'o Deus que me deu vingança, e sujeitou povos debaixo de mim,' },
      { v: 49, en: 'who brings me away from my enemies. Yes, you lift me up above those who rise up against me. You deliver me from the violent man.', pt: 'e me tirou dentre os meus inimigos; porque tu me exaltaste sobre os meus adversarios; tu me livraste do homem violento.' },
      { v: 50, en: 'Therefore I will give thanks to you, Yahweh, among the nations, and will sing praises to your name.', pt: 'Por isso, ó Senhor, louvar-te-ei entre as nações, e entoarei louvores ao teu nome.' },
      { v: 51, en: 'He gives great deliverance to his king, and shows loving kindness to his anointed, to David and to his offspring, forever more.”', pt: 'Ele dá grande livramento a seu rei, e usa de benignidade para com o seu ungido, para com Davi e a sua descendência para sempre.' },
    ],
    23: [
      { v: 1, en: 'Now these are the last words of David. David the son of Jesse says, the man who was raised on high says, the anointed of the God of Jacob, the sweet psalmist of Israel:', pt: 'São estas as últimas palavras de Davi: Diz Davi, filho de Jessé, diz a homem que foi exaltado, o ungido do Deus de Jacó, o suave salmista de Israel.' },
      { v: 2, en: '“Yahweh’s Spirit spoke by me. His word was on my tongue.', pt: 'O Espírito do Senhor fala por mim, e a sua palavra está na minha língua.' },
      { v: 3, en: 'The God of Israel said, the Rock of Israel spoke to me, ‘One who rules over men righteously, who rules in the fear of God,', pt: 'Falou o Deus de Israel, a Rocha de Israel me disse: Quando um justo governa sobre os homens, quando governa no temor de Deus,' },
      { v: 4, en: 'shall be as the light of the morning, when the sun rises, a morning without clouds, when the tender grass springs out of the earth, through clear shining after rain.’', pt: 'será como a luz da manhã ao sair do sol, da manhã sem nuvens, quando, depois da chuva, pelo resplendor do sol, a erva brota da terra.' },
      { v: 5, en: 'Isn’t my house so with God? Yet he has made with me an everlasting covenant, ordered in all things, and sure, for it is all my salvation, and all my desire, although he doesn’t make it grow.', pt: 'Pois não é assim a minha casa para com Deus? Porque estabeleceu comigo um pacto eterno, em tudo bem ordenado e seguro; pois não fará ele prosperar toda a minha salvação e todo o meu desejo?' },
      { v: 6, en: 'But all the ungodly will be as thorns to be thrust away, because they can’t be taken with the hand,', pt: 'Porém os ímpios todos serão como os espinhos, que se lançam fora, porque não se pode tocar neles;' },
      { v: 7, en: 'But the man who touches them must be armed with iron and the staff of a spear. They will be utterly burned with fire in their place.”', pt: 'mas qualquer que os tocar se armará de ferro e da haste de uma lança; e a fogo serão totalmente queimados no mesmo lugar.' },
      { v: 8, en: 'These are the names of the mighty men whom David had: Josheb Basshebeth a Tahchemonite, chief of the captains; the same was Adino the Eznite, against eight hundred slain at one time.', pt: 'São estes os nomes dos valentes de Davi: Josebe-Bassebete, o taquemonita; era este principal dos três; foi ele que, com a lança, matou oitocentos de uma vez.' },
      { v: 9, en: 'After him was Eleazar the son of Dodai the son of an Ahohite, one of the three mighty men with David, when they defied the Philistines who were there gathered together to battle, and the men of Israel had gone away.', pt: 'Depois dele Eleazar, filho de Dodó, filho de Aoí, um dos três valentes que estavam com Davi, quando desafiaram os filisteus que se haviam reunido para a peleja, enquanto os homens de Israel se retiravam.' },
      { v: 10, en: 'He arose and struck the Philistines until his hand was weary, and his hand froze to the sword; and Yahweh worked a great victory that day; and the people returned after him only to take plunder.', pt: 'Este se levantou, e feriu os filisteus, até lhe cansar a mão e ficar pegada à espada; e naquele dia o Senhor operou um grande livramento; e o povo voltou para junto de Eleazar, somente para tomar o despojo.' },
      { v: 11, en: 'After him was Shammah the son of Agee a Hararite. The Philistines had gathered together into a troop, where there was a plot of ground full of lentils; and the people fled from the Philistines.', pt: 'Depois dele era Samá, filho de Agé, o hararita. Os filisteus se haviam ajuntado em Leí, onde havia um terreno cheio de lentilhas; e o povo fugiu de diante dos filisteus.' },
      { v: 12, en: 'But he stood in the middle of the plot and defended it, and killed the Philistines; and Yahweh worked a great victory.', pt: 'Samá, porém, pondo-se no meio daquele terreno, defendeu-o e matou os filisteus, e o Senhor efetuou um grande livramento.' },
      { v: 13, en: 'Three of the thirty chief men went down, and came to David in the harvest time to the cave of Adullam; and the troop of the Philistines was encamped in the valley of Rephaim.', pt: 'Também três dos trinta cabeças desceram, no tempo da sega, e foram ter com Davi, à caverna de Adulão; e a tropa dos filisteus acampara no vale de Refaim.' },
      { v: 14, en: 'David was then in the stronghold; and the garrison of the Philistines was then in Bethlehem.', pt: 'Davi estava então no lugar forte, e a guarnição dos filisteus estava em Belém.' },
      { v: 15, en: 'David longed, and said, “Oh that someone would give me water to drink from the well of Bethlehem, which is by the gate!”', pt: 'E Davi, com saudade, exclamou: Quem me dera beber da água da cisterna que está junto a porta de Belém!' },
      { v: 16, en: 'The three mighty men broke through the army of the Philistines, and drew water out of the well of Bethlehem that was by the gate, and took it and brought it to David; but he would not drink of it, but poured it out to Yahweh.', pt: 'Então aqueles três valentes romperam pelo arraial dos filisteus, tiraram água da cisterna que está junto a porta de Belém, e a trouxeram a Davi; porém ele não quis bebê-la, mas derramou-a perante o Senhor;' },
      { v: 17, en: 'He said, “Be it far from me, Yahweh, that I should do this! Isn’t this the blood of the men who risked their lives to go?” Therefore he would not drink it. The three mighty men did these things.', pt: 'e disse: Longe de mim, ó Senhor, que eu tal faça! Beberia eu o sangue dos homens que foram com risco das suas vidas? De maneira que não a quis beber. Isto fizeram aqueles três valentes.' },
      { v: 18, en: 'Abishai, the brother of Joab, the son of Zeruiah, was chief of the three. He lifted up his spear against three hundred and killed them, and had a name among the three.', pt: 'Ora, Abisai, irmão de Joabe, filho de Zeruia, era chefe dos trinta; e este alçou a sua lança contra trezentos, e os matou, e tinha nome entre os três.' },
      { v: 19, en: 'Wasn’t he most honorable of the three? therefore he was made their captain. However he wasn’t included as one of the three.', pt: 'Porventura não era este o mais nobre dentre os trinta? portanto se tornou o chefe deles; porém aos primeiros três não chegou.' },
      { v: 20, en: 'Benaiah the son of Jehoiada, the son of a valiant man of Kabzeel, who had done mighty deeds, killed the two sons of Ariel of Moab. He also went down and killed a lion in the middle of a pit in a time of snow.', pt: 'Também Benaías, filho de Jeoiada, filho dum homem de Cabzeel, valoroso e de grandes feitos, matou os dois filhos de Ariel de Moabe; depois desceu, e matou um leão dentro duma cova, no tempo da neve.' },
      { v: 21, en: 'He killed a huge Egyptian, and the Egyptian had a spear in his hand; but he went down to him with a staff, and plucked the spear out of the Egyptian’s hand, and killed him with his own spear.', pt: 'Matou também um egípcio, homem de temível aspecto; tinha este uma lança na mão, mas Benaías desceu a ele com um cajado, arrancou-lhe da mão a lança, e com ela o matou.' },
      { v: 22, en: 'Benaiah the son of Jehoiada did these things, and had a name among the three mighty men.', pt: 'Estas coisas fez Benaías, filho de Jeoiada, pelo que teve nome entre os três valentes.' },
      { v: 23, en: 'He was more honorable than the thirty, but he didn’t attain to the three. David set him over his guard.', pt: 'Dentre os trinta ele era o mais afamado, porém aos três primeiros não chegou. Mas Davi o pôs sobre os seus guardas.' },
      { v: 24, en: 'Asahel the brother of Joab was one of the thirty: Elhanan the son of Dodo of Bethlehem,', pt: 'Asael, irmão de Joabe, era um dos trinta; El-Hanã, filho de Dodó, de Belém;' },
      { v: 25, en: 'Shammah the Harodite, Elika the Harodite,', pt: 'Samá, o harodita; Elica, o harodita;' },
      { v: 26, en: 'Helez the Paltite, Ira the son of Ikkesh the Tekoite,', pt: 'Jelez, o paltita; Ira, filho de Iques, o tecoíta;' },
      { v: 27, en: 'Abiezer the Anathothite, Mebunnai the Hushathite,', pt: 'Abiezer, o anatotita; Mebunai, o husatita;' },
      { v: 28, en: 'Zalmon the Ahohite, Maharai the Netophathite,', pt: 'Zalmom, o aoíta; Maarai, o netofatita;' },
      { v: 29, en: 'Heleb the son of Baanah the Netophathite, Ittai the son of Ribai of Gibeah of the children of Benjamin,', pt: 'Helebe, filho de Baaná, o netofatita; Itai, filho de Ribai, de Gibeá dos filhos de Benjamim;' },
      { v: 30, en: 'Benaiah a Pirathonite, Hiddai of the brooks of Gaash.', pt: 'Benaías, o piratonita; Hidai, das torrentes de Gaás;' },
      { v: 31, en: 'Abialbon the Arbathite, Azmaveth the Barhumite,', pt: 'Abi-Albom, o arbatita; Azmavete, o barumita;' },
      { v: 32, en: 'Eliahba the Shaalbonite, the sons of Jashen, Jonathan,', pt: 'Eliabá, o saalbonita; Bene-Jásen; e Jônatas;' },
      { v: 33, en: 'Shammah the Hararite, Ahiam the son of Sharar the Ararite,', pt: 'Samá, o hararita; Aião, filho de Sarar, o hararita;' },
      { v: 34, en: 'Eliphelet the son of Ahasbai, the son of the Maacathite, Eliam the son of Ahithophel the Gilonite,', pt: 'Elifelete, filho de Acasbai, filho do maacatita; Eliã, filho de Aitofel, o gilonita;' },
      { v: 35, en: 'Hezro the Carmelite, Paarai the Arbite,', pt: 'Hezrai, o carmelita; Paarai, o arbita;' },
      { v: 36, en: 'Igal the son of Nathan of Zobah, Bani the Gadite,', pt: 'Igal, filho de Natã, de Zobá; Bani, o gadita;' },
      { v: 37, en: 'Zelek the Ammonite, Naharai the Beerothite, armor bearers to Joab the son of Zeruiah,', pt: 'Zeleque, o amonita; Naarai, o beerotita, o que trazia as armas de Joabe, filho de Zeruia;' },
      { v: 38, en: 'Ira the Ithrite, Gareb the Ithrite,', pt: 'Ira, o itrita; Garebe, o itrita;' },
      { v: 39, en: 'and Uriah the Hittite: thirty-seven in all.', pt: 'Urias, o heteu; trinta e sete ao todo.' },
    ],
    24: [
      { v: 1, en: 'Again Yahweh’s anger burned against Israel, and he moved David against them, saying, “Go, count Israel and Judah.”', pt: 'A ira do Senhor tornou a acender-se contra Israel, e o Senhor incitou a Davi contra eles, dizendo: Vai, numera a Israel e a Judá.' },
      { v: 2, en: 'The king said to Joab the captain of the army, who was with him, “Now go back and forth through all the tribes of Israel, from Dan even to Beersheba, and count the people, that I may know the sum of the people.”', pt: 'Disse, pois, o rei a Joabe, chefe do exército, que estava com ele: Percorre todas as tribos de Israel, desde Dã até Berseba, e numera o povo, para que eu saiba o seu número.' },
      { v: 3, en: 'Joab said to the king, “Now may Yahweh your God add to the people, however many they may be, one hundred times; and may the eyes of my lord the king see it. But why does my lord the king delight in this thing?”', pt: 'Então disse Joabe ao rei: Ora, multiplique o Senhor teu Deus a este povo cem vezes tanto quanto agora é, e os olhos do rei meu senhor o vejam. Mas por que tem prazer nisto o rei meu senhor;' },
      { v: 4, en: 'Notwithstanding, the king’s word prevailed against Joab, and against the captains of the army. Joab and the captains of the army went out from the presence of the king to count the people of Israel.', pt: 'Todavia a palavra do rei prevaleceu contra Joabe, e contra os chefes do exército; Joabe, pois, saiu com os chefes do exército da presença do rei para numerar o povo de Israel.' },
      { v: 5, en: 'They passed over the Jordan, and encamped in Aroer, on the right side of the city that is in the middle of the valley of Gad, and to Jazer;', pt: 'Tendo eles passado o Jordão, acamparam-se em Aroer, à direita da cidade que está no meio do vale de Gade e na direção de Jazer;' },
      { v: 6, en: 'then they came to Gilead, and to the land of Tahtim Hodshi; and they came to Dan Jaan, and around to Sidon,', pt: 'em seguida foram a Gileade, e a terra de Tatim-Hódsi; dali foram a Da-Jaã, e ao redor até Sidom;' },
      { v: 7, en: 'and came to the stronghold of Tyre, and to all the cities of the Hivites, and of the Canaanites; and they went out to the south of Judah, at Beersheba.', pt: 'depois foram à fortaleza de Tiro, e a todas as cidades dos heveus e dos cananeus; e saíram para a banda do sul de Judá, em Berseba.' },
      { v: 8, en: 'So when they had gone back and forth through all the land, they came to Jerusalem at the end of nine months and twenty days.', pt: 'Assim, tendo percorrido todo o país, voltaram a Jerusalém, ao cabo de nove meses e vinte dias.' },
      { v: 9, en: 'Joab gave up the sum of the counting of the people to the king: and there were in Israel eight hundred thousand valiant men who drew the sword; and the men of Judah were five hundred thousand men.', pt: 'Joabe, pois, deu ao rei o resultado da numeração do povo. E havia em Israel oitocentos mil homens valorosos, que arrancavam da espada; e os homens de Judá eram quinhentos mil.' },
      { v: 10, en: 'David’s heart struck him after he had counted the people. David said to Yahweh, “I have sinned greatly in that which I have done. But now, Yahweh, put away, I beg you, the iniquity of your servant; for I have done very foolishly.”', pt: 'Mas o coração de Davi o acusou depois de haver ele numerado o povo; e disse Davi ao Senhor: Muito pequei no que fiz; porém agora, ó Senhor, rogo-te que perdoes a iniqüidade do teu servo, porque tenho procedido mui nesciamente.' },
      { v: 11, en: 'When David rose up in the morning, Yahweh’s word came to the prophet Gad, David’s seer, saying,', pt: 'Quando, pois, Davi se levantou pela manhã, veio a palavra do Senhor ao profeta Gade, vidente de Davi, dizendo:' },
      { v: 12, en: '“Go and speak to David, ‘Yahweh says, “I offer you three things. Choose one of them, that I may do it to you.”’”', pt: 'Vai, e dize a Davi: Assim diz o Senhor: Três coisas te ofereço; escolhe qual delas queres que eu te faça.' },
      { v: 13, en: 'So Gad came to David, and told him, and said to him, “Shall seven years of famine come to you in your land? Or will you flee three months before your foes while they pursue you? Or shall there be three days’ pestilence in your land? Now answer, and consider what answer I shall return to him who sent me.”', pt: 'Veio, pois, Gade a Davi, e fez-lho saber dizendo-lhe: Queres que te venham sete anos de fome na tua terra; ou que por três meses fujas diante de teus inimigos, enquanto estes te perseguirem; ou que por três dias haja peste na tua terra? Delibera agora, e vê que resposta hei de dar àquele que me enviou.' },
      { v: 14, en: 'David said to Gad, “I am in distress. Let us fall now into Yahweh’s hand; for his mercies are great. Let me not fall into man’s hand.”', pt: 'Respondeu Davi a Gade: Estou em grande angústia; porém caiamos nas mãos do Senhor, porque muitas são as suas misericórdias; mas nas mãos dos homens não caia eu.' },
      { v: 15, en: 'So Yahweh sent a pestilence on Israel from the morning even to the appointed time; and seventy thousand men died of the people from Dan even to Beersheba.', pt: 'Então enviou o Senhor a peste sobre Israel, desde a manhã até o tempo determinado; e morreram do povo, desde Dã até Berseba, setenta mil homens.' },
      { v: 16, en: 'When the angel stretched out his hand toward Jerusalem to destroy it, Yahweh relented of the disaster, and said to the angel who destroyed the people, “It is enough. Now withdraw your hand.” Yahweh’s angel was by the threshing floor of Araunah the Jebusite.', pt: 'Ora, quando o anjo estendeu a mão sobre Jerusalém, para a destruir, o Senhor se arrependeu daquele mal; e disse ao anjo que fazia a destruição entre o povo: Basta; retira agora a tua mão. E o anjo do Senhor estava junto à eira de Araúna, o jebuseu.' },
      { v: 17, en: 'David spoke to Yahweh when he saw the angel who struck the people, and said, “Behold, I have sinned, and I have done perversely; but these sheep, what have they done? Please let your hand be against me, and against my father’s house.”', pt: 'E, vendo Davi ao anjo que feria o povo, falou ao Senhor, dizendo: Eis que eu pequei, e procedi iniquamente; porém estas ovelhas, que fizeram? Seja, pois, a tua mão contra mim, e contra a casa de meu pai.' },
      { v: 18, en: 'Gad came that day to David, and said to him, “Go up, build an altar to Yahweh on the threshing floor of Araunah the Jebusite.”', pt: 'Naquele mesmo dia veio Gade a Davi, e lhe disse: Sobe, levanta ao Senhor um altar na eira de Araúna, o jebuseu:' },
      { v: 19, en: 'David went up according to the saying of Gad, as Yahweh commanded.', pt: 'Subiu, pois, Davi, conforme a palavra de Gade, como o Senhor havia ordenado.' },
      { v: 20, en: 'Araunah looked out, and saw the king and his servants coming on toward him. Then Araunah went out, and bowed himself before the king with his face to the ground.', pt: 'E olhando Araúna, viu que vinham ter com ele o rei e os seus servos; saiu, pois, e inclinou-se diante do rei com o rosto em terra.' },
      { v: 21, en: 'Araunah said, “Why has my lord the king come to his servant?” David said, “To buy your threshing floor, to build an altar to Yahweh, that the plague may be stopped from afflicting the people.”', pt: 'Perguntou Araúna: Por que vem o rei meu senhor ao seu servo? Respondeu Davi: Para comprar de ti a eira, a fim de edificar nela um altar ao Senhor, para que a praga cesse de sobre o povo.' },
      { v: 22, en: 'Araunah said to David, “Let my lord the king take and offer up what seems good to him. Behold, the cattle for the burnt offering, and the threshing instruments and the yokes of the oxen for the wood.', pt: 'Então disse Araúna a Davi: Tome e ofereça o rei meu senhor o que bem lhe parecer; eis aí os bois para o holocausto, e os trilhos e os aparelhos dos bois para lenha.' },
      { v: 23, en: 'All this, O king, does Araunah give to the king.” Araunah said to the king, “May Yahweh your God accept you.”', pt: 'Tudo isto, ó rei, Araúna te oferece. Disse mais Araúna ao rei: O Senhor teu Deus tome prazer em ti.' },
      { v: 24, en: 'The king said to Araunah, “No; but I will most certainly buy it from you for a price. I will not offer burnt offerings to Yahweh my God which cost me nothing.” So David bought the threshing floor and the oxen for fifty shekels of silver.', pt: 'Mas o rei disse a Araúna: Não! antes to comprarei pelo seu valor, porque não oferecerei ao Senhor meu Deus holocaustos que não me custem nada. Comprou, pois, Davi a eira e os bois por cinqüenta siclos de prata.' },
      { v: 25, en: 'David built an altar to Yahweh there, and offered burnt offerings and peace offerings. So Yahweh was entreated for the land, and the plague was removed from Israel.', pt: 'E edificou ali um altar ao Senhor, e ofereceu holocaustos e ofertas pacíficas. Assim o Senhor se tornou propício para com a terra, e cessou aquela praga de sobre Israel.' },
    ],
  },
};

export default book;
